def get_sota_confidence_wording(confidence: str) -> dict:
    """Map SOTA benchmark confidence tier to CER conclusion wording."""
    return SOTA_CONFIDENCE_WORDING_MAP.get(confidence, SOTA_CONFIDENCE_WORDING_MAP["low"])

