def _route_evidence_source_for_claim(claim_type: str) -> dict:
    """Return primary/fallback/excluded sources for a claim type."""
    claim_type_normalized = str(claim_type or "").lower().replace(" ", "_")
    for key, routing in CLAIM_TYPE_SOURCE_ROUTING.items():
        if key.lower().replace(" ", "_") == claim_type_normalized:
            return routing
    return {"primary": "PubMed/CT.gov", "fallback": "equivalent_device", "excluded": []}


DATABASE_TIERS = {
    "minimum": ["PubMed/MEDLINE"],
    "standard": ["PubMed/MEDLINE", "Embase", "Cochrane Library"],
    "enhanced": ["PubMed/MEDLINE", "Embase", "Cochrane Library", "Scopus", "Web of Science", "ClinicalTrials.gov"],
}


def _get_database_config(device_class: str, risk_level: str = "standard") -> list[str]:
    """Return database tier list based on device class and risk level."""
    if device_class in ("III",) or risk_level == "high":
        return DATABASE_TIERS["enhanced"]
    if device_class in ("IIb",):
        return DATABASE_TIERS["standard"]
    return DATABASE_TIERS["minimum"]


def _assess_ifu_quality(state: dict[str, Any]) -> dict[str, Any]:
    """Check IFU quality beyond mere existence (BL-12)."""
    ifu_items = [i for i in state.get("source_inventory") or []
                 if "ifu" in str(i.get("document_type", "")).lower()]
    if not ifu_items:
        return {"ifu_quality": "missing", "ifu_quality_score": 0}
    item = ifu_items[0]
    text = str(item.get("extracted_text") or "")
    score = 100
    issues = []
    if len(text) < 500:
        score -= 40
        issues.append("text_too_short")
    if not any(kw in text.lower() for kw in ["intended use", "indication", "contraindication"]):
        score -= 30
        issues.append("missing_clinical_sections")
    if item.get("is_scanned_pdf") and not item.get("ocr_successful"):
        score -= 50
        issues.append("scanned_unreadable")
    return {
        "ifu_quality_score": max(0, score),
        "ifu_quality_issues": issues,
        "ifu_quality": "acceptable" if score >= 60 else ("degraded" if score >= 30 else "unusable"),
    }


def _cleanup_spiral_lineage(state: dict[str, Any]) -> dict[str, Any]:
    """Archive old spiral round data, keep only latest + key summary (NW-05)."""
    lineage = state.get("evidence_spiral_lineage") or []
    if len(lineage) <= 1:
        return {}
    archive = list(state.get("evidence_spiral_archive") or [])
    latest_round = max(
        (r.get("spiral_round_id", 0) for r in lineage if isinstance(r, dict)),
        default=0,
    )
    old = [r for r in lineage if r.get("spiral_round_id", 0) < latest_round]
    current = [r for r in lineage if r.get("spiral_round_id", 0) >= latest_round]
    archive.extend(old)
    return {
        "evidence_spiral_lineage": current,
        "evidence_spiral_archive": archive,
        "spiral_current_round": latest_round,
    }


def _exhaust_alternatives_before_pmcf(state: dict[str, Any], gaps: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """Check if alternative paths have been exhausted before recommending PMCF."""
    exhausted = []
    for gap in gaps:
        gap_type = str(gap.get("gap_type") or "")
        if gap_type in ("evidence_gap", "retrieval_gap"):
            alt_endpoints = state.get("endpoint_alternatives_attempted") or []
            kw_expanded = state.get("keyword_expansion_attempted") or False
            if not alt_endpoints and not kw_expanded:
                gap["pmcf_premature"] = True
                gap["pmcf_measure"] = "ATTEMPT endpoint substitution and keyword expansion BEFORE PMCF"
            else:
                gap["pmcf_premature"] = False
        exhausted.append(gap)
    return exhausted

