def contains_cjk(value: Any) -> bool:
    return bool(_CJK_RE.search(str(value or "")))


def english_report_text(value: Any, context: str = "source text") -> str:
    """Return report-safe English text for CER body output.

    Original-language source text remains available in the structured workbook.
    The CER draft itself must be submission-style English, so known IFU source
    fragments are normalized here and any remaining Chinese is explicitly
    summarized rather than leaked into the final report.
    """
    text = _clean(value)
    if not text:
        return ""
    if not contains_cjk(text):
        return text
    lowered_context = context.lower()
    replacements = [
        ("一次性使用输尿管负压导引鞘", ENGLISH_DEVICE_NAME),
        ("一次性使用电子输尿管肾盂内窥镜导管", "Single-use Electronic Ureterorenoscope Catheter"),
        ("一次性使用电子膀胱肾盂内窥镜导管", "Single-use Electronic Cysto-Nephroscope Catheter"),
        ("输尿管肾盂内窥镜", "ureterorenoscope"),
        ("膀胱肾盂内窥镜", "cysto-nephroscope"),
        ("肾盂镜", "nephroscope"),
        ("膀胱镜", "cystoscope"),
        ("电子内窥镜", "electronic endoscope"),
        ("内窥镜图像处理器", "endoscopic image processor"),
        ("江苏圆和", "Jiangsu Yuanhe"),
        ("医疗科技有限公司", "Medical Technology Co., Ltd."),
        ("多通道脉冲电场消融仪", "Multi-channel Pulsed Field Ablation Generator"),
        ("心脏脉冲电场消融仪", "Cardiac Pulsed Field Ablation Generator"),
        ("一次性使用心脏脉冲电场消融导管", "Single-use Cardiac Pulsed Field Ablation Catheter"),
        ("可控弯环状脉冲消融导管", "Steerable Loop Pulsed Field Ablation Catheter"),
        ("等离子手术设备", "Plasma Surgical Equipment"),
        ("等离子射频治疗仪", "Radiofrequency Plasma Surgical Equipment"),
        ("等离子手术电极", "plasma surgical electrode"),
        ("滴液控制阀", "drip-control valve"),
        ("脚踏开关", "footswitch"),
        ("耳鼻喉", "ENT"),
        ("脉冲电场消融", "pulsed field ablation"),
        ("脉冲电场", "pulsed field"),
        ("消融导管", "ablation catheter"),
        ("心房颤动", "atrial fibrillation"),
        ("房颤", "atrial fibrillation"),
        ("肺静脉", "pulmonary vein"),
        ("电穿孔", "electroporation"),
        ("心脏", "heart"),
        ("泌尿系统感染", "urinary system infection"),
        ("肾功能不全", "renal insufficiency"),
        ("输尿管", "ureter"),
        ("肾盂", "renal pelvis"),
        ("泌尿道", "urinary tract"),
        ("负压", "negative pressure"),
        ("导丝", "guidewire"),
        ("扩张器", "dilator"),
        ("鞘管", "sheath tube"),
        ("亲水涂层", "hydrophilic coating"),
        ("环氧乙烷", "ethylene oxide"),
        ("灭菌", "sterilisation"),
        ("一次性使用", "single-use"),
    ]
    normalized = text
    for source, target in replacements:
        normalized = normalized.replace(source, target)

    if contains_cjk(normalized):
        mapped = _english_summary_for_cjk(text, context=lowered_context)
        return mapped
    return normalized


def english_filename(value: Any, source_id: str = "") -> str:
    filename = str(value or "")
    lower = filename.lower()
    label = ""
    if "ifu" in lower or "使用说明" in filename:
        label = "Instructions for Use"
    elif "等同" in filename or "equivalence" in lower:
        label = "equivalent-device search or equivalence support report"
    elif "风险" in filename or "risk" in lower:
        label = "risk management source document"
    elif "亲水" in filename or "coating" in lower:
        label = "hydrophilic coating performance verification document"
    elif "外鞘" in filename or "套管" in filename:
        label = "sheath tube extrusion performance verification document"
    elif "扩张" in filename or "dilator" in lower:
        label = "dilator performance verification document"
    elif "粘胶" in filename or "bond" in lower:
        label = "bonding performance verification document"
    elif "焊接" in filename or "weld" in lower:
        label = "welding performance verification document"
    elif "覆膜" in filename or "film" in lower:
        label = "coating or film performance verification document"
    elif "验证" in filename or "检验" in filename or "verification" in lower or "validation" in lower:
        label = "verification or validation source document"
    else:
        label = "controlled source document"
    prefix = f"{source_id} - " if source_id else ""
    return f"{prefix}{label}"


