def _writer_support_status(row: dict[str, Any]) -> str:
    status = str(row.get("support_status") or row.get("support_level") or "").strip()
    if not status or status.lower() in {"to_be_verified", "pending", "unknown"}:
        return "pmcf_objective"
    if str(row.get("domain_relevance_class") or "").lower() in {"background_only", "excluded"}:
        return "downgraded_background_only"
    return status


def _writer_allowed_wording(row: dict[str, Any]) -> str:
    existing = str(row.get("allowed_wording") or row.get("allowed_language") or "").strip()
    if existing:
        return existing
    status = _writer_support_status(row).lower()
    if status in {"closed", "supported", "fully_supported", "moderate", "strong"}:
        return "supports the conclusion that, within the stated evidence limitations"
    if "background" in status:
        return "provides background context only and does not independently support a clinical claim"
    return "requires PMCF or manufacturer source closure before final claim wording"


def _claim_final_body_allowed(row: dict[str, Any]) -> bool:
    status = _writer_support_status(row).lower()
    if status in {"to_be_verified", "pending", "unknown", "pmcf_objective"}:
        return False
    if "background" in status or str(row.get("writer_consumption_decision") or "").lower().startswith("background_only"):
        return False
    return True


def _build_final_text_claim_support_map(state: dict[str, Any], cer_body_text: str) -> list[dict[str, Any]]:
    """Map each claim to its text sections, support wording, and whether wording is allowed."""
    claim_matrix = state.get("claim_evidence_matrix") or []
    constraints = state.get("writer_conclusion_constraints") or {}
    text_lower = cer_body_text.lower()
    rows = []
    for row in claim_matrix[:20]:
        claim_id = str(row.get("claim_id", ""))
        if not claim_id:
            continue
        support = str(row.get("support_status") or row.get("support_level") or "")
        conclusion = str(row.get("conclusion_strength") or row.get("max_conclusion_strength") or "")
        allowed = str(constraints.get(claim_id, {}).get("allowed_language_strength") or "")
        text_refs = []
        if claim_id.lower() in text_lower:
            idx = text_lower.find(claim_id.lower())
            text_refs.append(cer_body_text[max(0, idx - 80):min(len(cer_body_text), idx + 220)])
        rows.append({
            "claim_id": claim_id,
            "support_status": _writer_support_status(row),
            "conclusion_strength": conclusion,
            "allowed_wording": allowed or _writer_allowed_wording(row),
            "evidence_strength_ceiling": str(row.get("evidence_strength_ceiling") or conclusion or "CAUTIOUS"),
            "final_body_allowed": _claim_final_body_allowed(row),
            "text_sections": text_refs[:3],
            "wording_is_allowed": _claim_final_body_allowed(row) and not (support.upper() in {"INSUFFICIENT", "ALLOWED_USE_BLOCKED", "NOT_ALLOWED"}),
        })
    rows = _exhaust_alternatives_before_pmcf(state, rows)
    return rows


# ── Phase 6: IFU Bidirectional Feedback (engineer: 99% IFU lack clinical benefit) ──

def _generate_ifu_feedback(state: dict[str, Any]) -> list[dict[str, Any]]:
    """Generate IFU update suggestions from CER evidence analysis.

    Per engineer feedback: CER should NOT just consume IFU → it should
    feed BACK to IFU. Two patterns:
    1. Clinical benefits found in evidence but missing from IFU → suggest addition
    2. IFU claims with insufficient evidence → suggest scope narrowing
    """
    claims = state.get("claim_ledger") or []
    profile = state.get("device_profile") or {}

    suggestions = []
    # Pattern 1: Missing clinical benefit claims in IFU
    clinical_benefits = [c for c in claims if str(c.get("claim_type", "")).lower() in ("clinical_benefit", "performance")]
    ifu_purpose = str(profile.get("intended_purpose", ""))
    for cb in clinical_benefits[:10]:
        cb_text = str(cb.get("claim_text", ""))
        if cb_text and cb_text not in ifu_purpose:
            suggestions.append({
                "type": "add_clinical_benefit_to_ifu",
                "claim_id": cb.get("claim_id", ""),
                "suggested_ifu_text": f"Clinical benefit: {cb_text[:200]}",
                "rationale": "Evidence supports this benefit but IFU does not state it as a clinical benefit.",
            })

    # Pattern 2: Scope narrowing for insufficiently supported claims
    for claim in claims:
        support = str(claim.get("support_status", "")).upper()
        if support in ("INSUFFICIENT", "EVIDENCE_GAP", "NOT_SUPPORTED"):
            suggestions.append({
                "type": "narrow_ifu_claim_scope",
                "claim_id": claim.get("claim_id", ""),
                "current_ifu_text": str(claim.get("claim_text", ""))[:200],
                "suggested_action": "Consider narrowing IFU claim scope or adding evidence-level qualification.",
            })

    return suggestions[:10]


# ── Phase 6: GSPR Depth by Device Class (engineer: Class III逐条, IIb分组, IIa精简) ──

_GSPR_DEPTH_BY_CLASS: dict[str, dict[str, str]] = {
    "III": {"mode": "per_item", "description": "逐条分析每个GSPR条款, 五段式完整展开"},
    "IIb": {"mode": "grouped", "description": "按临床主题分组(GSPR安全/GSPR性能/GSPR风险), 每组五段式"},
    "IIa": {"mode": "summary", "description": "精简综述, 仅对高风险GSPR逐条展开"},
    "I": {"mode": "summary", "description": "精简综述"},
}


def _gspr_depth_config(state: dict[str, Any]) -> dict[str, Any]:
    """Return GSPR analysis depth based on device class (per engineer feedback)."""
    profile = state.get("device_profile") or {}
    device_class = str(profile.get("device_class") or _device_class(state) or "IIb")
    for key in ["III", "IIb", "IIa", "I"]:
        if key in device_class:
            return dict(_GSPR_DEPTH_BY_CLASS[key])
    return dict(_GSPR_DEPTH_BY_CLASS["IIb"])


# ── Phase 6: Risk Matrix Mapping (engineer: 心擎 method: risk→evidence→MDCG→residual) ──

def _build_risk_evidence_mapping(state: dict[str, Any]) -> list[dict[str, Any]]:
    """Build risk-to-evidence mapping per 心擎 Risk Matrix method.

    For each risk: find clinical evidence → assign MDCG level → assess residual risk.
    """
    risk_rows = state.get("risk_trace_matrix") or []
    evidence = state.get("evidence_registry") or []
    gspr = state.get("gspr_trace_matrix") or state.get("gspr_checklist") or []

    mapping = []
    _RISK_KEYWORDS = {
        "infection", "bleeding", "perforation", "thrombosis", "failure",
        "malfunction", "breakage", "migration", "occlusion", "allergic",
        "toxic", "electrical", "thermal", "mechanical", "biological",
        "embolism", "stenosis", "fracture", "leakage", "displacement",
    }
    for risk in risk_rows[:20]:
        risk_id = str(risk.get("risk_id", ""))
        risk_desc = str(risk.get("risk_description", risk.get("description", "")))[:120]

        # Find related evidence by keyword
        related_evidence = []
        risk_kws = _RISK_KEYWORDS & set(risk_desc.lower().split())
        for ev in evidence:
            ev_text = str(ev.get("title", "")) + " " + str(ev.get("abstract", ""))[:200]
            if risk_kws and any(kw in ev_text.lower() for kw in risk_kws):
                related_evidence.append({
                    "evidence_id": ev.get("evidence_id", ev.get("article_id", "")),
                    "title": str(ev.get("title", ""))[:120],
                    "mdcg_level": ev.get("mdcg_level", 8),
                    "weight": ev.get("weight", "MEDIUM"),
                })

        # GSPR linkage
        gspr_links = []
        for g in gspr:
            g_risk_ids = str(g.get("risk_ids", g.get("related_risks", "")))
            if risk_id in g_risk_ids:
                gspr_links.append(str(g.get("gspr_id", g.get("id", ""))))

        mapping.append({
            "risk_id": risk_id,
            "risk_description": risk_desc,
            "clinical_evidence": related_evidence[:5],
            "gspr_coverage": gspr_links[:5],
            "mdcg_highest_level": min((e["mdcg_level"] for e in related_evidence), default=8),
            "residual_risk_assessment": (
                "Acceptable with clinical evidence" if related_evidence
                else "Requires PMCF or RMF review"
            ),
        })

    return mapping


# ── Phase 6: IFU Feedback Report (engineer: CER→IFU closed loop) ──

def _build_ifu_feedback_report(state: dict[str, Any]) -> dict[str, Any]:
    """Build IFU update recommendation report from CER findings."""
    feedback = state.get("ifu_feedback_suggestions") or []
    profile = state.get("device_profile") or {}

    return {
        "report_title": "IFU Update Recommendations (based on CER findings)",
        "generated_from": "CER authoring run",
        "device": profile.get("device_name", "Device Under Evaluation"),
        "suggestions": feedback,
        "summary": {
            "total_suggestions": len(feedback),
            "add_clinical_benefit": sum(1 for f in feedback if f.get("type") == "add_clinical_benefit_to_ifu"),
            "narrow_scope": sum(1 for f in feedback if f.get("type") == "narrow_ifu_claim_scope"),
        },
        "disclaimer": "These suggestions are based on CER evidence analysis. Final IFU updates require manufacturer review and regulatory assessment.",
    }


def write_cer_chapters(state: dict[str, Any]) -> dict[str, Any]:
    writer_guard = _writer_invocation_guard(state)
    if not writer_guard.get("writer_invocation_allowed"):
        return {
            "writer_invocation_allowed": False,
            "writer_invocation_guard": writer_guard,
            "stage_results": [
                {
                    "stage": "cer_writing",
                    "status": "blocked_pre_writer_readiness",
                    "reason": writer_guard.get("reason"),
                }
            ],
        }
    ledger_updates = build_claim_evidence_benefit_risk_ledgers(state)
    if ledger_updates:
        state = {**state, **ledger_updates}
    synthesis_updates = build_cross_evidence_synthesis(state)
    if synthesis_updates:
        state = {**state, **synthesis_updates}
    template_updates = build_writer_device_template_profile(state)
    if template_updates:
        state = {**state, **template_updates}
    writer_input_packet = _build_writer_input_packet(state)
    state = {**state, "writer_input_packet": writer_input_packet}
    lineage_freeze = _freeze_evidence_lineage_update(state, "cer_writing", "Writer completed after upstream evidence-sufficiency routing.")
    # Phase 6: Generate IFU feedback from CER findings
    ifu_feedback = _generate_ifu_feedback(state)
    if state.get("cer_chapter_drafts"):
        domain = _clinical_domain(state)
        sanitized = _sanitize_chapters_for_domain(dict(state["cer_chapter_drafts"]), domain)
        return {"cer_chapter_drafts": sanitized, "writer_invocation_allowed": True, "writer_invocation_guard": writer_guard, "writer_input_packet": writer_input_packet, "ifu_feedback_suggestions": ifu_feedback, "ifu_working_document_status": _build_ifu_working_document_status(state), "ifu_cer_alignment_ledger": _build_ifu_cer_alignment_ledger(state), "sota_benchmark_reasoning_trace": _build_sota_benchmark_reasoning_trace(state), **ledger_updates, **synthesis_updates, **template_updates, **lineage_freeze}
    state = _english_report_state(state)
    profile = state.get("device_profile") or {}
    device = profile.get("device_name", "Device Under Evaluation")
    domain = _clinical_domain(state)
    evaluator_device_context = (
        "cardiac electrophysiology and pulsed-field ablation device technology"
        if domain == "cardiac_pfa"
        else "radiofrequency ablation catheter device technology, pulmonary artery denervation and cardiac ablation clinical context"
        if domain == "cardiovascular_rf_ablation_catheter"
        else "cardiac tissue stabilizer device technology, coronary artery bypass and cardiac surgery clinical context"
        if domain == "cardiac_tissue_stabilizer"
        else "plasma surgical electrode device technology, ENT surgical resection and coagulation clinical context"
        if domain == "plasma_surgical_electrode"
        else "urological endoscopy, single-use ureteroscope/nephroscope device technology, electrical/endoscopic safety and sterilised patient-contact device controls"
        if domain == "urology_nephroscope"
        else "urological clinical context, access-sheath device technology"
        if domain == "urology_uas"
        else "the IFU-defined clinical and device-technology context"
    )
    chapters = {
        "Clinical Evaluation Report": _chapter_title_page(state),
        "Document Revision History": _chapter_revision_history(state),
        "Contents": _chapter_contents(),
        "1 Summary": _chapter_summary(device, state),
        "2 Scope of Clinical Evaluation": _chapter_scope(profile, state),
        "3 Clinical Background, Current Knowledge and SOTA": _chapter_sota(state),
        "4 Device Under Evaluation": _chapter_device_under_evaluation(state),
        "5 Conclusions": _chapter_conclusions(state),
        "6 Date of Next Clinical Evaluation": _chapter_next_evaluation(state),
        "7 Evaluator Qualification": _chapter_evaluator_qualification(state),
        "8 Declaration of Interest": _chapter_declaration_of_interest(state),
        "9 Dates and Signatures": _chapter_dates_and_signatures(state),
        "4.2 Equivalence Three-Dimensional Comparison": _chapter_equivalence_3d(state),
        "References": _chapter_references(state),
        "Annex A Source Inventory and Input Completeness": _annex_source_inventory(state),
        "Annex B Claim Ledger": _annex_claim_ledger(state),
        "Annex C PICO Derivation and Search Protocol": _annex_pico_and_search(state),
        "Annex D Literature Screening and Evidence Appraisal": _annex_evidence(state),
        "Annex E Endpoint Benchmark Matrix": _annex_endpoints_and_benchmarks(state),
        "Annex F Equivalence and Similar Device Use": _annex_equivalence(state),
        "Annex G Vigilance and Recall Registry": _annex_vigilance(state),
        "Annex H Risk, IFU, RMF, PMS/PMCF and GSPR Trace": _annex_risk_gspr(state),
        "Annex I Evidence Gaps and PMCF Recommendations": _annex_gaps(state),
        "Annex J MCP Execution and Human Template Benchmark": _annex_mcp_and_style(state),
        "Annex K Device Identity Lock and Source Role Separation": _annex_device_identity_lock(state),
        "Annex L Claim-by-Claim Evidence Reasoning Expansion": _annex_claim_reasoning_expansion(state),
        "Annex M Engineer NB-Facing Comment Controls": _annex_engineer_comment_controls(state),
        "Annex N Literature Search Protocol Methodology": _annex_lsp_methodology(state),
        "Annex O SOTA Complex Tables and 4.7 Trace": _annex_sota_complex_tables(state),
    }
    chapters = {key: _sanitize_regulatory_language(value) for key, value in chapters.items()}
    chapters = _sanitize_chapters_for_domain(chapters, domain)
    # ── R1: Attempt LLM refinement ──
    llm_refined = False
    try:
        refined = _llm_refine_chapters({**state, "cer_chapter_drafts": chapters, "writer_input_packet": writer_input_packet})
        if refined and any(
            str(refined.get(k, "")) != str(chapters.get(k, ""))
            for k in chapters
            if k in refined and len(str(chapters.get(k, "")).split()) > 50
        ):
            chapters = refined
            llm_refined = True
    except Exception:
        pass  # LLM unavailable — use deterministic chapters
    return {
        "cer_chapter_drafts": chapters,
        "domain_contamination_report": _domain_contamination_report({**state, "cer_chapter_drafts": chapters}),
        "writer_quality_report": _writer_quality_self_check(chapters),
        "writer_input_packet": writer_input_packet,
        "ifu_feedback_suggestions": ifu_feedback,
        "ifu_working_document_status": _build_ifu_working_document_status(state),
        "ifu_cer_alignment_ledger": _build_ifu_cer_alignment_ledger(state),
        "ifu_update_recommendation_ledger": _build_ifu_update_recommendation_ledger({**state, "ifu_feedback_suggestions": ifu_feedback}),
        "sota_benchmark_reasoning_trace": _build_sota_benchmark_reasoning_trace(state),
        "sota_endpoint_selection_ledger": _build_sota_endpoint_selection_ledger(state),
        "sota_benchmark_to_claim_alignment": _build_sota_benchmark_to_claim_alignment(state),
        "argument_flow_report": _score_argument_flow(chapters),
        "cross_chapter_review": _llm_cross_chapter_review({**state, "cer_chapter_drafts": chapters}),
        "pmcf_template": _build_pmcf_template(state),
        "br_quantitative_template": _build_br_quantitative_template(state),
        "data_flow_validation": _validate_data_flows({**state, "cer_chapter_drafts": chapters}),
        "llm_refinement_applied": llm_refined,
        **ledger_updates,
        **synthesis_updates,
        **template_updates,
        **lineage_freeze,
        "writer_invocation_allowed": True,
        "writer_invocation_guard": writer_guard,
    }


def _writer_invocation_guard(state: dict[str, Any]) -> dict[str, Any]:
    source_preflight = state.get("source_preflight_gate_report") or {}
    if source_preflight.get("status") == "BLOCKED":
        return {
            "writer_invocation_allowed": False,
            "reason": "source_preflight_gate is BLOCKED; Writer must not generate a CER from uncontrolled inputs.",
            "pre_writer_gate_status": "source_preflight_blocked",
            "required_gate": "SOURCE_PREFLIGHT",
            "allowed_ledgers": [],
            "prohibited_action": "Do not generate CER_draft when source package has P0 blockers.",
        }
    classification = state.get("classification_consistency_report") or {}
    if classification.get("status") == "BLOCKED":
        return {
            "writer_invocation_allowed": False,
            "reason": "classification_consistency_gate is BLOCKED; resolve device class conflict before Writer.",
            "pre_writer_gate_status": "classification_conflict",
            "required_gate": "CLASSIFICATION_CONSISTENCY_GATE",
            "allowed_ledgers": [],
            "prohibited_action": "Do not write CER with conflicting MDR classification.",
        }
    cep_ok, cep_message = _cep_complete_for_writer(state.get("clinical_evaluation_plan") or {})
    if not cep_ok:
        return {
            "writer_invocation_allowed": False,
            "reason": cep_message,
            "pre_writer_gate_status": "cep_incomplete",
            "required_gate": "G_CEP",
            "allowed_ledgers": [],
            "prohibited_action": "Do not generate final CER without a complete Clinical Evaluation Plan.",
        }
    br_matrix = state.get("benefit_risk_closure_matrix") or {}
    if br_matrix.get("closure_status") == "NOT_CONCLUDABLE":
        return {
            "writer_invocation_allowed": False,
            "reason": "benefit_risk_closure_matrix is NOT_CONCLUDABLE.",
            "pre_writer_gate_status": "benefit_risk_not_concludable",
            "required_gate": "BR_CLOSURE_GATE",
            "allowed_ledgers": [],
            "prohibited_action": "Do not write acceptable benefit-risk conclusion; only controlled limitation draft is allowed.",
        }
    readiness = state.get("pre_writer_readiness_report") or {}
    if readiness and readiness.get("status") != "PASS":
        return {
            "writer_invocation_allowed": False,
            "reason": f"pre_writer_readiness_gate is {readiness.get('status')}; Writer must wait for G46 PASS.",
            "pre_writer_gate_status": readiness.get("status"),
            "required_gate": "G46",
            "allowed_ledgers": [],
            "prohibited_action": "Do not generate CER_draft or convert background-only evidence into strong clinical conclusions.",
        }
    allowed = _gate_passed_ledger_status(state)
    return {
        "writer_invocation_allowed": True,
        "reason": "G46 passed or no readiness report is present in direct pipeline invocation compatibility mode.",
        "pre_writer_gate_status": readiness.get("status") or "not_recorded_compatibility_mode",
        "required_gate": "G46",
        "allowed_ledgers": allowed,
        "prohibited_action": "Background-only evidence may be described only as context/limitation; strong clinical conclusions require pivotal/supportive gate-passed evidence.",
    }


def _cep_complete_for_writer(cep: dict[str, Any]) -> tuple[bool, str]:
    if not cep:
        return False, "Clinical Evaluation Plan not generated."
    required = [
        "device_name",
        "device_class",
        "scope",
        "literature_search_protocol",
        "appraisal_method",
        "sota_methodology",
        "claim_support_method",
        "benefit_risk_method",
        "pms_pmcf_update_plan",
    ]
    missing = [key for key in required if not cep.get(key)]
    protocol = cep.get("literature_search_protocol") or {}
    if isinstance(protocol, dict):
        for key in ("databases", "inclusion_criteria", "exclusion_criteria"):
            if not protocol.get(key):
                missing.append(f"literature_search_protocol.{key}")
    if missing:
        return False, f"Clinical Evaluation Plan incomplete: {', '.join(missing[:8])}"
    return True, "Clinical Evaluation Plan complete."


def _gate_passed_ledger_status(state: dict[str, Any]) -> list[dict[str, Any]]:
    ledger_specs = (
        ("claim_evidence_matrix", "claim_evidence_gate_report"),
        ("benefit_risk_ledger", "br_justified_gate_report"),
        ("alignment_matrix", "alignment_gate_report"),
    )
    rows = []
    for artifact_name, gate_key in ledger_specs:
        report = state.get(gate_key) or {}
        rows.append(
            {
                "artifact_name": artifact_name,
                "gate_report": gate_key,
                "gate_status": report.get("status") or "not_recorded_compatibility_mode",
                "consumption_allowed": (not report) or report.get("status") == "PASS",
            }
        )
    return rows


def refresh_late_annexes(state: dict[str, Any]) -> dict[str, Any]:
    chapters = dict(state.get("cer_chapter_drafts") or {})
    if not chapters:
        return {}
    chapters["Annex J MCP Execution and Human Template Benchmark"] = _annex_mcp_and_style(state)
    chapters["Annex M Engineer NB-Facing Comment Controls"] = _annex_engineer_comment_controls(state)
    chapters["Annex N Literature Search Protocol Methodology"] = _annex_lsp_methodology(state)
    chapters["Annex O SOTA Complex Tables and 4.7 Trace"] = _annex_sota_complex_tables(state)
    chapters["Annex P PRISMA Flow and Search Trace"] = _annex_prisma_flow(state)
    chapters["Annex Q Similar Device Four-Step Confirmation"] = _annex_similar_device_four_step(state)
    chapters["Annex R Market PMS Questionnaire and Vigilance Statistics"] = _annex_market_vigilance_sources(state)
    domain = _clinical_domain(state)
    chapters = _sanitize_chapters_for_domain(chapters, domain)
    return {"cer_chapter_drafts": chapters}


def build_gap_pmcf_recommendations(state: dict[str, Any]) -> dict[str, Any]:
    existing = state.get("gap_pmcf_recommendations") or []
    gaps = list(existing or state.get("input_gap_list") or [])
    for evidence in state.get("evidence_registry") or []:
        if evidence.get("evidence_id", "").startswith("E-GAP") and not any(str(row.get("gap_id") or "") == "GAP-EVIDENCE-001" for row in gaps):
            gaps.append({"gap_id": "GAP-EVIDENCE-001", "gap": evidence.get("result"), "pmcf_measure": "Targeted PMCF/literature update and endpoint extraction"})
        if _is_pending_evidence_record(evidence):
            gap_id = f"GAP-{str(evidence.get('evidence_id') or evidence.get('source_type') or 'EVIDENCE-PENDING').replace('_', '-')}"
            if not any(str(row.get("gap_id") or "") == gap_id for row in gaps):
                gaps.append(
                    {
                        "gap_id": gap_id,
                        "gap": "Pending source placeholder requires retrieval before it can be treated as quantitative evidence.",
                        "gap_type": "retrieval_gap",
                        "required_input": evidence.get("source_anchor") or evidence.get("source") or evidence.get("evidence_id"),
                        "pmcf_measure": "Retrieve the pending source, parse endpoint/sample/timepoint/result data, or keep as evidence limitation.",
                        "severity": "LIMITING",
                    }
                )
    if not _has_source(state, "rmf"):
        if not any(str(row.get("gap_id") or "") == "GAP-RMF-001" for row in gaps):
            gaps.append({"gap_id": "GAP-RMF-001", "gap": "RMF/RMR not provided", "pmcf_measure": "Integrate RMF risk IDs and residual risk acceptability in next upgrade"})
    if not _has_source(state, "pms"):
        if not any(str(row.get("gap_id") or "") == "GAP-PMS-001" for row in gaps):
            gaps.append({"gap_id": "GAP-PMS-001", "gap": "PMS/PMCF data not provided", "pmcf_measure": "Collect post-market complaints, sales exposure, vigilance, and PMCF outcomes"})
    # V2 BL-18: PMCF follow-up adequacy and rare event sample size check
    device_class = str((state.get("device_profile") or {}).get("device_class") or "").replace("Class ","")
    device_type_lower = str((state.get("device_profile") or {}).get("device_type") or "").lower()
    implantable = device_class in ("III",) or any(k in device_type_lower for k in ("implant","stent","clip"))
    if implantable:
        facts = state.get("clinical_evidence_fact_table") or []
        max_followup = max((_safe_float(f.get("follow_up","0")) for f in facts if f.get("follow_up")), default=0)
        if max_followup < 12 and not any(str(r.get("gap_id") or "") == "GAP-FOLLOWUP-001" for r in gaps):
            gaps.append({"gap_id":"GAP-FOLLOWUP-001","gap":f"Max follow-up {max_followup} months < 12 months for implantable device","gap_type":"follow_up_adequacy","pmcf_measure":"Extend PMCF to minimum 12-month follow-up for implantable device","severity":"HIGH"})
    total_n = sum(_safe_int(f.get("population_n",0)) for f in (state.get("clinical_evidence_fact_table") or []))
    if total_n < 300 and implantable and not any(str(r.get("gap_id") or "") == "GAP-RAREEVENT-001" for r in gaps):
        gaps.append({"gap_id":"GAP-RAREEVENT-001","gap":f"Total N={total_n} < 300; underpowered for 1% rare event detection","gap_type":"rare_event_power","pmcf_measure":"PMCF should target >=300 patients for rare event detection (95% confidence for 1% event rate)","severity":"MEDIUM"})
    hardened = [_harden_gap_pmcf_row(state, row, idx) for idx, row in enumerate(gaps, start=1)]
    decisions = _pmcf_boundary_decision_rows(state, hardened)
    updates: dict[str, Any] = {"marketing_pms_customer_questionnaire": _marketing_pms_questionnaire_rows(state)}
    if hardened != existing:
        updates["gap_pmcf_recommendations"] = hardened
    if decisions != (state.get("pmcf_boundary_decision_log") or []):
        updates["pmcf_boundary_decision_log"] = decisions
    return updates


def _harden_gap_pmcf_row(state: dict[str, Any], row: dict[str, Any], idx: int) -> dict[str, Any]:
    gap_id = str(row.get("gap_id") or row.get("id") or f"GAP-PMCF-{idx:03d}")
    gap_text = str(row.get("gap") or row.get("description") or row.get("impact") or row.get("required_input") or "Evidence gap")
    required_input = str(row.get("required_input") or _required_input_for_gap(gap_id, gap_text))
    gap_type = row.get("gap_type") or _pmcf_gap_type(gap_id, gap_text, required_input)
    affected_claim_ids = row.get("affected_claim_ids") or _affected_claim_ids_for_gap(state, gap_text)
    affected_endpoint_ids = row.get("affected_endpoint_ids") or _affected_endpoint_ids_for_gap(state, gap_text)
    severity = row.get("severity") or _pmcf_gap_severity(str(gap_type), gap_text)
    return {
        **row,
        "gap_id": gap_id,
        "required_input": required_input,
        "gap": gap_text,
        "gap_type": gap_type,
        "affected_claim_ids": affected_claim_ids,
        "affected_endpoint_ids": affected_endpoint_ids,
        "severity": severity,
        "pmcf_measure": row.get("pmcf_measure") or _pmcf_measure_for_gap(str(gap_type), required_input),
    }


def _pmcf_boundary_decision_rows(state: dict[str, Any], gaps: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for idx, gap in enumerate(gaps, start=1):
        gap_type = str(gap.get("gap_type") or "")
        gap_text = str(gap.get("gap") or "")
        required_input = str(gap.get("required_input") or "")
        pre_submission, pre_rationale = _pre_submission_decision(gap_type, gap_text, required_input)
        pmcf_allowed, pmcf_rationale = _pmcf_allowed_decision(gap_type, gap_text, required_input)
        downgrade, downgrade_rationale = _claim_downgrade_decision(gap_type, gap_text, required_input)
        rows.append(
            {
                "decision_id": f"PMCF-BD-{idx:03d}",
                "gap_id": gap.get("gap_id"),
                "gap_type": gap_type,
                "gap": gap_text,
                "affected_claim_ids": gap.get("affected_claim_ids") or "all impacted claims",
                "affected_endpoint_ids": gap.get("affected_endpoint_ids") or "endpoint impact to be mapped",
                "severity": gap.get("severity") or "medium",
                "pre_submission_required": pre_submission,
                "pre_submission_rationale": pre_rationale,
                "pmcf_allowed": pmcf_allowed,
                "pmcf_allowed_rationale": pmcf_rationale,
                "claim_downgrade_required": downgrade,
                "claim_downgrade_rationale": downgrade_rationale,
                "claim_action": _claim_action_from_pmcf_boundary(pre_submission, pmcf_allowed, downgrade),
                "benefit_risk_impact": _benefit_risk_impact_from_pmcf_boundary(pre_submission, downgrade),
                "human_gate_required": _human_gate_for_pmcf_boundary(pre_submission, downgrade),
                "pmcf_measure": gap.get("pmcf_measure"),
                "evidence_basis": _pmcf_boundary_evidence_basis(state, gap),
                "source_artifact": "gap_pmcf_recommendations; evidence_registry; endpoint_extraction; risk_trace_matrix; source_inventory",
                "conclusion": "PMCF boundary is triaged across pre-submission resolution, PMCF permissibility and claim-downgrade control.",
            }
        )
    return rows


def _required_input_for_gap(gap_id: str, gap_text: str) -> str:
    text = f"{gap_id} {gap_text}".lower()
    if "rmf" in text or "risk" in text or "rmr" in text or "fmea" in text:
        return "RMF/RMR/FMEA"
    if "pms" in text or "pmcf" in text or "complaint" in text or "marketing" in text:
        return "PMS/PMCF"
    if "gspr" in text:
        return "GSPR checklist"
    if "full-text" in text or "full text" in text or "endpoint" in text or "clinical" in text or "evidence" in text:
        return "clinical evidence / full-text endpoint extraction"
    return "source document / human evaluator confirmation"


def _pmcf_gap_type(gap_id: str, gap_text: str, required_input: str) -> str:
    text = f"{gap_id} {gap_text} {required_input}".lower()
    if "rmf" in text or "rmr" in text or "fmea" in text or "risk" in text:
        return "risk_management_closure_gap"
    if "gspr" in text:
        return "gspr_conformity_gap"
    if "pivotal" in text or "clinical investigation" in text or "endpoint" in text or "benefit" in text or "performance" in text:
        return "core_clinical_evidence_gap"
    if "full text" in text or "full-text" in text or "ci" in text or "sample" in text or "follow" in text:
        return "evidence_extraction_precision_gap"
    if "pms" in text or "pmcf" in text or "complaint" in text or "marketing" in text:
        return "post_market_follow_up_gap"
    return "source_traceability_gap"


def _pmcf_gap_severity(gap_type: str, gap_text: str) -> str:
    text = f"{gap_type} {gap_text}".lower()
    if gap_type in {"risk_management_closure_gap", "gspr_conformity_gap"}:
        return "high"
    if "core" in gap_type or "pivotal" in text:
        return "high"
    if gap_type == "evidence_extraction_precision_gap":
        return "medium"
    return "medium"


def _affected_claim_ids_for_gap(state: dict[str, Any], gap_text: str) -> str:
    claims = state.get("claim_ledger") or []
    if not claims:
        return "claim mapping required"
    text = gap_text.lower()
    matched = [
        str(row.get("claim_id"))
        for row in claims
        if row.get("claim_id")
        and any(token in " ".join(str(value) for value in row.values()).lower() for token in ("performance", "safety", "benefit", "risk", "intended"))
        and any(token in text for token in ("performance", "safety", "benefit", "risk", "clinical", "evidence", "rmf", "pms", "pmcf"))
    ]
    return ", ".join(matched[:12]) or ", ".join(str(row.get("claim_id")) for row in claims[:8] if row.get("claim_id")) or "claim mapping required"


def _affected_endpoint_ids_for_gap(state: dict[str, Any], gap_text: str) -> str:
    endpoints = state.get("endpoint_extraction") or state.get("sota_endpoint_derivation_table") or []
    if not endpoints:
        return "endpoint mapping required"
    text = gap_text.lower()
    if any(token in text for token in ("endpoint", "clinical", "performance", "benefit", "evidence", "full text", "sample", "ci")):
        return ", ".join(str(row.get("endpoint_id")) for row in endpoints if row.get("endpoint_id")) or "endpoint mapping required"
    return "not endpoint-specific"


def _pmcf_measure_for_gap(gap_type: str, required_input: str) -> str:
    if gap_type == "risk_management_closure_gap":
        return "Obtain and map RMF/RMR risk IDs, controls, residual-risk acceptability and IFU warnings before final benefit-risk conclusion."
    if gap_type == "core_clinical_evidence_gap":
        return "Resolve pivotal/full-text endpoint evidence before signature-level claim; PMCF may monitor residual long-term uncertainty after claim downgrade."
    if gap_type == "evidence_extraction_precision_gap":
        return "Retrieve full text, extract endpoint definition, sample size, timepoint, numerator/denominator, CI/range and statistical method."
    if gap_type == "post_market_follow_up_gap":
        return "Provide PMS/PMCF plan or report, exposure denominator, complaint trend and follow-up timetable."
    if gap_type == "gspr_conformity_gap":
        return "Provide GSPR checklist and map clinical evidence/risk controls to Annex I before conformity wording."
    return f"Provide {required_input} and evaluator rationale before upgrading conclusions."


def _pre_submission_decision(gap_type: str, gap_text: str, required_input: str) -> tuple[str, str]:
    if gap_type in {"risk_management_closure_gap", "gspr_conformity_gap"}:
        return (
            "required_before_nb_submission_for_final_conformity_or_benefit_risk_claim",
            f"{required_input} is needed to substantiate risk/GSPR closure; PMCF cannot replace missing pre-submission conformity evidence.",
        )
    if gap_type == "core_clinical_evidence_gap":
        return (
            "required_before_nb_submission_for_signature_level_or_strong_claim",
            "A core clinical endpoint or pivotal evidence gap affects the claim basis itself; it must be resolved before strong/supportive final wording, or the claim must be downgraded.",
        )
    if gap_type == "evidence_extraction_precision_gap":
        return (
            "required_before_nb_submission_for_quantitative_benchmark_or_claim_upgrade",
            "Quantitative benchmark and endpoint wording requires full extraction; without it, the CER may proceed only as a controlled qualitative draft.",
        )
    if gap_type == "post_market_follow_up_gap":
        return (
            "conditional_before_submission_based_on_market_status_and_claim_strength",
            "PMS/PMCF source data are required for marketed-device final claims; for pre-market/no-sales projects, a justified PMCF plan and timetable may control residual uncertainty.",
        )
    return (
        "conditional_before_submission_based_on_evaluator_materiality",
        "The gap requires evaluator triage because its impact depends on the affected claim and the availability of alternative source evidence.",
    )


def _pmcf_allowed_decision(gap_type: str, gap_text: str, required_input: str) -> tuple[str, str]:
    if gap_type in {"risk_management_closure_gap", "gspr_conformity_gap"}:
        return (
            "not_allowed_as_primary_resolution",
            "PMCF may monitor residual risk after RMF/GSPR closure, but cannot substitute for absent risk-management or GSPR conformity evidence.",
        )
    if gap_type == "core_clinical_evidence_gap":
        return (
            "allowed_only_for_residual_uncertainty_after_pre_submission_evidence_or_claim_downgrade",
            "PMCF can address long-term, rare-event or real-world residual questions, but cannot be the only basis for an unsupported core clinical claim.",
        )
    if gap_type == "evidence_extraction_precision_gap":
        return (
            "not_pmcf_primary_full_text_or_source_extraction_required",
            "The first action is full-text/source extraction; PMCF is only relevant if residual long-term uncertainty remains after endpoint extraction.",
        )
    if gap_type == "post_market_follow_up_gap":
        return (
            "allowed_with_defined_plan_timetable_and_acceptance_criteria",
            "PMS/PMCF is the proper mechanism for post-market exposure, long-term performance and rare-event monitoring if the plan, endpoints and timetable are explicit.",
        )
    return (
        "allowed_with_conditions_after_source_traceability_review",
        "PMCF may be used only if the gap is a residual unanswered question rather than missing evidence for a core pre-submission claim.",
    )


def _claim_downgrade_decision(gap_type: str, gap_text: str, required_input: str) -> tuple[str, str]:
    if gap_type in {"risk_management_closure_gap", "gspr_conformity_gap"}:
        return (
            "downgrade_or_hold_safety_benefit_risk_and_conformity_claims",
            "Without risk/GSPR closure, the writer must not state final conformity, all-risks-acceptable or favourable benefit-risk conclusions.",
        )
    if gap_type == "core_clinical_evidence_gap":
        return (
            "downgrade_to_partial_support_or_remove_claim_until_evidence_resolved",
            "Core clinical evidence gaps require claim wording to be reduced to partial/gap-controlled support unless pre-submission evidence is added.",
        )
    if gap_type == "evidence_extraction_precision_gap":
        return (
            "downgrade_quantitative_or_comparative_wording_to_qualitative_controlled_wording",
            "Missing sample size, CI/range or endpoint definition prevents quantitative or comparative claim strength.",
        )
    if gap_type == "post_market_follow_up_gap":
        return (
            "downgrade_final_real_world_or_long_term_claims_until_pmcf_plan_or_data_available",
            "Missing PMS/PMCF affects real-world, long-term and rare-risk conclusions; short-term source-supported claims may remain qualified.",
        )
    return (
        "qualification_required_until_gap_materiality_confirmed",
        "The claim must remain qualified until the evaluator confirms whether the gap is material to the intended purpose or benefit-risk conclusion.",
    )


def _claim_action_from_pmcf_boundary(pre_submission: str, pmcf_allowed: str, downgrade: str) -> str:
    if "required_before_nb_submission" in pre_submission and "not_allowed" in pmcf_allowed:
        return "hold_final_claim_until_pre_submission_source_closure"
    if "downgrade" in downgrade or "remove" in downgrade:
        return "downgrade_or_qualify_claim_and_record_pmcf_boundary"
    if "allowed_with_defined_plan" in pmcf_allowed:
        return "retain_controlled_claim_with_pmcf_timetable"
    return "human_evaluator_triage_required"


def _benefit_risk_impact_from_pmcf_boundary(pre_submission: str, downgrade: str) -> str:
    if "risk" in downgrade or "benefit" in downgrade or "required_before_nb_submission" in pre_submission:
        return "blocks_unqualified_final_benefit_risk_conclusion"
    if "quantitative" in downgrade or "real_world" in downgrade:
        return "requires_qualified_or_partial_benefit_risk_conclusion"
    return "requires_documented_limitation"


def _human_gate_for_pmcf_boundary(pre_submission: str, downgrade: str) -> str:
    if "required_before_nb_submission" in pre_submission or "hold" in downgrade or "remove" in downgrade:
        return "yes"
    return "yes_for_signature_upgrade"


def _pmcf_boundary_evidence_basis(state: dict[str, Any], gap: dict[str, Any]) -> str:
    evidence_ids = ", ".join(str(row.get("evidence_id")) for row in (state.get("evidence_registry") or [])[:6] if row.get("evidence_id")) or "evidence registry gap"
    risk_ids = ", ".join(str(row.get("risk_id")) for row in (state.get("risk_trace_matrix") or [])[:6] if row.get("risk_id")) or "risk trace gap"
    source_ids = ", ".join(str(row.get("source_id")) for row in (state.get("source_inventory") or [])[:6] if row.get("source_id")) or "source inventory"
    return f"Gap {gap.get('gap_id')} assessed against evidence IDs [{evidence_ids}], risk IDs [{risk_ids}], source IDs [{source_ids}]."


def build_claim_evidence_benefit_risk_ledgers(state: dict[str, Any]) -> dict[str, Any]:
    """Build the mandatory Claim -> Evidence -> Benefit-Risk writer spine.

    This is a deterministic carrier layer for Phase 2.3. It does not change
    G38 criteria; it makes the conclusion-strength guard traceable to claims,
    evidence, SOTA benchmarks, gaps and risk controls before writer output.
    """

    claims = state.get("claim_ledger") or []
    if not claims:
        return {}
    boundary_updates = {}
    if not state.get("pmcf_boundary_decision_log"):
        boundary_updates = build_gap_pmcf_recommendations(state)
        if boundary_updates:
            state = {**state, **boundary_updates}
    alignment_updates = {}
    if not state.get("alignment_matrix"):
        alignment_updates = build_alignment_matrix(state)
        if alignment_updates:
            state = {**state, **alignment_updates}
    allowed_use = _allowed_use_matrix_rows(state)
    matrix = _claim_evidence_matrix_rows(state)
    benefit_risk = _benefit_risk_ledger_rows(state, matrix)
    writer_guard = _writer_conclusion_strength_guard_rows(state, matrix, benefit_risk)
    writer_evidence_trace = _writer_evidence_consumption_trace_rows({**state, "allowed_use_matrix": allowed_use})
    existing_guard = state.get("sota_conclusion_strength_guard") or []
    section_trace = _cer_section_trace_map_rows(state, matrix, benefit_risk, writer_guard)
    return {
        **boundary_updates,
        **alignment_updates,
        "allowed_use_matrix": allowed_use,
        "claim_evidence_matrix": matrix,
        "benefit_risk_ledger": benefit_risk,
        "writer_conclusion_strength_guard": writer_guard,
        "writer_evidence_consumption_trace": writer_evidence_trace,
        "sota_conclusion_strength_guard": [*existing_guard, *writer_guard],
        "cer_section_trace_map": section_trace,
    }


def build_controlled_compromise_report(state: dict[str, Any]) -> dict[str, Any]:
    """Build the terminal non-CER insufficiency packet.

    Controlled compromise is entered before Writer. This function must not
    generate CER chapter drafts or call writer helpers; it only summarizes what
    is known, what cannot be concluded, and what human decision is required.
    """

    readiness = state.get("pre_writer_readiness_report") or {}
    blocked_conditions = readiness.get("failing_sub_conditions") or []
    source_preflight = state.get("source_preflight_gate_report") or {}
    if not blocked_conditions and source_preflight.get("status") == "BLOCKED":
        blocked_conditions = [
            {
                "condition_name": "source_preflight",
                "status": "BLOCKED",
                "message": issue.get("message") or issue.get("issue_id") or "Source preflight blocker.",
                "failure_pattern": issue.get("issue_id") or "source_preflight_blocked",
                "details": issue,
            }
            for issue in source_preflight.get("blocking_issues") or []
            if isinstance(issue, dict)
        ]
    blocked_reason = (
        readiness.get("compromise_reason")
        or readiness.get("message")
        or (
            "Source preflight blocked Writer invocation."
            if source_preflight.get("status") == "BLOCKED"
            else "Pre-writer readiness gate blocked Writer invocation."
        )
    )
    terminal_status = _controlled_compromise_terminal_status(blocked_conditions, blocked_reason)
    manifest = {
        "schema_name": "controlled_compromise_manifest",
        "terminal_status": terminal_status,
        "blocked_reason": blocked_reason,
        "blocked_conditions": blocked_conditions,
        "spiral_rounds_exhausted": state.get("spiral_rounds_exhausted", False),
        "writer_invoked": False,
        "cer_draft_generated": False,
    }
    evidence_status = _controlled_compromise_evidence_status_report(state, readiness)
    recommendation = _controlled_compromise_recommendation(state, terminal_status, blocked_conditions)
    human_decisions = _controlled_compromise_human_decisions(terminal_status, blocked_conditions)
    lineage_freeze = _freeze_evidence_lineage_update(state, "controlled_compromise", blocked_reason)
    return {
        "compromise_manifest": manifest,
        "controlled_compromise_manifest": manifest,
        "evidence_status_report": evidence_status,
        "recommendation": recommendation,
        "human_decision_required": human_decisions,
        **lineage_freeze,
    }


def _controlled_compromise_terminal_status(blocked_conditions: list[dict[str, Any]], blocked_reason: str) -> str:
    names = {str(row.get("condition_name") or "").lower() for row in blocked_conditions}
    reason = str(blocked_reason or "").lower()
    name_blob = " ".join(sorted(names))
    if "identity" in names or "domain" in reason or "domain" in name_blob:
        return "DOMAIN_FATAL"
    if "human" in reason:
        return "HUMAN_DECISION_REQUIRED"
    if any(token in name_blob for token in ("evidence_sufficiency", "fulltext_basis", "screening_pool")):
        return "EVIDENCE_INSUFFICIENT_TERMINAL"
    if "evidence" in name_blob:
        return "EVIDENCE_INSUFFICIENT_TERMINAL"
    return "REASONING_CHAIN_INCOMPLETE"


def _controlled_compromise_evidence_status_report(state: dict[str, Any], readiness: dict[str, Any]) -> str:
    claims = state.get("claim_ledger") or []
    evidence = state.get("evidence_registry") or []
    approved_evidence = _writer_approved_evidence_rows(evidence)
    gaps = state.get("gap_pmcf_recommendations") or []
    lines = [
        "# Evidence Status Report",
        "",
        "## What Is Known",
        "",
    ]
    if claims:
        for claim in claims[:12]:
            claim_id = claim.get("claim_id") or "claim"
            lines.append(f"- {claim_id}: {claim.get('claim_text') or claim.get('statement') or claim.get('claim_type') or 'claim recorded'}")
    else:
        lines.append("- No claim ledger rows were available.")
    lines.extend(["", "## Evidence Available", ""])
    if approved_evidence:
        for row in approved_evidence[:12]:
            lines.append(f"- {row.get('evidence_id')}: {row.get('source') or row.get('title') or 'evidence row'}; weight={row.get('weight')}")
    else:
        lines.append("- No writer-approved pivotal/supportive evidence is available.")
    lines.extend(["", "## What Cannot Be Concluded", ""])
    failing = readiness.get("failing_sub_conditions") or []
    if failing:
        for row in failing:
            lines.append(f"- {row.get('condition_name')}: {row.get('status')} — {row.get('message')}")
    else:
        lines.append("- Pre-writer readiness did not provide a failing-condition list.")
    if gaps:
        lines.extend(["", "## Evidence Gaps", ""])
        for gap in gaps[:12]:
            lines.append(f"- {gap.get('gap_id') or 'gap'}: {gap.get('gap') or gap.get('gap_description') or gap.get('recommendation') or 'gap recorded'}")
    lines.extend(
        [
            "",
            "## Writer Status",
            "",
            "Writer was not invoked. This is a controlled compromise packet, not a CER draft.",
        ]
    )
    return "\n".join(lines) + "\n"


def _controlled_compromise_recommendation(state: dict[str, Any], terminal_status: str, blocked_conditions: list[dict[str, Any]]) -> str:
    names = {str(row.get("condition_name") or "") for row in blocked_conditions}
    primary = "supplement_evidence"
    if terminal_status == "DOMAIN_FATAL":
        primary = "abandon_until_identity_corrected"
    elif "alignment" in names:
        primary = "accept_with_limitation_only_after_source_alignment"
    elif not blocked_conditions:
        primary = "supplement_evidence"
    lines = [
        "# Recommendation",
        "",
        f"Primary recommendation: `{primary}`.",
        "",
        "## Options",
        "",
        "- `supplement_evidence`: provide additional literature/full text/manufacturer clinical data and restart authoring.",
        "- `accept_with_limitation`: only possible after explicit human authorization and updated claim limitations.",
        "- `abandon`: stop this authoring run if the intended claim cannot be supported.",
        "",
        "## Rationale",
        "",
        f"Terminal status is `{terminal_status}`. The blocked pre-writer conditions prevent a traceable CER draft from being generated in this run.",
    ]
    return "\n".join(lines) + "\n"


def _controlled_compromise_human_decisions(terminal_status: str, blocked_conditions: list[dict[str, Any]]) -> dict[str, Any]:
    decisions = []
    for idx, condition in enumerate(blocked_conditions or [], start=1):
        decisions.append(
            {
                "decision_id": f"HDR-{idx:03d}",
                "condition_name": condition.get("condition_name"),
                "status": condition.get("status"),
                "question": f"How should the run proceed after `{condition.get('condition_name')}` blocked pre-writer readiness?",
                "options": ["supplement_evidence", "accept_with_limitation", "abandon"],
            }
        )
    if not decisions:
        decisions.append(
            {
                "decision_id": "HDR-001",
                "condition_name": "pre_writer_readiness",
                "status": "BLOCKED",
                "question": "Confirm whether to supplement evidence, accept with limitation, or abandon this run.",
                "options": ["supplement_evidence", "accept_with_limitation", "abandon"],
            }
        )
    return {"schema_name": "human_decision_required", "terminal_status": terminal_status, "decisions": decisions}


def build_alignment_matrix(state: dict[str, Any]) -> dict[str, Any]:
    """Build full CER-to-source alignment before writer synthesis.

    Phase 5A P5-1 is a deterministic alignment carrier, not a gate change. It
    gives the writer a row-level view of CER claims against IFU, RMF/RMR, GSPR
    and PMCF so section 4.7/5 language can be qualified before drafting.
    """

    claims = state.get("claim_ledger") or []
    if not claims:
        return {}
    rows = _alignment_matrix_rows(state, claims)
    return {"alignment_matrix": rows}


def build_cross_evidence_synthesis(state: dict[str, Any]) -> dict[str, Any]:
    """Build the writer-synthesis layer used before CER section 4 prose.

    Phase 4 Priority 1 fixes COG-003 by giving the writer a claim/endpoint-level
    synthesis object. The writer should consume this table instead of moving
    from one article summary to the next.
    """

    if state.get("cross_evidence_synthesis_table") and state.get("cross_evidence_synthesis_narratives"):
        return {}
    ledger_updates = {}
    working = dict(state)
    if not working.get("claim_evidence_matrix"):
        ledger_updates = build_claim_evidence_benefit_risk_ledgers(working)
        working = {**working, **ledger_updates}
    rows = _cross_evidence_synthesis_rows(working)
    narratives = _cross_evidence_synthesis_narrative_rows(working, rows)
    trace = [
        {
            "trace_id": "WRITER-SYNTHESIS-001",
            "stage": "writer_synthesis",
            "layer": "writer_synthesis",
            "input_artifacts": "claim_evidence_matrix; evidence_registry; endpoint_extraction; sota_endpoint_derivation_table; benefit_risk_ledger",
            "output_artifacts": "cross_evidence_synthesis_table; cross_evidence_synthesis_narratives",
            "writer_rule": "CER section 4 must synthesize across evidence by claim/endpoint/benchmark before listing individual article limitations.",
            "conclusion": "Writer synthesis generated before CER section 4 drafting.",
        }
    ]
    return {
        **ledger_updates,
        "cross_evidence_synthesis_table": rows,
        "cross_evidence_synthesis_narratives": narratives,
        "writer_synthesis_trace": trace,
    }


def build_writer_device_template_profile(state: dict[str, Any]) -> dict[str, Any]:
    """Select the writer template profile without changing graph or gates.

    Phase 4A P4 fixes COG-007 by making the existing writer template adapt to
    the locked device class/domain. It only supplies conditional section blocks
    consumed by the writer; it does not alter identity arbitration, agents or
    gate criteria.

    Phase 2A: Unknown domain blocks Writer. Domain-specific templates prevent
    cross-domain contamination.
    """

    if state.get("writer_device_template_profile") and state.get("writer_device_conditional_sections"):
        return {}
    profile = _writer_device_template_profile(state)

    # Phase 2A: Unknown domain blocking
    clinical_domain = str(profile.get("clinical_domain") or "")
    block = block_if_unknown(clinical_domain)
    if block:
        profile["writer_blocked"] = True
        profile["writer_block_reason"] = block["block_reason"]
        profile["writer_block_required_action"] = block["required_action"]
        profile["conditional_sections"] = []
        return {
            "writer_device_template_profile": profile,
            "writer_device_conditional_sections": [],
            "writer_blocked_by_unknown_domain": True,
        }

    return {
        "writer_device_template_profile": profile,
        "writer_device_conditional_sections": profile.get("conditional_sections", []),
    }


def _writer_device_template_profile(state: dict[str, Any]) -> dict[str, Any]:
    device_profile = state.get("device_profile") or {}
    identity_lock = state.get("device_identity_lock") or {}
    clinical_domain = str(identity_lock.get("locked_domain") or device_profile.get("clinical_domain") or device_profile.get("device_domain") or _clinical_domain(state) or "generic_unknown")
    confidence = str(
        identity_lock.get("classification_confidence")
        or identity_lock.get("confidence")
        or device_profile.get("classification_confidence")
        or device_profile.get("device_type_confidence")
        or ""
    ).lower()
    device_class = _device_class(state)
    basis = " ".join(
        str(value or "")
        for value in (
            clinical_domain,
            device_class,
            device_profile.get("device_name"),
            device_profile.get("device_type"),
            device_profile.get("device_family"),
            device_profile.get("intended_purpose"),
            device_profile.get("mode_of_action"),
            device_profile.get("anatomical_site"),
            device_profile.get("working_principle"),
            device_profile.get("composition"),
        )
    ).lower()

    signal_profile = _writer_template_signal_profile(
        state=state,
        basis=basis,
        clinical_domain=clinical_domain,
        device_class=device_class,
        confidence=confidence,
    )
    sections, section_provenance = _compose_modular_writer_sections(signal_profile)
    if not sections:
        if signal_profile["allow_generic_fallback"]:
            sections = _with_section_provenance(
                _generic_device_template_sections(),
                module_id="generic_fallback",
                module_type="fallback",
                selected_by="identity_confidence",
                trigger_signals="identity confidence below high and no high-confidence device family/function signals",
                signal_profile=signal_profile,
            )
            section_provenance.append(_section_provenance_row("generic_fallback", "fallback", "identity_confidence", "low confidence and no module signal"))
        else:
            sections = _with_section_provenance(
                _unmapped_device_class_template_sections(),
                module_id="high_confidence_unmapped",
                module_type="fallback",
                selected_by="modular_composition",
                trigger_signals="high-confidence identity but no validated module matched",
                signal_profile=signal_profile,
            )
            section_provenance.append(_section_provenance_row("high_confidence_unmapped", "fallback", "modular_composition", "high-confidence identity with no module match"))

    template_id = _modular_template_id(signal_profile, sections)
    selection_rule = (
        "Modular writer section composition based on device_family, functional_profile and feature_modules; "
        "device_class only modifies expected rigor/depth. Generic fallback is only allowed when identity confidence and "
        "device-family/function signals are low."
    )
    return {
        "template_id": template_id,
        "device_class": device_class,
        "clinical_domain": clinical_domain,
        "identity_confidence": confidence or "not_reported",
        "device_family": signal_profile["device_family"],
        "device_family_confidence": signal_profile["device_family_confidence"],
        "functional_profile": signal_profile["functional_profile"],
        "functional_profile_confidence": signal_profile["functional_profile_confidence"],
        "feature_modules": signal_profile["feature_modules"],
        "rigor_modifier": signal_profile["rigor_modifier"],
        "composition_strategy": "modular_section_composition",
        "selection_rule": selection_rule,
        "section_selection_provenance": section_provenance,
        "source_layer": "writer_template_selector",
        "graph_change": "none",
        "agent_change": "none",
        "gate_change": "none",
        "conditional_sections": _dedupe_conditional_sections(sections),
    }


def _writer_template_signal_profile(
    *,
    state: dict[str, Any],
    basis: str,
    clinical_domain: str,
    device_class: str,
    confidence: str,
) -> dict[str, Any]:
    device_profile = state.get("device_profile") or {}
    is_high_confidence = not confidence or any(token in confidence for token in ("high", "locked", "pass", "confirmed"))
    device_family, family_confidence, family_trigger = _infer_writer_device_family(clinical_domain, basis)
    functional_profile, functional_confidence, functional_trigger = _infer_writer_functional_profile(clinical_domain, basis, device_family)
    feature_modules, feature_triggers = _infer_writer_feature_modules(clinical_domain, basis, device_family, functional_profile)
    has_high_family_or_function_signal = device_family != "unknown" or functional_profile != "unknown"
    return {
        "clinical_domain": clinical_domain,
        "device_class": device_class,
        "identity_confidence": confidence or "not_reported",
        "identity_high_confidence": is_high_confidence,
        "device_family": device_family,
        "device_family_confidence": family_confidence,
        "functional_profile": functional_profile,
        "functional_profile_confidence": functional_confidence,
        "feature_modules": feature_modules,
        "rigor_modifier": _writer_rigor_modifier(device_class),
        "allow_generic_fallback": not is_high_confidence and not has_high_family_or_function_signal,
        "trigger_signals": {
            "device_family": family_trigger,
            "functional_profile": functional_trigger,
            "feature_modules": feature_triggers,
            "basis_excerpt": basis[:600],
            "source_ids": ", ".join(_unique_nonempty(device_profile.get("supporting_source_ids") or []))
            if isinstance(device_profile.get("supporting_source_ids"), list)
            else str(device_profile.get("supporting_source_ids") or ""),
        },
    }


def _infer_writer_device_family(clinical_domain: str, basis: str) -> tuple[str, str, str]:
    if clinical_domain in {"ai_diagnostic_software", "software_medical_device"} or _basis_has(
        basis, ("software as a medical device", "samd", "standalone software", "ai diagnostic software", "algorithm", "machine learning")
    ):
        return "SaMD", "high", "software/SaMD domain or algorithm evidence"
    if clinical_domain == "surgical_ligating_clip" or _basis_has(
        basis, ("ligating clip", "hemostatic clip", "vascular clip", "implantable clip", "titanium clip", "surgical implant")
    ):
        return "implantable", "high", "ligating clip / implantable surgical clip evidence"
    if clinical_domain == "cardiovascular_rf_ablation_catheter" or _basis_has(
        basis, ("ablation catheter", "rf ablation", "radiofrequency ablation", "therapeutic catheter", "catheter-based ablation")
    ):
        return "disposable", "high", "therapeutic catheter / ablation catheter evidence"
    if _basis_has(basis, ("feeding pump", "enteral pump", "infusion pump", "pump", "generator", "powered equipment", "electrical equipment", "electronic equipment")):
        return "powered_equipment", "high", "powered equipment / pump / generator evidence"
    if _basis_has(basis, ("implantable", "implanted", "implant ", "stent", "prosthesis")):
        return "implantable", "medium", "implantable-device terminology"
    if _basis_has(basis, ("single-use", "disposable", "sterile disposable", "needle", "catheter", "sheath", "endoscope", "cartridge", "tubing set")):
        return "disposable", "medium", "single-use disposable physical device terminology"
    return "unknown", "low", "no reliable device-family signal"


def _infer_writer_functional_profile(clinical_domain: str, basis: str, device_family: str) -> tuple[str, str, str]:
    if clinical_domain in {"ai_diagnostic_software", "software_medical_device"} or _basis_has(
        basis, ("diagnostic output", "diagnostic decision support", "diagnosis", "detect", "classification", "image analysis")
    ):
        return "diagnostic", "high" if device_family == "SaMD" else "medium", "diagnostic workflow / output terminology"
    if _basis_has(
        basis,
        (
            "ablation",
            "treatment",
            "therapy",
            "therapeutic",
            "ligation",
            "ligating",
            "occlusion",
            "feeding",
            "enteral nutrition",
            "infusion",
            "drug injection",
            "nerve block",
        ),
    ):
        return "therapeutic", "high", "treatment / therapy / delivery / ligation evidence"
    if _basis_has(basis, ("monitoring", "monitor ", "sensor", "alarm monitoring", "surveillance")):
        return "monitoring", "medium", "monitoring or sensor terminology"
    if _basis_has(basis, ("life-support", "life support", "ventilator", "critical care pump")):
        return "life-supporting", "medium", "life-supporting terminology"
    return "unknown", "low", "no reliable functional-profile signal"


def _infer_writer_feature_modules(clinical_domain: str, basis: str, device_family: str, functional_profile: str) -> tuple[list[str], dict[str, str]]:
    module_rules = {
        "powered_device": ("pump", "generator", "powered", "electrical", "electronic", "battery", "motor", "emc", "iec 60601"),
        "fluid_delivery": ("feeding", "enteral", "nutrition", "infusion", "flow rate", "fluid", "drug delivery", "injection", "tubing"),
        "alarmed_system": ("alarm", "alert", "audible", "visual signal", "occlusion alarm", "empty alarm"),
        "software_component": ("software", "algorithm", "control logic", "cybersecurity", "iec 62304", "firmware"),
        "invasive": ("catheter", "needle", "puncture", "implant", "surgical", "clip", "sheath", "endoscope", "vessel", "tissue contact"),
        "sterile": ("sterile", "sterilization", "sterilisation", "single-use", "disposable", "eo residual", "aseptic"),
        "implantable": ("implantable", "implanted", "implant ", "ligating clip", "titanium clip", "migration", "detachment"),
        "energy_delivery": ("ablation", "radiofrequency", "rf energy", "pulsed field", "electroporation", "microwave", "electrosurgical", "energy delivery"),
        "reusable_or_reprocessable": ("reusable", "reprocessing", "reprocess", "cleaning", "disinfection", "use-life", "cycle validation"),
    }
    modules: list[str] = []
    triggers: dict[str, str] = {}
    for module, tokens in module_rules.items():
        if _basis_has(basis, tokens):
            modules.append(module)
            triggers[module] = ", ".join(token for token in tokens if token in basis)[:180] or "semantic module token"
    if clinical_domain == "cardiovascular_rf_ablation_catheter":
        for module, trigger in {
            "energy_delivery": "locked RF ablation domain",
            "invasive": "catheter-based therapeutic procedure",
            "sterile": "catheter/tissue contact procedural device",
            "powered_device": "generator-catheter system compatibility",
        }.items():
            if module not in modules:
                modules.append(module)
                triggers[module] = trigger
    if clinical_domain == "surgical_ligating_clip":
        for module, trigger in {
            "implantable": "locked ligating clip domain",
            "invasive": "surgical implantation / vessel ligation",
            "sterile": "sterile implantable surgical device",
        }.items():
            if module not in modules:
                modules.append(module)
                triggers[module] = trigger
    if device_family == "SaMD" and "software_component" not in modules:
        modules.append("software_component")
        triggers["software_component"] = "SaMD device family"
    if device_family == "powered_equipment" and "powered_device" not in modules:
        modules.append("powered_device")
        triggers["powered_device"] = "powered equipment device family"
    if device_family == "powered_equipment" and "pump" in basis and "alarmed_system" not in modules:
        modules.append("alarmed_system")
        triggers["alarmed_system"] = "powered pump family; alarm functions must be confirmed or treated as a source gap"
    if functional_profile == "therapeutic" and device_family == "powered_equipment" and "fluid_delivery" in basis and "fluid_delivery" not in modules:
        modules.append("fluid_delivery")
        triggers["fluid_delivery"] = "therapeutic powered delivery context"
    if device_family == "powered_equipment":
        if "implantable" in modules and not _basis_has(basis, ("implantable pump", "implanted pump")):
            modules.remove("implantable")
            triggers.pop("implantable", None)
        if "invasive" in modules and not _basis_has(basis, ("catheter", "needle", "puncture", "endoscope", "tissue contact", "invasive access")):
            modules.remove("invasive")
            triggers.pop("invasive", None)
    return modules, triggers


def _basis_has(basis: str, tokens: tuple[str, ...]) -> bool:
    return any(token in basis for token in tokens)


def _writer_rigor_modifier(device_class: str) -> str:
    lowered = str(device_class or "").lower()
    if "iii" in lowered or "class 3" in lowered:
        return "highest_depth_required_for_class_iii"
    if "iib" in lowered or "class 2b" in lowered:
        return "high_depth_required_for_class_iib"
    if "iia" in lowered or "class 2a" in lowered:
        return "moderate_depth_required_for_class_iia"
    if re.search(r"\bclass\s*i\b|\bi\b", lowered):
        return "baseline_depth_for_class_i"
    return "depth_modifier_unknown_use_risk_based_depth"


def _compose_modular_writer_sections(signal_profile: dict[str, Any]) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    sections: list[dict[str, Any]] = []
    provenance: list[dict[str, Any]] = []

    def add_module(module_id: str, module_type: str, selected_by: str, trigger: str, module_sections: list[dict[str, Any]]) -> None:
        sections.extend(
            _with_section_provenance(
                module_sections,
                module_id=module_id,
                module_type=module_type,
                selected_by=selected_by,
                trigger_signals=trigger,
                signal_profile=signal_profile,
            )
        )
        provenance.append(_section_provenance_row(module_id, module_type, selected_by, trigger))

    family = signal_profile["device_family"]
    function = signal_profile["functional_profile"]
    features = list(signal_profile.get("feature_modules") or [])
    triggers = signal_profile.get("trigger_signals") or {}
    feature_triggers = triggers.get("feature_modules") or {}
    clinical_domain = signal_profile.get("clinical_domain")

    if family == "SaMD":
        add_module("family_samd", "device_family", "device_family=SaMD", str(triggers.get("device_family") or ""), _software_medical_device_template_sections())
    elif clinical_domain == "cardiovascular_rf_ablation_catheter":
        add_module(
            "domain_therapeutic_rf_catheter",
            "domain_family_bridge",
            "locked clinical_domain + device_family",
            "cardiovascular RF ablation catheter domain",
            _therapeutic_catheter_template_sections(),
        )
    elif clinical_domain == "surgical_ligating_clip":
        add_module(
            "domain_surgical_ligating_clip",
            "domain_family_bridge",
            "locked clinical_domain + device_family",
            "surgical ligating clip domain",
            _surgical_implant_ligating_clip_template_sections(),
        )
    # ── Phase 2A: Domain-specific template dispatch ──
    elif clinical_domain in {"cardiac_tissue_stabilizer"}:
        domain_sections = get_domain_template_sections(clinical_domain) or []
        if domain_sections:
            add_module(
                "domain_cardiac_stabilizer",
                "domain_specific",
                "locked clinical_domain=cardiac_tissue_stabilizer",
                "cardiac tissue stabilizer domain template",
                domain_sections,
            )
    elif clinical_domain in {"orthopedic_rf_plasma_electrode", "plasma_surgical_electrode"}:
        domain_sections = get_domain_template_sections(clinical_domain) or []
        if domain_sections:
            add_module(
                "domain_plasma_electrode",
                "domain_specific",
                "locked clinical_domain=plasma_surgical_electrode",
                "orthopedic RF plasma electrode domain template",
                domain_sections,
            )
    elif clinical_domain in {"medical_imaging_software", "ai_diagnostic_software", "diagnostic_software"}:
        domain_sections = get_domain_template_sections(clinical_domain) or []
        if domain_sections:
            add_module(
                "domain_imaging_software",
                "domain_specific",
                "locked clinical_domain=medical_imaging_software",
                "medical imaging software (SaMD) domain template",
                domain_sections,
            )
    # ── End Phase 2A domain dispatch ──
    elif family == "implantable":
        add_module("family_implantable", "device_family", "device_family=implantable", str(triggers.get("device_family") or ""), _implantable_device_template_sections())
    elif family == "powered_equipment":
        add_module(
            "family_powered_equipment",
            "device_family",
            "device_family=powered_equipment",
            str(triggers.get("device_family") or ""),
            _powered_equipment_template_sections(),
        )
    elif family == "disposable":
        add_module("family_disposable", "device_family", "device_family=disposable", str(triggers.get("device_family") or ""), _disposable_device_template_sections())

    if function == "therapeutic":
        add_module("function_therapeutic", "functional_profile", "functional_profile=therapeutic", str(triggers.get("functional_profile") or ""), _therapeutic_function_template_sections())
    elif function == "diagnostic":
        add_module("function_diagnostic", "functional_profile", "functional_profile=diagnostic", str(triggers.get("functional_profile") or ""), _diagnostic_function_template_sections())
    elif function == "monitoring":
        add_module("function_monitoring", "functional_profile", "functional_profile=monitoring", str(triggers.get("functional_profile") or ""), _monitoring_function_template_sections())
    elif function == "life-supporting":
        add_module("function_life_supporting", "functional_profile", "functional_profile=life-supporting", str(triggers.get("functional_profile") or ""), _life_supporting_function_template_sections())

    feature_section_builders = {
        "powered_device": _powered_device_feature_sections,
        "fluid_delivery": _fluid_delivery_feature_sections,
        "alarmed_system": _alarmed_system_feature_sections,
        "software_component": _software_component_feature_sections,
        "invasive": _invasive_feature_sections,
        "sterile": _sterile_feature_sections,
        "implantable": _implantable_feature_sections,
        "energy_delivery": _energy_delivery_feature_sections,
        "reusable_or_reprocessable": _reusable_or_reprocessable_feature_sections,
    }
    can_use_feature_only_modules = not (family == "unknown" and function == "unknown" and clinical_domain in {"generic_unknown", "unknown", ""})
    for feature in features:
        builder = feature_section_builders.get(feature)
        if builder and can_use_feature_only_modules:
            add_module(f"feature_{feature}", "feature_module", f"feature_module={feature}", str(feature_triggers.get(feature) or feature), builder())

    return _dedupe_conditional_sections(sections), provenance


def _with_section_provenance(
    sections: list[dict[str, Any]],
    *,
    module_id: str,
    module_type: str,
    selected_by: str,
    trigger_signals: str,
    signal_profile: dict[str, Any],
) -> list[dict[str, Any]]:
    rows = []
    for section in sections:
        row = dict(section)
        row["module_id"] = module_id
        row["module_type"] = module_type
        row["selected_by"] = selected_by
        row["trigger_signals"] = trigger_signals
        row["device_family"] = signal_profile.get("device_family")
        row["functional_profile"] = signal_profile.get("functional_profile")
        row["feature_modules"] = ", ".join(signal_profile.get("feature_modules") or [])
        row["rigor_modifier"] = signal_profile.get("rigor_modifier")
        rows.append(row)
    return rows


def _section_provenance_row(module_id: str, module_type: str, selected_by: str, trigger_signals: str) -> dict[str, str]:
    return {
        "module_id": module_id,
        "module_type": module_type,
        "selected_by": selected_by,
        "trigger_signals": trigger_signals,
    }


def _dedupe_conditional_sections(sections: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[str] = set()
    deduped: list[dict[str, Any]] = []
    for section in sections:
        key = str(section.get("row_id") or section.get("title") or "")
        if not key or key in seen:
            continue
        seen.add(key)
        deduped.append(section)
    return deduped


def _apply_domain_relevance_classification(records: list[dict[str, Any]], state: dict[str, Any]) -> list[dict[str, Any]]:
    """Classify retrieval relevance so broad SOTA records cannot over-support claims."""
    domain = _sota_context_domain(state)
    if domain != "plasma_surgical_equipment":
        return records
    direct_terms = ("coblation", "radiofrequency plasma", "plasma", "otolaryngology", "tonsil", "adenoid", "turbinate", "ent ")
    exclusion_terms = (
        "cardiopulmonary bypass",
        "liver transplant",
        "trauma",
        "coagulation assay",
        "viscoelastic",
        "atrial fibrillation",
        "pulsed field",
        "plasma exchange",
        "urology",
        "vaporization",
    )
    enriched = []
    for record in records:
        text = " ".join(
            str(record.get(key) or "")
            for key in ("title", "abstract", "journal", "mesh_terms", "keywords")
        ).lower()
        excluded = any(term in text for term in exclusion_terms)
        direct_score = sum(1 for term in direct_terms if term in text)
        row = dict(record)
        if excluded and direct_score == 0:
            row["domain_relevance_class"] = "excluded"
            row["writer_consumption_decision"] = "background_only_excluded_from_claim_support"
            row["support_status"] = "BACKGROUND_ONLY"
        elif direct_score >= 2:
            row["domain_relevance_class"] = "direct_supportive_candidate"
        elif direct_score == 1:
            row["domain_relevance_class"] = "indirect_comparator_or_background"
            row.setdefault("support_status", "BACKGROUND_ONLY")
        else:
            row["domain_relevance_class"] = "background_only"
            row.setdefault("support_status", "BACKGROUND_ONLY")
        enriched.append(row)
    return enriched


def _modular_template_id(signal_profile: dict[str, Any], sections: list[dict[str, Any]]) -> str:
    if signal_profile.get("allow_generic_fallback"):
        return "generic_medical_device"
    family = str(signal_profile.get("device_family") or "unknown").lower().replace("-", "_")
    function = str(signal_profile.get("functional_profile") or "unknown").lower().replace("-", "_")
    domain = str(signal_profile.get("clinical_domain") or "")
    if domain == "cardiovascular_rf_ablation_catheter":
        return "modular_therapeutic_catheter_rf_ablation"
    if domain == "surgical_ligating_clip":
        return "modular_surgical_implant_ligating_clip"
    if family == "samd":
        return "modular_software_medical_device"
    if family == "powered_equipment" and function == "therapeutic":
        return "modular_powered_non_implantable_therapeutic_equipment"
    if not sections or any(str(section.get("module_id") or "") == "high_confidence_unmapped" for section in sections):
        return "device_class_unmapped_requires_template_review"
    return f"modular_{family}_{function}_template"


def _conditional_section(row_id: str, title: str, rationale: str, required_inputs: str, writer_instruction: str, section_target: str = "4.3.2") -> dict[str, Any]:
    return {
        "row_id": row_id,
        "section_target": section_target,
        "title": title,
        "rationale": rationale,
        "required_inputs": required_inputs,
        "writer_instruction": writer_instruction,
        "conclusion_rule": "State support level conservatively. If the required source is missing, mark the item as a source gap and link it to PMCF/source upgrade rather than fabricating coverage.",
    }


