def _ocr_pdf_page_with_tesseract(path: Path, page_number: int, *, timeout_seconds: float | None = None) -> dict[str, Any]:
    import tempfile

    from pdf2image import convert_from_path

    timeout_value = max(1, int(timeout_seconds or PDF_OCR_PAGE_TIMEOUT_SECONDS))
    try:
        images = convert_from_path(str(path), dpi=300, first_page=page_number, last_page=page_number, fmt="png", timeout=timeout_value)
    except Exception as exc:
        return {"used": True, "text": "", "chars": 0, "quality_flag": "OCR_LOW_QUALITY", "error": f"pdf2image:{type(exc).__name__}:{exc}"}
    if not images:
        return {"used": True, "text": "", "chars": 0, "quality_flag": "OCR_LOW_QUALITY", "error": "pdf2image:no_image_returned"}
    with tempfile.TemporaryDirectory() as tmpdir:
        image_path = Path(tmpdir) / f"page_{page_number}.png"
        images[0].save(image_path)
        try:
            result = subprocess.run(
                ["tesseract", str(image_path), "stdout", "--dpi", "300"],
                check=False,
                capture_output=True,
                text=True,
                timeout=timeout_value,
            )
        except Exception as exc:
            return {"used": True, "text": "", "chars": 0, "quality_flag": "OCR_LOW_QUALITY", "error": f"tesseract:{type(exc).__name__}:{exc}"}
    text = (result.stdout or "").strip()
    chars = len(text)
    quality_flag = "OCR_LOW_QUALITY" if chars < 100 else ""
    error = ""
    if result.returncode != 0:
        error = f"tesseract:returncode_{result.returncode}:{(result.stderr or '').strip()[:300]}"
        quality_flag = "OCR_LOW_QUALITY"
    return {"used": True, "text": text, "chars": chars, "quality_flag": quality_flag, "error": error}


def _pymupdf_text_blocks(page: Any) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    text_dict = page.get_text("dict", sort=True)
    raw_blocks: list[dict[str, Any]] = []
    for block in text_dict.get("blocks", []):
        if block.get("type") != 0:
            continue
        lines = []
        max_size = 0.0
        font_names: list[str] = []
        for line in block.get("lines", []):
            spans = line.get("spans", [])
            text = " ".join(str(span.get("text", "")).strip() for span in spans if str(span.get("text", "")).strip())
            if text:
                lines.append(text)
            for span in spans:
                try:
                    max_size = max(max_size, float(span.get("size") or 0))
                except Exception:
                    pass
                if span.get("font"):
                    font_names.append(str(span.get("font")))
        text = " ".join(lines).strip()
        if not text:
            continue
        raw_blocks.append(
            {
                "text": text,
                "font_size": round(max_size, 2),
                "font": ", ".join(sorted(set(font_names)))[:160],
                "bbox": _round_bbox(block.get("bbox")),
            }
        )
    headings: list[dict[str, Any]] = []
    paragraphs: list[dict[str, Any]] = []
    for idx, block in enumerate(raw_blocks, start=1):
        text = str(block.get("text") or "")
        font = str(block.get("font") or "").lower()
        is_heading = len(text) <= 180 and (
            float(block.get("font_size") or 0) >= 13
            or "bold" in font
            or (text.upper() == text and any(char.isalpha() for char in text) and len(text) <= 120)
        )
        row = {"block_id": f"B-{idx:03d}", **block}
        if is_heading:
            headings.append(row)
        else:
            paragraphs.append(row)
    return headings, paragraphs


def _round_bbox(value: Any) -> list[float]:
    if not isinstance(value, (list, tuple)):
        return []
    rounded = []
    for item in value[:4]:
        try:
            rounded.append(round(float(item), 2))
        except Exception:
            rounded.append(0.0)
    return rounded


def _extract_pdf_tables_with_camelot(path: Path, source_id: str, *, pages: list[int] | None = None, deadline: float | None = None) -> tuple[list[dict[str, Any]], list[str]]:
    tables: list[dict[str, Any]] = []
    errors: list[str] = []
    for page_number in pages or []:
        if deadline is not None and _deadline_exceeded(deadline):
            errors.append(f"camelot_timeout:file_deadline_before_page_{page_number}")
            break
        page_timeout = _remaining_timeout(deadline, PDF_CAMELOT_PAGE_TIMEOUT_SECONDS) if deadline is not None else PDF_CAMELOT_PAGE_TIMEOUT_SECONDS
        lattice_tables, lattice_error = _run_camelot_page_with_timeout(path, source_id, page_number, "lattice", page_timeout)
        if lattice_error:
            errors.append(lattice_error)
        if lattice_tables:
            tables.extend(lattice_tables)
            continue
    for idx, table in enumerate(tables, start=1):
        table["table_id"] = f"{source_id}-T{idx:03d}"
        table["source_table"] = f"{source_id}-T{idx:03d}"
        table["source_anchor"] = f"{source_id}:p{int(table.get('page_number') or 1)}:T{idx:03d}"
    return tables, errors


def _deep_reparse_requests_for_document(item: dict[str, Any], path: Path, source_id: str, pages: list[dict[str, Any]], parser_depth: str) -> list[dict[str, Any]]:
    if parser_depth == "deep":
        return []
    reason = ""
    if str(item.get("evidence_role") or "").lower() == "pivotal":
        reason = "evidence_role=pivotal"
    elif str(item.get("quality_tier") or item.get("evidence_quality_tier") or "").lower() in {"good", "excellent"}:
        reason = "quality_tier>=good"
    elif item.get("high_impact_claim"):
        reason = "high_impact_claim"
    elif item.get("unresolved_br_gap"):
        reason = "unresolved_br_gap"
    elif item.get("unresolved_pmcf_gap"):
        reason = "unresolved_pmcf_gap"
    elif item.get("critical_conflict"):
        reason = "critical_conflict"
    elif item.get("conclusion_strength_boundary"):
        reason = "conclusion_strength_boundary"
    if not reason:
        return []
    max_per_file = max(1, int(item.get("max_deep_reparse_per_file") or 1))
    attempts = int(item.get("deep_reparse_attempt_count") or 0)
    requests = []
    for page in pages:
        if len(requests) >= max_per_file:
            break
        page_number = int(page.get("page_number") or 0)
        if page_number <= 0:
            continue
        cache_key = (*_pdf_failure_cache_key(path, page_number, "deep_reparse", reason)[:2], reason)
        if cache_key in PDF_DEEP_REPARSE_REQUEST_CACHE:
            continue
        PDF_DEEP_REPARSE_REQUEST_CACHE.add(cache_key)
        page["deep_reparse_requested"] = True
        page["deep_reparse_reason"] = reason
        page["deep_reparse_attempt_count"] = attempts
        if page.get("page_lineage"):
            page["page_lineage"]["deep_reparse_requested"] = True
            page["page_lineage"]["deep_reparse_reason"] = reason
            page["page_lineage"]["deep_reparse_attempt_count"] = attempts
        requests.append(
            {
                "request_id": f"DRR-{source_id}-{page_number:03d}",
                "source_id": source_id,
                "source_file": str(path),
                "page_number": page_number,
                "deep_reparse_requested": True,
                "deep_reparse_reason": reason,
                "deep_reparse_attempt_count": attempts,
                "parser_depth_requested": "deep",
                "status": "queued",
                "bounded_scope": "page",
            }
        )
    return requests


def _extraction_gap_row(item: dict[str, Any], source_id: str, path: Path, page_number: int, reason: str, detail: str) -> dict[str, Any]:
    return {
        "gap_id": f"XG-{source_id}-{page_number:03d}",
        "source_id": source_id,
        "source_file": str(path),
        "page_number": page_number,
        "gap_type": "parser_fallback",
        "trigger_reason": reason,
        "trigger_detail": detail,
        "parser_depth": "deep",
        "impact": "human_review_required" if _high_impact_extraction_item(item) else "informational",
        "status": "open",
    }


def _extraction_gap_review_row(gap: dict[str, Any]) -> dict[str, Any]:
    return {
        "review_id": f"HRQ-{gap.get('gap_id')}",
        "fact_id": "",
        "evidence_id": "",
        "trigger_reason": "extraction_gap",
        "trigger_detail": gap.get("trigger_detail", ""),
        "status": "pending",
        "reviewer_notes": None,
        "reviewed_at": None,
        "source_id": gap.get("source_id"),
        "source_page": gap.get("page_number"),
    }


def _run_camelot_page_with_timeout(path: Path, source_id: str, page_number: int, flavor: str, timeout_seconds: float) -> tuple[list[dict[str, Any]], str]:
    if flavor != "lattice":
        return [], f"camelot_{flavor}:disabled_pdf1_lattice_only:page_{page_number}"
    cache_key = _pdf_failure_cache_key(path, page_number, "camelot", flavor)
    if cache_key in PDF_ENGINE_FAILURE_CACHE:
        return [], f"cached_failure:{PDF_ENGINE_FAILURE_CACHE[cache_key]}"
    timeout_value = max(1.0, float(timeout_seconds))
    script = r"""
import json
import sys

path, source_id, page_number, flavor = sys.argv[1], sys.argv[2], int(sys.argv[3]), sys.argv[4]
try:
    import camelot

    raw_tables = list(camelot.read_pdf(path, pages=str(page_number), flavor=flavor))
    records = []
    for idx, table in enumerate(raw_tables, start=1):
        df = getattr(table, "df", None)
        if df is None:
            continue
        rows = [[str(cell).strip() for cell in row] for row in df.fillna("").values.tolist()]
        if not rows or not any(any(cell for cell in row) for row in rows):
            continue
        parsing_report = getattr(table, "parsing_report", {}) or {}
        records.append(
            {
                "table_id": f"{source_id}-T{idx:03d}",
                "page_number": page_number,
                "source_page": page_number,
                "source_table": f"{source_id}-T{idx:03d}",
                "source_anchor": f"{source_id}:p{page_number}:T{idx:03d}",
                "extraction_method": f"camelot_{flavor}",
                "row_count": len(rows),
                "column_count": max((len(row) for row in rows), default=0),
                "accuracy": parsing_report.get("accuracy"),
                "whitespace": parsing_report.get("whitespace"),
                "cells": rows,
            }
        )
    print(json.dumps({"tables": records, "error": ""}, ensure_ascii=False))
except Exception as exc:
    print(json.dumps({"tables": [], "error": f"camelot_{flavor}:{type(exc).__name__}:page_{page_number}:{exc}"}, ensure_ascii=False))
"""
    try:
        result = subprocess.run(
            [sys.executable, "-c", script, str(path), source_id, str(page_number), flavor],
            check=False,
            capture_output=True,
            text=True,
            timeout=timeout_value,
        )
    except subprocess.TimeoutExpired:
        error = f"camelot_timeout:{flavor}:page_{page_number}:>{round(timeout_value, 2)}s"
        PDF_ENGINE_FAILURE_CACHE[cache_key] = error
        return [], error
    if result.returncode != 0:
        stderr = (result.stderr or "").strip()[:500]
        error = f"camelot_{flavor}:returncode_{result.returncode}:page_{page_number}:{stderr}"
        PDF_ENGINE_FAILURE_CACHE[cache_key] = error
        return [], error
    try:
        payload = json.loads((result.stdout or "").strip().splitlines()[-1])
    except Exception as exc:
        error = f"camelot_{flavor}:invalid_json:page_{page_number}:{type(exc).__name__}:{(result.stdout or result.stderr or '')[:300]}"
        PDF_ENGINE_FAILURE_CACHE[cache_key] = error
        return [], error
    tables = payload.get("tables") or []
    error = str(payload.get("error") or "")
    if error:
        PDF_ENGINE_FAILURE_CACHE[cache_key] = error
    return tables, error


def _pdf_failure_cache_key(path: Path, page_number: int, engine: str, mode: str) -> tuple[str, int, str, str]:
    try:
        path_key = f"{path.resolve()}:{path.stat().st_mtime_ns}:{path.stat().st_size}"
    except Exception:
        path_key = str(path)
    return (path_key, int(page_number), engine, mode)


def _camelot_table_records(raw_tables: list[Any], source_id: str, method: str) -> list[dict[str, Any]]:
    records = []
    for idx, table in enumerate(raw_tables, start=1):
        df = getattr(table, "df", None)
        if df is None:
            continue
        rows = [[str(cell).strip() for cell in row] for row in df.fillna("").values.tolist()]
        if not rows or not any(any(cell for cell in row) for row in rows):
            continue
        page_number = int(str(getattr(table, "page", "1") or "1").split(",")[0])
        parsing_report = getattr(table, "parsing_report", {}) or {}
        records.append(
            {
                "table_id": f"{source_id}-T{idx:03d}",
                "page_number": page_number,
                "source_page": page_number,
                "source_table": f"{source_id}-T{idx:03d}",
                "source_anchor": f"{source_id}:p{page_number}:T{idx:03d}",
                "extraction_method": method,
                "row_count": len(rows),
                "column_count": max((len(row) for row in rows), default=0),
                "accuracy": parsing_report.get("accuracy"),
                "whitespace": parsing_report.get("whitespace"),
                "cells": rows,
            }
        )
    return records


def _parse_docx_structured_content(item: dict[str, Any], path: Path) -> dict[str, Any]:
    from docx import Document

    document = Document(path)
    headings: list[dict[str, Any]] = []
    paragraphs: list[dict[str, Any]] = []
    for idx, paragraph in enumerate(document.paragraphs, start=1):
        text = paragraph.text.strip()
        if not text:
            continue
        style_name = str(getattr(paragraph.style, "name", "") or "")
        row = {"block_id": f"P-{idx:03d}", "text": text, "style": style_name}
        if style_name.lower().startswith("heading"):
            headings.append(row)
        else:
            paragraphs.append(row)
    tables = []
    for idx, table in enumerate(document.tables, start=1):
        rows = [[cell.text.strip() for cell in row.cells] for row in table.rows]
        if not rows:
            continue
        tables.append(
            {
                "table_id": f"{item.get('source_id') or path.stem}-T{idx:03d}",
                "page_number": 1,
                "extraction_method": "python-docx",
                "row_count": len(rows),
                "column_count": max((len(row) for row in rows), default=0),
                "cells": rows,
            }
        )
    pages = [{"page_number": 1, "page_label": "docx_flow", "headings": headings, "paragraphs": paragraphs, "tables": tables}]
    return _document_structured_record(item, path, parser_stack="python-docx", pages=pages, page_count=1, errors=[])


def _document_structured_record(
    item: dict[str, Any],
    path: Path,
    *,
    parser_stack: str,
    pages: list[dict[str, Any]],
    page_count: int,
    errors: list[str],
    status: str = "parsed",
    docling_shadow: dict[str, Any] | None = None,
    parser_depth: str = "standard",
    parser_depth_reason: str = "",
    parser_depth_status: str = "selected",
    deep_reparse_requests: list[dict[str, Any]] | None = None,
    extraction_gaps: list[dict[str, Any]] | None = None,
    human_review_queue: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    source_id = str(item.get("source_id") or path.stem)
    paragraph_count = sum(len(page.get("paragraphs") or []) for page in pages)
    heading_count = sum(len(page.get("headings") or []) for page in pages)
    table_count = sum(len(page.get("tables") or []) for page in pages)
    pages_extractable = sum(1 for page in pages if int(page.get("extractable_text_chars") or 0) >= 100)
    pages_ocr = sum(1 for page in pages if page.get("ocr_used"))
    pages_skipped_image = sum(1 for page in pages if page.get("table_extraction_status") == "skipped_image_page" or page.get("extraction_status") == "skipped_image_page")
    pages_timeout = sum(1 for page in pages if page.get("extraction_status") in {"timeout", "file_timeout_skipped"} or page.get("table_extraction_status") in {"timeout", "file_timeout_skipped"})
    ocr_quality_flags = sorted({str(page.get("ocr_quality_flag")) for page in pages if page.get("ocr_quality_flag")})
    return {
        "document_id": f"DOC-{source_id}",
        "source_id": source_id,
        "filename": str(item.get("filename") or path.name),
        "path": str(path),
        "document_type": item.get("document_type") or _classify_document(path.name, str(path)),
        "parser_stack": parser_stack,
        "status": status,
        "parser_depth": parser_depth,
        "parser_depth_reason": parser_depth_reason,
        "parser_depth_status": parser_depth_status,
        "deep_reparse_requested": bool(deep_reparse_requests),
        "deep_reparse_reason": "; ".join(str(row.get("deep_reparse_reason") or "") for row in deep_reparse_requests or [] if row.get("deep_reparse_reason")),
        "deep_reparse_attempt_count": max([int(row.get("deep_reparse_attempt_count") or 0) for row in deep_reparse_requests or []] or [0]),
        "page_count": page_count,
        "paragraph_count": paragraph_count,
        "heading_count": heading_count,
        "table_count": table_count,
        "pages_extractable": pages_extractable,
        "pages_ocr": pages_ocr,
        "pages_skipped_image": pages_skipped_image,
        "pages_timeout": pages_timeout,
        "ocr_quality_flags": ocr_quality_flags,
        "parse_errors": errors,
        "docling_shadow": docling_shadow or {},
        "deep_reparse_requests": deep_reparse_requests or [],
        "extraction_gaps": extraction_gaps or [],
        "human_review_queue": human_review_queue or [],
        "pages": pages,
    }


def _document_parsing_lineage_row(
    item: dict[str, Any],
    path: Path,
    document: dict[str, Any],
    preflight: dict[str, Any],
    *,
    status: str,
) -> dict[str, Any]:
    source_id = str(item.get("source_id") or path.stem)
    tables = [table for page in document.get("pages") or [] for table in page.get("tables") or []]
    method_counts: dict[str, int] = {}
    for table in tables:
        method = str(table.get("extraction_method") or "")
        method_counts[method] = method_counts.get(method, 0) + 1
    return {
        "row_id": f"DPL-{source_id}",
        "lineage_id": f"DPL-{source_id}",
        "document_id": document.get("document_id"),
        "source_id": source_id,
        "filename": document.get("filename"),
        "path": str(path),
        "parser_stack": document.get("parser_stack"),
        "parser_used": document.get("parser_stack"),
        "status": status,
        "parser_depth": document.get("parser_depth", ""),
        "parser_depth_reason": document.get("parser_depth_reason", ""),
        "parser_depth_status": document.get("parser_depth_status", ""),
        "deep_reparse_requested": document.get("deep_reparse_requested", False),
        "deep_reparse_reason": document.get("deep_reparse_reason", ""),
        "deep_reparse_attempt_count": document.get("deep_reparse_attempt_count", 0),
        "routed_engine": ", ".join(sorted({str((page.get("page_lineage") or {}).get("routed_engine") or page.get("routed_to") or "") for page in document.get("pages") or [] if page})),
        "timeout_budget_ms": max([int((page.get("page_lineage") or {}).get("timeout_budget_ms") or page.get("timeout_budget_ms") or 0) for page in document.get("pages") or []] or [0]),
        "actual_timing_ms": sum(int((page.get("page_lineage") or {}).get("actual_timing_ms") or page.get("actual_timing_ms") or 0) for page in document.get("pages") or []),
        "page_count": document.get("page_count", 0),
        "pages_total": document.get("page_count", 0),
        "pages_parsed": len(document.get("pages") or []),
        "pages_extractable": document.get("pages_extractable", 0),
        "pages_ocr": document.get("pages_ocr", 0),
        "pages_skipped_image": document.get("pages_skipped_image", 0),
        "pages_timeout": document.get("pages_timeout", 0),
        "page_lineage": [page.get("page_lineage") for page in document.get("pages") or [] if page.get("page_lineage")],
        "paragraph_count": document.get("paragraph_count", 0),
        "heading_count": document.get("heading_count", 0),
        "table_count": document.get("table_count", 0),
        "tables_found": len(tables),
        "tables_extracted": len(tables),
        "lattice_table_count": method_counts.get("camelot_lattice", 0),
        "stream_table_count": method_counts.get("camelot_stream", 0),
        "ocr_quality_flags": ", ".join(document.get("ocr_quality_flags") or []),
        "ocr_recovered_content": bool(document.get("pages_ocr")),
        "dependency_preflight_status": preflight.get("status", ""),
        "dependency_checks": preflight.get("checks", {}),
        "error": "; ".join(document.get("parse_errors") or []),
    }


def _parser_stack_for_suffix(suffix: str) -> str:
    if suffix == ".pdf":
        return "PyMuPDF+Camelot(page-bounded)+OCR"
    if suffix == ".docx":
        return "python-docx"
    return "unsupported"


def _structured_document_plain_text(document: dict[str, Any]) -> str:
    chunks: list[str] = []
    for page in document.get("pages") or []:
        for heading in page.get("headings") or []:
            if heading.get("text"):
                chunks.append(str(heading.get("text")))
        for paragraph in page.get("paragraphs") or []:
            if paragraph.get("text"):
                chunks.append(str(paragraph.get("text")))
        for table in page.get("tables") or []:
            cells = table.get("cells") or []
            for row in cells:
                if isinstance(row, list):
                    text = " | ".join(str(cell) for cell in row if str(cell).strip())
                    if text:
                        chunks.append(text)
    return "\n".join(chunks)[:DOCUMENT_STRUCTURED_TEXT_CHARS]


def extract_clinical_facts(state: dict[str, Any]) -> dict[str, Any]:
    """Extract source-anchored clinical facts from parsed document content."""

    if state.get("clinical_evidence_fact_table"):
        return {}
    documents = state.get("document_structured_content") or []
    if not documents:
        return {"clinical_evidence_fact_table": [], "human_review_queue": []}
    evidence_by_source = _evidence_id_by_source_id(state)
    facts: list[dict[str, Any]] = []
    review_rows: list[dict[str, Any]] = []
    for document in documents:
        if str(document.get("parser_depth") or "") == "fast":
            continue
        source_id = str(document.get("source_id") or "")
        evidence_id = evidence_by_source.get(source_id) or str(document.get("evidence_id") or f"EVIDENCE_PENDING_{source_id or document.get('document_id') or 'DOCUMENT'}")
        for page in document.get("pages") or []:
            page_number = page.get("page_number", "")
            for paragraph in (page.get("headings") or []) + (page.get("paragraphs") or []):
                text = str(paragraph.get("text") or "")
                if not text.strip():
                    continue
                method = "OCR_recovered" if paragraph.get("extraction_method") == "tesseract_ocr" or page.get("ocr_used") else "direct_text"
                for excerpt in _clinical_fact_candidate_excerpts(text):
                    facts.append(
                        _clinical_fact_row(
                            state,
                            fact_index=len(facts) + 1,
                            evidence_id=evidence_id,
                            document=document,
                            source_page=page_number,
                            source_table="",
                            excerpt=excerpt,
                            extraction_method=method,
                            ocr_quality_flag=str(paragraph.get("ocr_quality_flag") or page.get("ocr_quality_flag") or ""),
                        )
                    )
            for table in page.get("tables") or []:
                facts.extend(
                    _clinical_fact_rows_from_table(
                        state,
                        document=document,
                        evidence_id=evidence_id,
                        page_number=page_number,
                        table=table,
                        start_index=len(facts) + 1,
                    )
                )
    facts = [fact for fact in facts if fact.get("endpoint_label") or fact.get("value_numeric") not in ("", None) or fact.get("value_type") == "qualitative"]
    for fact in facts:
        if "TRANSLATION_NEEDED" in str(fact.get("extraction_flags") or ""):
            review_rows.append(
                {
                    "review_id": f"HRQ-{len(review_rows) + 1:03d}",
                    "fact_id": fact.get("fact_id"),
                    "evidence_id": fact.get("evidence_id"),
                    "flag": "TRANSLATION_NEEDED",
                    "impact": "LIMITING",
                    "source_language": fact.get("source_language"),
                    "original_excerpt": fact.get("original_excerpt"),
                    "required_action": "Human review of original-language source excerpt before final CER wording.",
                }
            )
    return {"clinical_evidence_fact_table": facts, "human_review_queue": review_rows}


def _evidence_id_by_source_id(state: dict[str, Any]) -> dict[str, str]:
    mapping: dict[str, str] = {}
    for row in state.get("evidence_registry") or []:
        evidence_id = str(row.get("evidence_id") or "")
        if not evidence_id:
            continue
        for key in ("source_id", "source", "source_anchor"):
            value = str(row.get(key) or "")
            if value:
                mapping.setdefault(value, evidence_id)
    return mapping


def _clinical_fact_candidate_excerpts(text: str) -> list[str]:
    excerpts: list[str] = []
    normalized = re.sub(r"\s+", " ", str(text or "")).strip()
    if not normalized:
        return excerpts
    parts = [part.strip() for part in re.split(r"(?<=[.!?。；;])\s+", normalized) if part.strip()]
    for part in parts or [normalized]:
        lower = part.lower()
        has_numeric = bool(re.search(r"\d+(?:\.\d+)?\s*(?:%|mmhg|ml|events?|score)?", part, flags=re.I))
        has_endpoint = _endpoint_family_from_text(part) != "effectiveness" or any(
            token in lower for token in ("success", "effective", "performance", "endpoint", "mean", "rate", "n=", "patients", "subjects")
        )
        has_qualitative = any(token in lower for token in ("no device failure", "no malfunction", "no serious adverse", "no complications"))
        if has_numeric and has_endpoint:
            excerpts.append(part[:1000])
        elif has_qualitative:
            excerpts.append(part[:1000])
    return excerpts


def _clinical_fact_rows_from_table(
    state: dict[str, Any],
    *,
    document: dict[str, Any],
    evidence_id: str,
    page_number: Any,
    table: dict[str, Any],
    start_index: int,
) -> list[dict[str, Any]]:
    cells = table.get("cells") or []
    if len(cells) < 2 or not isinstance(cells[0], list):
        return []
    headers = [str(cell).strip().lower() for cell in cells[0]]
    rows: list[dict[str, Any]] = []
    for row in cells[1:]:
        if not isinstance(row, list) or not any(str(cell).strip() for cell in row):
            continue
        by_header = {headers[idx]: str(value).strip() for idx, value in enumerate(row) if idx < len(headers)}
        endpoint = _first_header_value(by_header, ("endpoint", "outcome", "measure", "parameter", "指标", "终点"))
        value = _first_header_value(by_header, ("result", "value", "rate", "mean", "n", "结果", "数值"))
        excerpt = " | ".join(str(cell).strip() for cell in row if str(cell).strip())
        if not endpoint and not value and not re.search(r"\d", excerpt):
            continue
        table_context = " | ".join(str(cell).strip() for cell in cells[0] if str(cell).strip())
        fact = _clinical_fact_row(
            state,
            fact_index=start_index + len(rows),
            evidence_id=evidence_id,
            document=document,
            source_page=page_number or table.get("page_number", ""),
            source_table=table.get("table_id", ""),
            excerpt=f"{table_context} | {excerpt}",
            extraction_method="table_cell",
            endpoint_override=endpoint,
            value_override=value,
            population_override=_first_header_value(by_header, ("n", "population", "sample", "subjects", "patients", "样本量")),
            follow_up_override=_first_header_value(by_header, ("follow-up", "follow up", "timepoint", "duration", "随访")),
        )
        rows.append(fact)
    return rows


def _first_header_value(row: dict[str, str], names: tuple[str, ...]) -> str:
    for name in names:
        for header, value in row.items():
            matched = header == name if len(name) <= 2 else name in header
            if matched and value:
                return value
    return ""


def _clinical_fact_row(
    state: dict[str, Any],
    *,
    fact_index: int,
    evidence_id: str,
    document: dict[str, Any],
    source_page: Any,
    source_table: Any,
    excerpt: str,
    extraction_method: str,
    ocr_quality_flag: str = "",
    endpoint_override: str = "",
    value_override: str = "",
    population_override: str = "",
    follow_up_override: str = "",
) -> dict[str, Any]:
    original_excerpt = str(excerpt or "").strip()
    source_language = "zh" if contains_cjk(original_excerpt) else "en"
    label_source = endpoint_override or _endpoint_label_from_text(original_excerpt)
    endpoint_label = _normalize_endpoint_label(label_source or original_excerpt)
    endpoint_family = _endpoint_family_from_text(f"{label_source} {original_excerpt}")
    value_text = value_override or original_excerpt
    value_numeric, value_unit = _clinical_value_from_text(value_text)
    value_type = _clinical_value_type(endpoint_family, value_numeric, value_unit, original_excerpt)
    population_n = _population_n_from_text(population_override or original_excerpt)
    follow_up = follow_up_override or _extract_follow_up_from_text(original_excerpt)
    ci_lower, ci_upper = _confidence_interval_from_text(original_excerpt)
    p_value = _p_value_from_text(original_excerpt)
    validators = _clinical_fact_validators(
        endpoint_family=endpoint_family,
        value_type=value_type,
        value_numeric=value_numeric,
        value_unit=value_unit,
        population_n=population_n,
        source_excerpt=original_excerpt,
        extraction_method=extraction_method,
    )
    confidence = _clinical_fact_confidence(extraction_method, validators, ocr_quality_flag)
    flags = []
    if source_language != "en":
        flags.append("TRANSLATION_NEEDED")
    if confidence in {"low", "OCR_uncertain"}:
        flags.append("LOW_CONFIDENCE_BACKGROUND_ONLY")
    normalizer_status = "needs_human_review" if flags else ("normalized" if value_numeric not in ("", None) or endpoint_label != label_source else "raw")
    return {
        "fact_id": f"FACT-{fact_index:03d}",
        "evidence_id": evidence_id,
        "source_id": document.get("source_id"),
        "document_id": document.get("document_id"),
        "source_anchor": document.get("source_anchor") or document.get("source_id") or document.get("document_id"),
        "candidate_claim_ids": ", ".join(_candidate_claim_ids_for_fact(state, endpoint_family, endpoint_label)),
        "endpoint_family": endpoint_family,
        "endpoint_label": endpoint_label,
        "endpoint_label_original": label_source,
        "value_type": value_type,
        "value_numeric": value_numeric,
        "value_unit": value_unit,
        "normalized_value": value_numeric,
        "normalized_unit": _normalized_unit(value_unit),
        "population_n": population_n,
        "follow_up": follow_up,
        "CI_lower": ci_lower,
        "CI_upper": ci_upper,
        "p_value": p_value,
        "comparator": _comparator_from_text(original_excerpt),
        "source_page": source_page,
        "source_table": source_table,
        "source_excerpt": original_excerpt,
        "original_excerpt": original_excerpt,
        "source_language": source_language,
        "extraction_method": extraction_method,
        "method_confidence": "OCR_uncertain" if extraction_method == "OCR_recovered" and ocr_quality_flag else CLINICAL_FACT_METHOD_CONFIDENCE.get(extraction_method, "low"),
        "numeric_sanity": validators["numeric_sanity"],
        "unit_consistency": validators["unit_consistency"],
        "denominator_check": validators["denominator_check"],
        "source_cross_check": validators["source_cross_check"],
        "extraction_confidence": confidence,
        "evidence_role_cap": "background" if confidence in {"low", "OCR_uncertain"} else "supportive_or_pivotal_by_appraisal",
        "normalizer_status": normalizer_status,
        "extraction_flags": ", ".join(flags),
    }


def _clinical_value_from_text(text: str) -> tuple[Any, str]:
    pattern = re.compile(r"(?<![A-Za-z])(-?\d+(?:\.\d+)?)\s*(%|mmHg|mL|events?|score)?", flags=re.I)
    for match in pattern.finditer(str(text or "")):
        number = match.group(1)
        unit = match.group(2) or ""
        prefix = str(text or "")[max(0, match.start() - 3) : match.start()].lower()
        if prefix.endswith("n=") or prefix.endswith("n:"):
            continue
        try:
            value: int | float = float(number)
            if value.is_integer():
                value = int(value)
        except Exception:
            value = number
        return value, unit
    return "", ""


def _population_n_from_text(text: str) -> str:
    if not text:
        return ""
    if re.fullmatch(r"\d{1,6}", str(text).strip()):
        return str(text).strip()
    match = re.search(r"(?:\bN\b|\bn\b|sample size|population|patients|subjects)\s*[=:]?\s*(\d{1,6})", text, flags=re.I)
    if match:
        return match.group(1)
    match = re.search(r"(\d{1,6})\s+(?:patients|subjects|cases)", text, flags=re.I)
    return match.group(1) if match else ""


def _confidence_interval_from_text(text: str) -> tuple[str, str]:
    match = re.search(r"(?:95%\s*)?CI[:\s]*(-?\d+(?:\.\d+)?)\s*(?:-|to|,)\s*(-?\d+(?:\.\d+)?)", text, flags=re.I)
    return (match.group(1), match.group(2)) if match else ("", "")


def _p_value_from_text(text: str) -> str:
    match = re.search(r"\bp\s*([<=>]=?)\s*(0?\.\d+|1(?:\.0+)?)", text, flags=re.I)
    return f"p{match.group(1)}{match.group(2)}" if match else ""


def _comparator_from_text(text: str) -> str:
    match = re.search(r"(?:compared with|versus|vs\.?)\s+([^.;|]{2,120})", text, flags=re.I)
    return match.group(1).strip() if match else ""


def _endpoint_label_from_text(text: str) -> str:
    patterns = [
        r"(serious adverse events?|SAE|adverse events?|complications?|infection|bleeding|perforation)",
        r"(procedural success|clinical success|access success|stone[- ]free rate|completion rate)",
        r"(mPAP|pulmonary pressure|blood pressure|pressure reduction)",
        r"(device failure|malfunction|breakage|leakage|integrity)",
        r"(quality of life|QoL|score)",
        r"(有效率|成功率|不良事件|并发症|感染|出血|故障|破损|压力)",
    ]
    for pattern in patterns:
        match = re.search(pattern, text, flags=re.I)
        if match:
            return match.group(1)
    return "clinical endpoint"


def _normalize_endpoint_label(value: str) -> str:
    text = str(value or "").strip()
    replacements = {
        "有效率": "effectiveness rate",
        "成功率": "success rate",
        "不良事件": "adverse events",
        "并发症": "complications",
        "感染": "infection",
        "出血": "bleeding",
        "故障": "device malfunction",
        "破损": "device breakage",
        "压力": "pressure",
    }
    for source, target in replacements.items():
        text = text.replace(source, target)
    return english_report_text(text, "clinical endpoint label") if contains_cjk(text) else text


def _endpoint_family_from_text(text: str) -> str:
    lower = str(text or "").lower()
    if any(token in lower for token in ("sae", "adverse", "complication", "infection", "bleeding", "perforation", "不良", "并发", "感染", "出血")):
        return "safety" if "adverse" in lower or "sae" in lower or "不良" in lower else "complication"
    if any(token in lower for token in ("success", "completion", "stone-free", "access", "成功", "完成")):
        return "procedural_success"
    if any(token in lower for token in ("mpap", "pressure", "mmhg", "hemodynamic", "压力")):
        return "hemodynamic"
    if any(token in lower for token in ("malfunction", "failure", "breakage", "leakage", "integrity", "故障", "破损")):
        return "device_integrity"
    if any(token in lower for token in ("quality of life", "qol", "score")):
        return "quality_of_life"
    return "effectiveness"


def _clinical_value_type(endpoint_family: str, value_numeric: Any, value_unit: str, text: str) -> str:
    lower = str(text or "").lower()
    unit = str(value_unit or "").lower()
    if value_numeric == "":
        return "qualitative"
    if unit == "%":
        return "rate"
    if any(token in lower for token in (" or ", "odds ratio")):
        return "OR"
    if "hazard ratio" in lower or re.search(r"\bHR\b", text):
        return "HR"
    if "risk ratio" in lower or re.search(r"\bRR\b", text):
        return "RR"
    if any(token in lower for token in ("median",)):
        return "median"
    if endpoint_family in {"safety", "complication", "device_integrity"} and unit in {"event", "events"}:
        return "count"
    if unit in {"mmhg", "ml", "score"} or "mean" in lower:
        return "mean"
    return "count" if endpoint_family in {"safety", "complication"} else "mean"


def _clinical_fact_validators(
    *,
    endpoint_family: str,
    value_type: str,
    value_numeric: Any,
    value_unit: str,
    population_n: str,
    source_excerpt: str,
    extraction_method: str,
) -> dict[str, str]:
    numeric = _numeric_or_none(value_numeric)
    unit = str(value_unit or "")
    if numeric is None:
        numeric_sanity = "high" if value_type == "qualitative" else "medium"
    elif unit == "%" and not (0 <= numeric <= 100):
        numeric_sanity = "medium"
    elif abs(numeric) > 1_000_000:
        numeric_sanity = "medium"
    else:
        numeric_sanity = "high"
    expected_units = {
        "hemodynamic": {"mmHg", ""},
        "quality_of_life": {"score", ""},
        "safety": {"%", "event", "events", ""},
        "complication": {"%", "event", "events", ""},
        "procedural_success": {"%", ""},
    }
    allowed_units = expected_units.get(endpoint_family, {"%", "mmHg", "mL", "event", "events", "score", ""})
    unit_consistency = "high" if unit in allowed_units else "medium"
    denominator_check = "high"
    n = _numeric_or_none(population_n)
    if value_type == "rate" and not population_n:
        denominator_check = "medium"
    elif value_type == "count" and n is not None and numeric is not None and numeric > n:
        denominator_check = "medium"
    source_cross_check = "high"
    if value_numeric not in ("", None) and str(value_numeric) not in str(source_excerpt):
        source_cross_check = "medium"
    if extraction_method == "LLM_inferred" and any(value != "high" for value in (numeric_sanity, unit_consistency, denominator_check, source_cross_check)):
        return {
            "numeric_sanity": "low" if numeric_sanity != "high" else numeric_sanity,
            "unit_consistency": "low" if unit_consistency != "high" else unit_consistency,
            "denominator_check": "low" if denominator_check != "high" else denominator_check,
            "source_cross_check": "low" if source_cross_check != "high" else source_cross_check,
        }
    return {
        "numeric_sanity": numeric_sanity,
        "unit_consistency": unit_consistency,
        "denominator_check": denominator_check,
        "source_cross_check": source_cross_check,
    }


def _clinical_fact_confidence(extraction_method: str, validators: dict[str, str], ocr_quality_flag: str = "") -> str:
    method_confidence = "OCR_uncertain" if extraction_method == "OCR_recovered" and ocr_quality_flag else CLINICAL_FACT_METHOD_CONFIDENCE.get(extraction_method, "low")
    values = [method_confidence, *validators.values()]
    lowest = min(values, key=lambda value: CLINICAL_FACT_CONFIDENCE_RANK.get(value, 1))
    return lowest


def _numeric_or_none(value: Any) -> float | None:
    try:
        if value in ("", None):
            return None
        return float(value)
    except Exception:
        return None


def _candidate_claim_ids_for_fact(state: dict[str, Any], endpoint_family: str, endpoint_label: str) -> list[str]:
    rows = state.get("claim_ledger") or []
    if not rows:
        return []
    preferred_tokens = {
        "safety": ("safety", "risk", "complication", "adverse"),
        "complication": ("safety", "risk", "complication", "adverse"),
        "procedural_success": ("performance", "benefit", "success", "intended"),
        "effectiveness": ("performance", "benefit", "effectiveness", "intended"),
        "hemodynamic": ("benefit", "performance", "clinical"),
        "device_integrity": ("performance", "safety", "integrity"),
        "quality_of_life": ("benefit", "quality"),
    }.get(endpoint_family, ("clinical", "performance", "benefit"))
    matches = []
    for row in rows:
        haystack = " ".join(str(row.get(key) or "") for key in ("claim_type", "statement", "required_evidence", "element")).lower()
        if any(token in haystack for token in preferred_tokens) or str(endpoint_label).lower() in haystack:
            matches.append(str(row.get("claim_id") or ""))
    return [claim_id for claim_id in matches if claim_id]


def _enrich_evidence_with_clinical_facts(evidence_rows: list[dict[str, Any]], facts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    facts_by_evidence: dict[str, list[dict[str, Any]]] = {}
    for fact in facts:
        evidence_id = str(fact.get("evidence_id") or "")
        if evidence_id:
            facts_by_evidence.setdefault(evidence_id, []).append(fact)
    enriched = []
    for row in evidence_rows:
        evidence_id = str(row.get("evidence_id") or "")
        evidence_facts = facts_by_evidence.get(evidence_id, [])
        if not evidence_facts:
            enriched.append(row)
            continue
        confidences = [str(fact.get("extraction_confidence") or "low") for fact in evidence_facts]
        high_medium = [value for value in confidences if value in {"high", "medium"}]
        enriched.append(
            {
                **row,
                "clinical_fact_ids": ", ".join(str(fact.get("fact_id")) for fact in evidence_facts if fact.get("fact_id")),
                "clinical_fact_count": len(evidence_facts),
                "clinical_fact_confidence_max": max(confidences, key=lambda value: CLINICAL_FACT_CONFIDENCE_RANK.get(value, 1)),
                "clinical_fact_role_cap": "background_only" if not high_medium else "appraisal_weight_controls",
            }
        )
    return enriched


def map_semantic_endpoints(state: dict[str, Any]) -> dict[str, Any]:
    facts = state.get("clinical_evidence_fact_table") or []
    if not facts:
        return {
            "clinical_evidence_fact_table": [],
            "semantic_endpoint_mapping_table": [],
            "endpoint_match_trace": {"embedding_model": SEMANTIC_ENDPOINT_MODEL, "mappings": []},
            "fact_to_claim_link_matrix": [],
            "human_review_queue": [],
        }
    mapping_rows: list[dict[str, Any]] = []
    trace_rows: list[dict[str, Any]] = []
    link_rows: list[dict[str, Any]] = []
    review_rows: list[dict[str, Any]] = []
    mapped_facts: list[dict[str, Any]] = []
    for idx, fact in enumerate(facts, start=1):
        mapping = _semantic_endpoint_mapping_for_fact(fact)
        claim_ids = _fact_claim_links(state, {**fact, **mapping})
        normalized_value, normalized_unit, normalizer_status = _normalize_quantitative_value(fact)
        mapped_fact = {
            **fact,
            "endpoint_family": mapping["mapped_endpoint_family"],
            "endpoint_cluster_id": mapping["endpoint_cluster_id"],
            "mapping_confidence": mapping["mapping_confidence"],
            "candidate_claim_ids": ", ".join(claim_ids),
            "normalized_value": normalized_value,
            "normalized_unit": normalized_unit,
            "normalizer_status": normalizer_status if normalizer_status != "normalized" else fact.get("normalizer_status", "normalized"),
        }
        mapped_facts.append(mapped_fact)
        mapping_row = {
            "mapping_id": f"SEM-{idx:03d}",
            "fact_id": fact.get("fact_id"),
            "evidence_id": fact.get("evidence_id"),
            "raw_endpoint_label": fact.get("endpoint_label_original") or fact.get("endpoint_label"),
            "mapped_endpoint_label": mapping["mapped_endpoint_label"],
            "endpoint_family": mapping["mapped_endpoint_family"],
            "endpoint_cluster_id": mapping["endpoint_cluster_id"],
            "mapping_confidence": mapping["mapping_confidence"],
            "similarity_score": mapping["similarity_score"],
            "dimension_match_count": mapping["dimension_match_count"],
            "match_dimensions": json.dumps(mapping["match_dimensions"], ensure_ascii=False, sort_keys=True),
            "embedding_model": SEMANTIC_ENDPOINT_MODEL,
            "threshold_source": SEMANTIC_ENDPOINT_THRESHOLD_SOURCE,
        }
        mapping_rows.append(mapping_row)
        trace_rows.append({**mapping_row, "endpoint_match_trace": mapping["endpoint_match_trace"]})
        for claim_id in claim_ids:
            link_rows.append(
                {
                    "link_id": f"FCL-{len(link_rows) + 1:03d}",
                    "fact_id": fact.get("fact_id"),
                    "claim_id": claim_id,
                    "evidence_id": fact.get("evidence_id"),
                    "endpoint_cluster_id": mapping["endpoint_cluster_id"],
                    "link_confidence": mapping["mapping_confidence"] if mapping["mapping_confidence"] in {"high", "medium"} else "low",
                    "link_basis": "semantic_endpoint_mapping_and_claim_type_alignment",
                }
            )
        if normalizer_status != "normalized":
            review_rows.append(
                {
                    "review_id": f"HRQ-NORM-{idx:03d}",
                    "fact_id": fact.get("fact_id"),
                    "evidence_id": fact.get("evidence_id"),
                    "flag": "QUANTITATIVE_NORMALIZATION_FAILED",
                    "impact": "LIMITING",
                    "source_excerpt": fact.get("source_excerpt"),
                    "required_action": "Review extracted value/unit before quantitative synthesis or conflict detection.",
                }
            )
    return {
        "clinical_evidence_fact_table": mapped_facts,
        "semantic_endpoint_mapping_table": mapping_rows,
        "endpoint_match_trace": {"embedding_model": SEMANTIC_ENDPOINT_MODEL, "threshold_source": SEMANTIC_ENDPOINT_THRESHOLD_SOURCE, "mappings": trace_rows},
        "fact_to_claim_link_matrix": link_rows,
        "human_review_queue": review_rows,
    }


def detect_evidence_conflicts(state: dict[str, Any]) -> dict[str, Any]:
    facts = [fact for fact in state.get("clinical_evidence_fact_table") or [] if fact.get("endpoint_cluster_id")]
    links_by_fact: dict[str, list[str]] = {}
    for link in state.get("fact_to_claim_link_matrix") or []:
        links_by_fact.setdefault(str(link.get("fact_id") or ""), []).append(str(link.get("claim_id") or ""))
    by_cluster: dict[str, list[dict[str, Any]]] = {}
    for fact in facts:
        by_cluster.setdefault(str(fact.get("endpoint_cluster_id")), []).append(fact)
    conflict_groups: dict[tuple[Any, ...], dict[str, Any]] = {}
    pairwise_conflict_count = 0
    for cluster_id, cluster_facts in by_cluster.items():
        if len({str(fact.get("evidence_id") or "") for fact in cluster_facts}) < 2:
            continue
        for i, left in enumerate(cluster_facts):
            for right in cluster_facts[i + 1 :]:
                conflict = _conflict_between_facts(cluster_id, left, right, pairwise_conflict_count + 1, links_by_fact)
                if not conflict:
                    continue
                pairwise_conflict_count += 1
                _merge_conflict_group(conflict_groups, conflict)
    conflicts = _finalize_conflict_groups(conflict_groups)
    review_rows: list[dict[str, Any]] = []
    for conflict in conflicts:
        if conflict["severity"] in {"CRITICAL", "HIGH"}:
            review_rows.append(
                {
                    "review_id": f"HRQ-CONFLICT-{len(review_rows) + 1:03d}",
                    "flag": "EVIDENCE_CONFLICT_REVIEW",
                    "impact": "BLOCKING" if conflict["severity"] == "CRITICAL" else "LIMITING",
                    "conflict_id": conflict["conflict_id"],
                    "claim_ids": ", ".join(conflict.get("claim_ids") or []),
                    "required_action": "Resolve endpoint-level evidence conflict before upgrading linked claim support.",
                }
            )
    return {
        "evidence_conflict_report": {
            "schema_name": "evidence_conflict_report",
            "conflict_count": len(conflicts),
            "generation_summary": _conflict_generation_summary(pairwise_conflict_count, conflicts),
            "conflicts": conflicts,
            "claim_impacts": _claim_conflict_impacts(conflicts),
        },
        "human_review_queue": review_rows,
    }


def _semantic_endpoint_mapping_for_fact(fact: dict[str, Any]) -> dict[str, Any]:
    text = " ".join(str(fact.get(key) or "") for key in ("endpoint_label", "endpoint_label_original", "source_excerpt", "follow_up", "comparator")).lower()
    candidates = _semantic_endpoint_candidates()
    scored = []
    for candidate in candidates:
        similarity = _token_similarity(text, " ".join(candidate["terms"]))
        dimensions = {
            "endpoint_definition": any(term in text for term in candidate["definition_terms"]),
            "measurement_method": _measurement_method_matches(text, candidate),
            "timepoint": bool(fact.get("follow_up")) or any(term in text for term in candidate["timepoint_terms"]),
            "population": bool(fact.get("population_n")) or any(term in text for term in ("patient", "subject", "population", "cohort", "n=")),
            "procedure_anatomy": any(term in text for term in candidate["anatomy_terms"]) or not candidate["anatomy_terms"],
            "benefit_risk_direction": any(term in text for term in candidate["direction_terms"]),
        }
        count = sum(1 for value in dimensions.values() if value)
        label_text = str(fact.get("endpoint_label") or "").lower()
        exact = label_text == candidate["label"] or label_text in candidate["terms"]
        scored.append((count, similarity, exact, candidate, dimensions))
    count, similarity, exact, candidate, dimensions = max(scored, key=lambda item: (item[0], item[1], item[2]))
    if count == 6 and exact:
        confidence = "high"
    elif count >= 4 and similarity > 0.8:
        confidence = "medium"
    elif candidate["family"] == fact.get("endpoint_family") or count >= 1:
        confidence = "low"
    else:
        confidence = "unmatched"
    cluster = _endpoint_cluster_id(candidate["label"], fact)
    return {
        "mapped_endpoint_label": candidate["label"] if confidence != "unmatched" else str(fact.get("endpoint_label") or "unmatched endpoint"),
        "mapped_endpoint_family": candidate["family"] if confidence != "unmatched" else str(fact.get("endpoint_family") or "unmatched"),
        "endpoint_cluster_id": cluster if confidence != "unmatched" else f"ENDPOINT-UNMATCHED-{str(fact.get('fact_id') or '').upper()}",
        "mapping_confidence": confidence,
        "similarity_score": round(similarity, 3),
        "dimension_match_count": count,
        "match_dimensions": dimensions,
        "endpoint_match_trace": {
            "candidate_label": candidate["label"],
            "exact_label": exact,
            "confidence_rule": "6/6 exact high; >=4 and >0.8 medium; family-only low; no match unmatched",
            "matched_terms": sorted(set(re.findall(r"[a-z0-9]+", text)).intersection(set(candidate["terms"]))),
        },
    }


def _semantic_endpoint_candidates() -> list[dict[str, Any]]:
    return [
        {
            "label": "clinical success",
            "family": "effectiveness",
            "terms": {"clinical", "success", "procedural", "technical", "effective", "completion", "performance", "rate", "pvi", "isolation"},
            "definition_terms": {"success", "completion", "effective", "performance", "isolation"},
            "timepoint_terms": {"day", "month", "follow", "acute"},
            "anatomy_terms": set(),
            "direction_terms": {"success", "effective", "improved", "reduction", "benefit"},
        },
        {
            "label": "serious adverse events",
            "family": "safety",
            "terms": {"serious", "adverse", "event", "events", "sae", "complication", "harm", "death"},
            "definition_terms": {"adverse", "sae", "complication", "harm", "death"},
            "timepoint_terms": {"day", "month", "follow"},
            "anatomy_terms": set(),
            "direction_terms": {"adverse", "harm", "complication", "death", "serious"},
        },
        {
            "label": "hemodynamic pressure",
            "family": "hemodynamic",
            "terms": {"mpap", "pressure", "mmhg", "hemodynamic", "blood", "vascular"},
            "definition_terms": {"mpap", "pressure", "hemodynamic"},
            "timepoint_terms": {"day", "month", "follow", "baseline"},
            "anatomy_terms": {"pulmonary", "cardiac", "vascular"},
            "direction_terms": {"reduction", "decrease", "increase", "improved"},
        },
        {
            "label": "device integrity",
            "family": "device_integrity",
            "terms": {"device", "failure", "malfunction", "breakage", "integrity", "leakage"},
            "definition_terms": {"failure", "malfunction", "breakage", "integrity"},
            "timepoint_terms": {"use", "procedure", "follow"},
            "anatomy_terms": set(),
            "direction_terms": {"failure", "malfunction", "breakage"},
        },
        {
            "label": "quality of life score",
            "family": "quality_of_life",
            "terms": {"quality", "life", "qol", "score", "symptom", "functional"},
            "definition_terms": {"qol", "score", "symptom", "functional"},
            "timepoint_terms": {"day", "month", "follow"},
            "anatomy_terms": set(),
            "direction_terms": {"improved", "increase", "decrease", "reduction"},
        },
    ]


def _measurement_method_matches(text: str, candidate: dict[str, Any]) -> bool:
    if any(unit in text for unit in ("%", "rate", "count", "events", "score", "mmhg")):
        return True
    return any(term in text for term in candidate["terms"])


def _token_similarity(left: str, right: str) -> float:
    left_tokens = set(re.findall(r"[a-z0-9]+", left.lower()))
    right_tokens = set(re.findall(r"[a-z0-9]+", right.lower()))
    if not left_tokens or not right_tokens:
        return 0.0
    return len(left_tokens & right_tokens) / len(left_tokens | right_tokens)


def _endpoint_cluster_id(endpoint_label: str, fact: dict[str, Any]) -> str:
    parts = [
        endpoint_label,
        _time_bucket(str(fact.get("follow_up") or "")),
        _population_bucket(str(fact.get("population_n") or "")),
        str(fact.get("device_relationship") or "any_device"),
        str(fact.get("comparator") or "no_comparator"),
    ]
    slug = re.sub(r"[^a-z0-9]+", "-", "-".join(part.lower() for part in parts if part)).strip("-")
    return f"ENDPOINT-CLUSTER-{slug[:80] or 'UNSPECIFIED'}"


def _time_bucket(value: str) -> str:
    lower = value.lower()
    if any(token in lower for token in ("year", "12 month", "24 month", "long")):
        return "long_term"
    if any(token in lower for token in ("day", "30", "acute", "short")):
        return "short_term"
    return "time_unspecified"


def _population_bucket(value: str) -> str:
    number = _numeric_or_none(value)
    if number is None:
        return "population_unspecified"
    if number < 50:
        return "n_lt_50"
    if number < 200:
        return "n_50_199"
    return "n_ge_200"


def _fact_claim_links(state: dict[str, Any], fact: dict[str, Any]) -> list[str]:
    explicit = [part.strip() for part in str(fact.get("candidate_claim_ids") or "").split(",") if part.strip()]
    if explicit:
        return explicit
    return _candidate_claim_ids_for_fact(state, str(fact.get("endpoint_family") or ""), str(fact.get("endpoint_label") or ""))


def _normalize_quantitative_value(fact: dict[str, Any]) -> tuple[Any, str, str]:
    value = fact.get("value_numeric")
    unit = _normalized_unit(str(fact.get("value_unit") or ""))
    if value in ("", None):
        return "", unit, "needs_human_review" if str(fact.get("value_type") or "") != "qualitative" else "raw"
    numeric = _numeric_or_none(value)
    if numeric is None:
        return value, unit, "needs_human_review"
    if unit == "percent":
        return numeric / 100.0, "proportion", "normalized"
    return numeric, unit, "normalized"


def _normalized_unit(unit: str) -> str:
    value = str(unit or "").strip()
    lower = value.lower()
    if value == "%":
        return "percent"
    if lower in {"mmhg", "mm hg"}:
        return "mmHg"
    if lower in {"event", "events"}:
        return "events"
    return value


def _conflict_between_facts(cluster_id: str, left: dict[str, Any], right: dict[str, Any], index: int, links_by_fact: dict[str, list[str]]) -> dict[str, Any] | None:
    left_direction = _fact_effect_direction(left)
    right_direction = _fact_effect_direction(right)
    conflict_type = ""
    severity = ""
    if left_direction and right_direction and left_direction != right_direction:
        conflict_type = "DIRECTIONAL"
        severity = "CRITICAL"
    elif _magnitude_ratio(left, right) > 2.0:
        conflict_type = "MAGNITUDE"
        severity = "HIGH"
    elif _significance(left) and _significance(right) and _significance(left) != _significance(right):
        conflict_type = "STATISTICAL"
        severity = "HIGH"
    elif _time_bucket(str(left.get("follow_up") or "")) != _time_bucket(str(right.get("follow_up") or "")):
        conflict_type = "TEMPORAL"
        severity = "MEDIUM"
    elif _population_bucket(str(left.get("population_n") or "")) != _population_bucket(str(right.get("population_n") or "")):
        conflict_type = "POPULATION"
        severity = "MEDIUM"
    if not conflict_type:
        return None
    claim_ids = sorted(set(links_by_fact.get(str(left.get("fact_id") or ""), []) + links_by_fact.get(str(right.get("fact_id") or ""), [])))
    evidence_ids = sorted({str(left.get("evidence_id") or ""), str(right.get("evidence_id") or "")})
    conflict_scope = _conflict_scope_for_fact_pair(conflict_type, left, right, claim_ids)
    return {
        "conflict_id": f"CONF-{index:03d}",
        "conflict_scope": conflict_scope,
        "endpoint_cluster_id": cluster_id,
        "endpoint_family": left.get("endpoint_family") or right.get("endpoint_family"),
        "evidence_ids": evidence_ids,
        "fact_ids": [left.get("fact_id"), right.get("fact_id")],
        "claim_ids": claim_ids,
        "conflict_type": conflict_type,
        "severity": severity,
        "comparison_count": 1,
        "representative_fact_pairs": [
            {
                "left_fact_id": left.get("fact_id"),
                "right_fact_id": right.get("fact_id"),
                "left_evidence_id": left.get("evidence_id"),
                "right_evidence_id": right.get("evidence_id"),
            }
        ],
        "description": f"{conflict_type} conflict detected between {evidence_ids[0]} and {evidence_ids[-1]} within {cluster_id}.",
    }


def _merge_conflict_group(groups: dict[tuple[Any, ...], dict[str, Any]], conflict: dict[str, Any]) -> None:
    key = _conflict_group_key(conflict)
    existing = groups.get(key)
    if not existing:
        groups[key] = dict(conflict)
        return
    existing["comparison_count"] = int(existing.get("comparison_count") or 1) + int(conflict.get("comparison_count") or 1)
    for field in ("evidence_ids", "fact_ids", "claim_ids"):
        existing[field] = _limited_unique_values([*(existing.get(field) or []), *(conflict.get(field) or [])], limit=500 if field == "evidence_ids" else 200)
    pairs = [*(existing.get("representative_fact_pairs") or []), *(conflict.get("representative_fact_pairs") or [])]
    existing["representative_fact_pairs"] = pairs[:10]


def _conflict_group_key(conflict: dict[str, Any]) -> tuple[Any, ...]:
    return (
        conflict.get("conflict_scope") or "",
        conflict.get("endpoint_cluster_id") or "",
        conflict.get("endpoint_family") or "",
        conflict.get("conflict_type") or "",
        conflict.get("severity") or "",
    )


def _finalize_conflict_groups(groups: dict[tuple[Any, ...], dict[str, Any]]) -> list[dict[str, Any]]:
    conflicts = []
    for idx, conflict in enumerate(groups.values(), start=1):
        row = dict(conflict)
        row["conflict_id"] = f"CONF-{idx:03d}"
        pair_count = int(row.get("comparison_count") or 1)
        row["description"] = (
            f"{row.get('conflict_type')} conflict aggregated from {pair_count} pairwise comparison(s) "
            f"within {row.get('endpoint_cluster_id')}."
        )
        conflicts.append(row)
    return conflicts


def _limited_unique_values(values: list[Any], *, limit: int) -> list[str]:
    output: list[str] = []
    seen: set[str] = set()
    for value in values:
        text = str(value or "")
        if not text or text in seen:
            continue
        seen.add(text)
        if len(output) < limit:
            output.append(text)
    return output


def _conflict_generation_summary(pairwise_conflict_count: int, conflicts: list[dict[str, Any]]) -> dict[str, Any]:
    scope_counts: dict[str, int] = {}
    type_counts: dict[str, int] = {}
    emitted_pairwise_total = 0
    for conflict in conflicts:
        scope = str(conflict.get("conflict_scope") or "unscoped")
        conflict_type = str(conflict.get("conflict_type") or "unknown")
        scope_counts[scope] = scope_counts.get(scope, 0) + 1
        type_counts[conflict_type] = type_counts.get(conflict_type, 0) + 1
        emitted_pairwise_total += int(conflict.get("comparison_count") or 1)
    return {
        "pairwise_conflicts_detected": pairwise_conflict_count,
        "emitted_conflict_records": len(conflicts),
        "aggregated_pairwise_conflicts": max(0, pairwise_conflict_count - len(conflicts)),
        "emitted_pairwise_total_check": emitted_pairwise_total,
        "conflict_scope_counts": scope_counts,
        "conflict_type_counts": type_counts,
        "granularity": "aggregated_by_conflict_scope_endpoint_cluster_family_type_severity",
    }


def _conflict_scope_for_fact_pair(conflict_type: str, left: dict[str, Any], right: dict[str, Any], claim_ids: list[str]) -> str:
    if _fact_has_entity_level_markers(left) or _fact_has_entity_level_markers(right):
        return "entity_level"
    if conflict_type not in {"DIRECTIONAL", "MAGNITUDE", "STATISTICAL"}:
        return "entity_level"
    if not claim_ids:
        return "entity_level"
    return "semantic"


def _fact_has_entity_level_markers(fact: dict[str, Any]) -> bool:
    return any(
        fact.get(key)
        for key in (
            "entity_id",
            "source_entity_id",
            "extracted_entity_id",
            "normalized_entity_id",
            "left_entity_id",
            "right_entity_id",
            "entity_pair_id",
        )
    )


def _fact_effect_direction(fact: dict[str, Any]) -> str:
    text = " ".join(str(fact.get(key) or "") for key in ("endpoint_family", "endpoint_label", "source_excerpt", "value_numeric")).lower()
    numeric = _numeric_or_none(fact.get("normalized_value", fact.get("value_numeric")))
    if any(token in text for token in ("adverse", "harm", "complication", "failure", "death", "malfunction")):
        if numeric is not None and numeric > 0.05:
            return "harm"
        return "benefit"
    if any(token in text for token in ("success", "improved", "reduction", "effective", "benefit")):
        if numeric is not None and numeric < 0:
            return "harm"
        return "benefit"
    return ""


def _magnitude_ratio(left: dict[str, Any], right: dict[str, Any]) -> float:
    a = abs(_numeric_or_none(left.get("normalized_value", left.get("value_numeric"))) or 0)
    b = abs(_numeric_or_none(right.get("normalized_value", right.get("value_numeric"))) or 0)
    if a == 0 or b == 0:
        return 0.0
    return max(a, b) / min(a, b)


def _significance(fact: dict[str, Any]) -> str:
    p_text = str(fact.get("p_value") or "")
    match = re.search(r"([<=>]=?)\s*(0?\.\d+|1(?:\.0+)?)", p_text)
    if not match:
        return ""
    value = float(match.group(2))
    operator = match.group(1)
    if operator.startswith("<"):
        return "significant" if value <= 0.05 else "not_significant"
    return "significant" if value < 0.05 else "not_significant"


def _claim_conflict_impacts(conflicts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    impacts: dict[str, dict[str, Any]] = {}
    for conflict in conflicts:
        for claim_id in conflict.get("claim_ids") or []:
            row = impacts.setdefault(str(claim_id), {"claim_id": str(claim_id), "conflict_ids": [], "max_severity": "MEDIUM", "impact": "human_review"})
            row["conflict_ids"].append(conflict.get("conflict_id"))
            if conflict.get("severity") == "CRITICAL":
                row["max_severity"] = "CRITICAL"
                row["impact"] = "pivotal_role_blocked"
            elif conflict.get("severity") == "HIGH" and row["max_severity"] != "CRITICAL":
                row["max_severity"] = "HIGH"
                row["impact"] = "human_review_required"
    for row in impacts.values():
        row["conflict_ids"] = ", ".join(str(item) for item in row["conflict_ids"])
    return list(impacts.values())


def _apply_conflict_caps_to_evidence(evidence_rows: list[dict[str, Any]], report: dict[str, Any]) -> list[dict[str, Any]]:
    critical_ids: set[str] = set()
    for conflict in report.get("conflicts") or []:
        if conflict.get("severity") == "CRITICAL":
            critical_ids.update(str(item) for item in conflict.get("evidence_ids") or [] if item)
    if not critical_ids:
        return evidence_rows
    capped = []
    for row in evidence_rows:
        if str(row.get("evidence_id") or "") in critical_ids and row.get("weight") == "pivotal":
            capped.append(
                {
                    **row,
                    "weight": "supportive",
                    "conflict_role_cap": "supportive",
                    "conflict_role_cap_reason": "CRITICAL endpoint-cluster conflict prevents pivotal use.",
                }
            )
        elif str(row.get("evidence_id") or "") in critical_ids:
            capped.append({**row, "conflict_role_cap": "supportive", "conflict_role_cap_reason": "CRITICAL endpoint-cluster conflict prevents pivotal use."})
        else:
            capped.append(row)
    return capped


def _aggregate_fact_confidence_to_evidence(
    evidence_rows: list[dict[str, Any]],
    appraisal_rows: list[dict[str, Any]],
    facts: list[dict[str, Any]],
    conflict_report: dict[str, Any],
) -> dict[str, list[dict[str, Any]]]:
    facts_by_evidence: dict[str, list[dict[str, Any]]] = {}
    for fact in facts:
        evidence_id = str(fact.get("evidence_id") or "")
        if evidence_id:
            facts_by_evidence.setdefault(evidence_id, []).append(fact)
    critical_evidence_ids = {
        str(evidence_id)
        for conflict in conflict_report.get("conflicts") or []
        if conflict.get("severity") == "CRITICAL"
        for evidence_id in conflict.get("evidence_ids") or []
    }
    summary_by_evidence: dict[str, dict[str, Any]] = {}
    enriched_evidence = []
    for row in evidence_rows:
        evidence_id = str(row.get("evidence_id") or "")
        evidence_facts = facts_by_evidence.get(evidence_id, [])
        if not evidence_facts:
            enriched_evidence.append(row)
            continue
        summary = _fact_confidence_summary(evidence_facts, critical_conflict=evidence_id in critical_evidence_ids)
        summary_by_evidence[evidence_id] = summary
        weight = str(row.get("weight") or "")
        ledger_approved = row.get("ledger_approved_for_writer")
        if summary["fact_role_cap"] == "background" and weight in {"pivotal", "supportive"}:
            weight = "background"
            ledger_approved = False
        elif summary["fact_role_cap"] == "supportive" and weight == "pivotal":
            weight = "supportive"
        enriched_evidence.append(
            {
                **row,
                "weight": weight or row.get("weight"),
                "ledger_approved_for_writer": ledger_approved,
                "fact_confidence_signal": summary["fact_confidence_signal"],
                "fact_confidence_summary": summary["summary"],
                "fact_confidence_high_count": summary["high_count"],
                "fact_confidence_medium_count": summary["medium_count"],
                "fact_confidence_low_count": summary["low_count"],
                "fact_confidence_ocr_uncertain_count": summary["ocr_uncertain_count"],
                "fact_role_cap": summary["fact_role_cap"],
                "fact_role_cap_reason": summary["fact_role_cap_reason"],
                "g42_fact_signal": summary["g42_fact_signal"],
            }
        )
    enriched_appraisals = []
    for row in appraisal_rows:
        evidence_id = str(row.get("evidence_id") or "")
        summary = summary_by_evidence.get(evidence_id)
        if not summary:
            enriched_appraisals.append(row)
            continue
        enriched_appraisals.append(
            {
                **row,
                "fact_confidence_signal": summary["fact_confidence_signal"],
                "fact_confidence_summary": summary["summary"],
                "fact_role_cap": summary["fact_role_cap"],
                "g42_fact_signal": summary["g42_fact_signal"],
            }
        )
    return {"evidence_registry": enriched_evidence, "article_appraisal": enriched_appraisals}


def _fact_confidence_summary(facts: list[dict[str, Any]], *, critical_conflict: bool) -> dict[str, Any]:
    confidences = [str(fact.get("extraction_confidence") or "low") for fact in facts]
    high_count = sum(1 for value in confidences if value == "high")
    medium_count = sum(1 for value in confidences if value == "medium")
    low_count = sum(1 for value in confidences if value == "low")
    ocr_uncertain_count = sum(1 for value in confidences if value == "OCR_uncertain")
    if high_count >= 1 and not critical_conflict:
        cap = "pivotal_eligible"
        signal = "FACT_HIGH_CONFIDENCE_PIVOTAL_ELIGIBLE"
        reason = "At least one high-confidence fact is linked and no CRITICAL conflict is recorded."
    elif facts and all(value in {"low", "OCR_uncertain"} for value in confidences):
        cap = "background"
        signal = "FACT_LOW_CONFIDENCE_BACKGROUND_ONLY"
        reason = "All linked facts are low-confidence or OCR-uncertain."
    else:
        cap = "supportive"
        signal = "FACT_MEDIUM_OR_CONFLICT_SUPPORTIVE_CAP"
        reason = "Linked facts are medium/low or a CRITICAL conflict prevents pivotal use."
    if critical_conflict and cap == "pivotal_eligible":
        cap = "supportive"
        signal = "FACT_CRITICAL_CONFLICT_SUPPORTIVE_CAP"
        reason = "CRITICAL conflict prevents pivotal use despite high-confidence facts."
    return {
        "fact_confidence_signal": signal,
        "fact_role_cap": cap,
        "fact_role_cap_reason": reason,
        "g42_fact_signal": cap,
        "high_count": high_count,
        "medium_count": medium_count,
        "low_count": low_count,
        "ocr_uncertain_count": ocr_uncertain_count,
        "summary": f"facts={len(facts)}; high={high_count}; medium={medium_count}; low={low_count}; OCR_uncertain={ocr_uncertain_count}; critical_conflict={critical_conflict}",
    }


def _fact_anchored_claim_rows(state: dict[str, Any]) -> list[dict[str, Any]]:
    facts = {str(row.get("fact_id") or ""): row for row in state.get("clinical_evidence_fact_table") or [] if row.get("fact_id")}
    links = state.get("fact_to_claim_link_matrix") or []
    if not links:
        links = [
            {"fact_id": fact_id, "claim_id": claim_id, "evidence_id": fact.get("evidence_id")}
            for fact_id, fact in facts.items()
            for claim_id in [part.strip() for part in str(fact.get("candidate_claim_ids") or "").split(",") if part.strip()]
        ]
    rows = []
    for idx, link in enumerate(links, start=1):
        fact = facts.get(str(link.get("fact_id") or ""))
        if not fact:
            continue
        confidence = str(fact.get("extraction_confidence") or "low")
        writer_use_level = "quantitative_allowed" if confidence == "high" else "qualitative_only"
        rows.append(
            {
                "row_id": f"FAC-{len(rows) + 1:03d}",
                "claim_id": link.get("claim_id"),
                "fact_id": fact.get("fact_id"),
                "evidence_id": fact.get("evidence_id"),
                "endpoint_cluster_id": fact.get("endpoint_cluster_id"),
                "endpoint_label": fact.get("endpoint_label"),
                "extraction_confidence": confidence,
                "writer_use_level": writer_use_level,
                "formatted_claim": _format_fact_anchored_claim(fact, quantitative=writer_use_level == "quantitative_allowed"),
                "source_page": fact.get("source_page"),
                "source_table": fact.get("source_table"),
                "source_excerpt": fact.get("source_excerpt"),
            }
        )
    return rows


def _format_fact_anchored_claim(fact: dict[str, Any], *, quantitative: bool) -> str:
    endpoint = str(fact.get("endpoint_label") or "the endpoint")
    if not quantitative:
        return f"The evidence reports {endpoint}; use qualitative wording only until fact confidence is high."
    value = fact.get("value_numeric")
    unit = str(fact.get("value_unit") or "")
    if value in ("", None):
        return f"The evidence reports {endpoint}; no normalized quantitative value is available for citation."
    value_text = f"{value}{unit}" if unit == "%" else " ".join(str(part) for part in (value, unit) if str(part))
    ci = ""
    if fact.get("CI_lower") not in ("", None) and fact.get("CI_upper") not in ("", None):
        ci = f" (95% CI: {fact.get('CI_lower')}-{fact.get('CI_upper')})"
    _PLACEHOLDER_FALLBACKS = {"not reported in source", "not extracted", "not available", "not quantified in first-pass", "N/A", ""}
    fu = fact.get("follow_up")
    follow_up = f" at {fu}" if fu and str(fu).strip() not in _PLACEHOLDER_FALLBACKS else ""
    return f"{endpoint} was {value_text}{ci}{follow_up}."


def _build_human_review_queue(facts: list[dict[str, Any]], conflict_report: dict[str, Any], existing_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for fact in facts:
        confidence = str(fact.get("extraction_confidence") or "")
        if confidence in {"low", "OCR_uncertain"}:
            rows.append(_human_review_row(fact, "low_confidence", f"extraction_confidence={confidence}"))
        if str(fact.get("normalizer_status") or "") == "needs_human_review":
            rows.append(_human_review_row(fact, "normalization_failure", "normalizer_status=needs_human_review"))
        if "TRANSLATION_NEEDED" in str(fact.get("extraction_flags") or ""):
            rows.append(_human_review_row(fact, "translation_needed", "TRANSLATION_NEEDED flag present"))
    facts_by_id = {str(fact.get("fact_id") or ""): fact for fact in facts}
    for conflict in conflict_report.get("conflicts") or []:
        if conflict.get("severity") not in {"CRITICAL", "HIGH"}:
            continue
        for fact_id in conflict.get("fact_ids") or []:
            fact = facts_by_id.get(str(fact_id)) or {"fact_id": fact_id, "evidence_id": ""}
            rows.append(_human_review_row(fact, "conflict_flagged", f"{conflict.get('severity')} {conflict.get('conflict_type')} conflict {conflict.get('conflict_id')}"))
    for row in existing_rows:
        rows.append(_normalize_existing_review_row(row))
    return _deduplicate_review_rows(rows)


def _human_review_row(fact: dict[str, Any], trigger_reason: str, trigger_detail: str) -> dict[str, Any]:
    return {
        "review_id": "",
        "fact_id": fact.get("fact_id"),
        "evidence_id": fact.get("evidence_id"),
        "trigger_reason": trigger_reason,
        "trigger_detail": trigger_detail,
        "status": "pending",
        "reviewer_notes": None,
        "reviewed_at": None,
        "flag": trigger_reason.upper(),
        "impact": "BLOCKING" if trigger_reason == "conflict_flagged" and "CRITICAL" in trigger_detail else "LIMITING",
    }


def _normalize_existing_review_row(row: dict[str, Any]) -> dict[str, Any]:
    compact = _compact_review_row(row)
    if row.get("trigger_reason"):
        return {
            **compact,
            "trigger_reason": row.get("trigger_reason"),
            "trigger_detail": row.get("trigger_detail") or row.get("required_action") or row.get("flag") or "",
        }
    flag = str(row.get("flag") or "")
    trigger = {
        "TRANSLATION_NEEDED": "translation_needed",
        "QUANTITATIVE_NORMALIZATION_FAILED": "normalization_failure",
        "EVIDENCE_CONFLICT_REVIEW": "conflict_flagged",
    }.get(flag, "normalization_failure" if "NORMAL" in flag else "low_confidence")
    return {
        **compact,
        "trigger_reason": trigger,
        "trigger_detail": row.get("required_action") or row.get("source_excerpt") or row.get("original_excerpt") or flag,
    }


def _compact_review_row(row: dict[str, Any]) -> dict[str, Any]:
    reference = {
        key: row.get(key)
        for key in ("source_page", "source_table", "source_anchor", "conflict_id", "review_source")
        if row.get(key) not in (None, "")
    }
    return {
        "review_id": row.get("review_id") or "",
        "fact_id": row.get("fact_id"),
        "evidence_id": row.get("evidence_id"),
        "trigger_reason": row.get("trigger_reason") or row.get("flag") or "review_required",
        "trigger_detail": str(row.get("trigger_detail") or row.get("required_action") or row.get("flag") or "")[:1000],
        "status": row.get("status") or "pending",
        "reviewer_notes": row.get("reviewer_notes") if row.get("reviewer_notes") in (None, "") else str(row.get("reviewer_notes"))[:1000],
        "reviewed_at": row.get("reviewed_at"),
        "flag": row.get("flag"),
        "impact": row.get("impact"),
        "source_reference": reference,
    }


def _compact_human_review_queue(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    return _deduplicate_review_rows([_compact_review_row(row) for row in rows if isinstance(row, dict)])


def _deduplicate_fact_rows(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    output: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for row in rows:
        key = (str(row.get("fact_id") or ""), str(row.get("evidence_id") or ""), str(row.get("source_excerpt") or row.get("endpoint_label") or ""))
        if key in seen:
            continue
        seen.add(key)
        output.append(row)
    return output


def _deduplicate_review_rows(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    output: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for idx, row in enumerate(rows, start=1):
        key = (
            str(row.get("trigger_reason") or row.get("flag") or ""),
            str(row.get("fact_id") or row.get("conflict_id") or ""),
            str(row.get("evidence_id") or row.get("claim_ids") or row.get("trigger_detail") or ""),
        )
        if key in seen:
            continue
        seen.add(key)
        output.append(
            {
                **row,
                "review_id": row.get("review_id") or f"HR-{len(output) + 1:03d}",
                "status": row.get("status") or "pending",
                "reviewer_notes": row.get("reviewer_notes") if "reviewer_notes" in row else None,
                "reviewed_at": row.get("reviewed_at") if "reviewed_at" in row else None,
            }
        )
    return output


def _extract_text(path: Path) -> str:
    if path.suffix.lower() in {".txt", ".md"}:
        return path.read_text(encoding="utf-8", errors="replace")
    if path.suffix.lower() == ".doc":
        try:
            result = subprocess.run(
                ["textutil", "-convert", "txt", "-stdout", str(path)],
                check=False,
                capture_output=True,
                text=True,
                timeout=45,
            )
            if result.stdout.strip():
                return result.stdout
        except Exception:
            pass
    try:
        from deerflow.utils.file_conversion import _do_convert

        return _do_convert(path, "auto")
    except Exception:
        if path.suffix.lower() in {".csv", ".json", ".xml"}:
            try:
                return path.read_text(encoding="utf-8", errors="replace")
            except Exception:
                return ""
        return ""


def _classify_document(filename: str, path: str | None = None) -> str:
    lower = filename.lower()
    if path and _is_locked_delta_path(path):
        return "locked_delta_only"
    if _has_strong_ifu_signal(filename, path or ""):
        return "IFU"
    mapping = [
        ("gspr", "GSPR"),
        ("rmf", "RMF"),
        ("risk", "RMF"),
        ("风险管理", "RMF"),
        ("风险", "RMF"),
        ("fmea", "RMF"),
        ("cep", "CEP"),
        ("pmcf", "PMCF"),
        ("pms", "PMS"),
        ("equivalence", "equivalence"),
        ("等同", "equivalence"),
        ("clinical evaluation", "previous_cer"),
        ("cer", "previous_cer"),
        ("metadata", "metadata"),
        ("device profile", "metadata"),
        ("device_profile", "metadata"),
        ("classification", "metadata"),
        ("产品分类", "metadata"),
        ("器械分类", "metadata"),
    ]
    for needle, doc_type in mapping:
        if needle in lower:
            return doc_type
    return "source"


def _normalized_path_text(value: str) -> str:
    return re.sub(r"[^a-z0-9\u3400-\u9fff]+", "_", str(value or "").lower()).strip("_")


def _compact_path_text(value: str) -> str:
    return re.sub(r"[^a-z0-9\u3400-\u9fff]+", "", str(value or "").lower())


def _path_parts(path: str) -> list[str]:
    if not path:
        return []
    return [_normalized_path_text(part) for part in Path(str(path)).parts if part]


def _is_locked_delta_path(path: str | None) -> bool:
    normalized = _normalized_path_text(str(path or ""))
    return any(token in normalized for token in LOCKED_DELTA_PATH_TOKENS)


def _is_ifu_folder_path(path: str | None) -> bool:
    parts = _path_parts(str(path or ""))
    return any(part in IFU_FOLDER_TOKENS or part.startswith("01_ifu") for part in parts)


def _has_strong_ifu_signal(filename: str, path: str | None = None) -> bool:
    if _is_locked_delta_path(path):
        return False
    text = f"{filename} {path or ''}"
    normalized = _normalized_path_text(text)
    compact = _compact_path_text(text)
    if any(token in compact or token in normalized for token in IFU_STRONG_NAME_TOKENS):
        return True
    if _is_ifu_folder_path(path):
        return True
    if any(token in compact or token in normalized for token in IFU_CONTEXT_TOKENS) and _is_ifu_folder_path(path):
        return True
    return False


def _ifu_candidate_score(item: dict[str, Any]) -> int:
    filename = str(item.get("filename") or "")
    path = str(item.get("path") or item.get("filepath") or "")
    score = int(item.get("relevance_score") or 0)
    score += _source_subject_score(filename, path, [], "generic")
    if _has_strong_ifu_signal(filename, path):
        score += 5
    if _is_ifu_folder_path(path):
        score += 3
    if item.get("source_role") == "subject_device_ifu":
        score += 2
    if item.get("excluded_from_device_profile"):
        score -= 50
    return score


def _rank_ifu_candidates(inventory: list[dict[str, Any]]) -> list[dict[str, Any]]:
    candidates = [
        item
        for item in inventory
        if item.get("document_type") == "IFU" or _has_strong_ifu_signal(str(item.get("filename") or ""), str(item.get("path") or ""))
    ]
    ranked = sorted(candidates, key=lambda item: (_ifu_candidate_score(item), str(item.get("filename") or "")), reverse=True)
    rows = []
    for rank, item in enumerate(ranked, start=1):
        rows.append(
            {
                "rank": rank,
                "source_id": item.get("source_id"),
                "filename": item.get("filename"),
                "document_type": item.get("document_type"),
                "source_role": item.get("source_role"),
                "relevance_score": item.get("relevance_score"),
                "ifu_candidate_score": _ifu_candidate_score(item),
                "primary_for_authoring": bool(item.get("primary_for_authoring")),
                "excluded_from_device_profile": bool(item.get("excluded_from_device_profile")),
                "role_reason": item.get("role_reason"),
            }
        )
    return rows


def _input_gaps(inventory: list[dict[str, Any]]) -> list[dict[str, Any]]:
    present = {str(item.get("document_type", "")).lower() for item in inventory}
    recommended = {
        "GSPR": "GSPR coverage can only be partial without a checklist.",
        "RMF": "Risk closure cannot claim RMF coverage without RMF/RMR/FMEA.",
        "PMS": "Post-market evidence remains limited without PMS/complaints/sales data.",
        "PMCF": "Remaining uncertainties require PMCF planning if PMCF source is absent.",
        "equivalence": "Equivalence cannot be claimed without confirmed equivalent-device documentation.",
    }
    gaps = []
    for doc_type, impact in recommended.items():
        if doc_type.lower() not in present:
            gaps.append({"gap_id": f"GAP-INPUT-{doc_type.upper()}", "required_input": doc_type, "impact": impact})
    return gaps


def _build_evidence_source_inventory(inventory: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for item in inventory:
        source_type, confidence, basis = _classify_evidence_source_type(item)
        relationship, relationship_basis = _classify_device_relationship(item)
        source_type = _source_type_for_relationship_boundary(source_type, relationship)
        relation_metadata = _relationship_metadata_for_source(relationship, source_type, item)
        source_anchor = str(item.get("path") or item.get("filepath") or item.get("filename") or item.get("source_id") or "")
        item["evidence_source_type"] = source_type
        item["device_relationship"] = relationship
        item["source_anchor"] = source_anchor
        item.update({key: value for key, value in relation_metadata.items() if key not in {"source_anchor"}})
        rows.append(
            {
                "source_id": item.get("source_id"),
                "filename": item.get("filename"),
                "document_type": item.get("document_type"),
                "source_role": item.get("source_role"),
                "source_type": source_type,
                "source_anchor": source_anchor,
                "device_relationship": relationship,
                **relation_metadata,
                "classification_confidence": confidence,
                "classification_basis": basis,
                "relationship_basis": relationship_basis,
                "content_priority": "content_first_filename_path_hint_second",
                "text_length": item.get("text_length") or len(str(item.get("text") or "")),
            }
        )
    return rows


def _classify_evidence_source_type(item: dict[str, Any]) -> tuple[str, str, str]:
    doc_type = str(item.get("document_type") or "").lower()
    text = str(item.get("text") or "").lower()
    descriptor = " ".join(str(item.get(key) or "") for key in ("filename", "path", "filepath", "source_role")).lower()
    content = text[:40_000]
    combined = f"{content}\n{descriptor}"
    if doc_type == "locked_delta_only" or item.get("source_role") == "locked_delta_only":
        return "locked_delta_only", "high", "locked delta-only source role/path"
    doc_type_map = {
        "rmf": "subject_device_risk_management",
        "gspr": "subject_device_gspr",
        "pms": "subject_device_pms_pmcf",
        "pmcf": "subject_device_pms_pmcf",
        "equivalence": "similar_device_regulatory",
        "previous_cer": "manufacturer_cep_technical_file",
        "cep": "manufacturer_cep_technical_file",
    }
    if doc_type in doc_type_map:
        return doc_type_map[doc_type], "high", f"document_type `{doc_type}` controls source-type classification"
    content_rules: list[tuple[str, tuple[str, ...], str]] = [
        ("subject_device_gspr", ("general safety and performance requirement", "gspr", "annex i", "基本安全和性能"), "GSPR checklist content"),
        ("subject_device_ifu", ("instructions for use", "instruction for use", "ifu", "intended use", "contraindications", "warnings", "使用说明书"), "IFU/labeling content"),
        ("subject_device_risk_management", ("risk management", "iso 14971", "residual risk", "hazard", "fmea", "风险管理"), "risk-management content"),
        ("subject_device_pms_pmcf", ("post-market clinical follow-up", "pmcf", "post market surveillance", "post-market surveillance", "pms plan", "pmcf plan"), "PMS/PMCF content"),
        ("subject_device_vigilance", ("vigilance", "maude", "recall", "complaint", "adverse event", "field safety corrective"), "vigilance/recall content"),
        ("subject_device_clinical_study", ("clinical investigation", "clinical trial", "investigational plan", "clinical study report", "clinical trial protocol"), "subject clinical-investigation content"),
        ("subject_device_clinical_data", ("manufacturer clinical data", "clinical data held", "clinical evaluation data", "own clinical"), "manufacturer-held clinical data content"),
        ("similar_device_regulatory", ("equivalence", "equivalent device", "similar device", "comparable device", "predicate device"), "equivalence/comparator content"),
        ("competitor_device_public", ("competitor", "competitive device", "predicate device"), "competitor public-device content"),
        ("subject_device_test_performance", ("bench test", "verification report", "validation report", "performance test", "electrical safety", "emc", "software validation", "biocompatibility", "iso 10993", "sterilization", "sterilisation", "sterile barrier", "eo residual"), "test/performance/biocompatibility/sterilization content"),
        ("manufacturer_cep_technical_file", ("clinical evaluation report", "clinical evaluation plan", "cep", "technical file", "technical documentation"), "manufacturer CER/CEP/technical-file content"),
        ("other_manufacturer_data", ("standard", "guidance", "mdcg", "meddev", "harmonised standard", "harmonized standard"), "manufacturer standards/guidance source content"),
    ]
    for source_type, tokens, basis in content_rules:
        if any(token in content for token in tokens):
            return source_type, "high", basis
    if doc_type == "ifu":
        return "subject_device_ifu", "medium", "document_type hint `ifu` used after content scan"
    descriptor_rules: list[tuple[str, tuple[str, ...], str]] = [
        ("competitor_device_public", ("competitor", "competitive"), "filename/path competitor hint"),
        ("similar_device_regulatory", ("equivalence", "equivalent", "similar", "predicate"), "filename/path comparator hint"),
        ("subject_device_test_performance", ("test", "verification", "validation", "performance"), "filename/path test hint"),
        ("other_manufacturer_data", ("standard", "guidance", "mdcg", "meddev"), "filename/path standards hint"),
    ]
    for source_type, tokens, basis in descriptor_rules:
        if any(token in descriptor for token in tokens):
            return source_type, "low", basis
    return "unknown_unclassified", "low", "content classification did not match known source-type rules; no literature fallback applied"


def _classify_device_relationship(item: dict[str, Any]) -> tuple[str, str]:
    role = str(item.get("source_role") or "").lower()
    text = str(item.get("text") or "").lower()
    descriptor = " ".join(str(item.get(key) or "") for key in ("filename", "path", "filepath", "document_type")).lower()
    combined = f"{text[:20_000]}\n{descriptor}"
    if role in {"subject_device_ifu", "primary_subject_source"} or item.get("primary_for_authoring"):
        return "subject", "source_role/primary_for_authoring indicates subject device"
    if "previous" in descriptor or "previous generation" in descriptor:
        return "previous_gen", "filename/path indicates previous-generation evidence"
    explicit_competitor = any(token in combined for token in ("lithovue", "ethicon", "teleflex", "weck", "boston scientific", "olympus", "cook medical")) or (
        any(token in descriptor for token in ("competitor", "competitive"))
        and not any(token in descriptor for token in ("similar", "equivalent", "predicate", "benchmark"))
    )
    if explicit_competitor:
        return "competitor", "filename/path indicates competitor device source"
    if role in {"similar_device_ifu", "similar_or_benchmark_source"} or any(token in combined for token in ("similar", "equivalent", "predicate", "benchmark", "comparator")):
        return "similar", "source role/path indicates similar/equivalent/benchmark device"
    if role == "locked_delta_only":
        return "unrelated", "locked delta-only source is not writer evidence"
    return "unknown", "relationship not determinable from content/source role"


def _source_type_for_relationship_boundary(source_type: str, relationship: str) -> str:
    if relationship == "competitor":
        return "competitor_device_public"
    if relationship == "previous_gen":
        return "previous_generation_device"
    if relationship == "similar" and source_type.startswith("subject_device_"):
        return "similar_device_regulatory"
    return source_type


def _relationship_metadata_for_source(relationship: str, source_type: str, source: dict[str, Any]) -> dict[str, Any]:
    text = str(source.get("text") or "")
    relation_type = _relationship_type(relationship, text)
    scores = _comparability_scores_for_relation(relation_type, source_type, text)
    allowed = _allowed_use_for_relationship(relation_type)
    return {
        "relationship_type": relation_type,
        "technical_comparability_score": scores["technical"],
        "biological_comparability_score": scores["biological"],
        "clinical_comparability_score": scores["clinical"],
        "comparability_score_raw": scores["raw"],
        "comparability_score_normalized": scores["normalized"],
        "comparability_band": scores["band"],
        "comparability_rationale": scores["rationale"],
        "relation_rationale": allowed["relation_rationale"],
        "relation_limitations": allowed["relation_limitations"],
        "allowed_claim_types": allowed["allowed_claim_types"],
        "allowed_use": allowed["allowed_use"],
        "forbidden_use": allowed["forbidden_use"],
        "max_conclusion_strength": allowed["max_conclusion_strength"],
    }


def _relationship_type(relationship: str, text: str) -> str:
    lower = text.lower()
    formal_equivalence = all(token in lower for token in ("technical", "biological", "clinical", "equivalence")) and any(
        token in lower for token in ("demonstrated", "validated", "established", "confirmed")
    )
    if relationship == "similar" and formal_equivalence:
        return "equivalent_device"
    if relationship == "similar":
        return "similar_device"
    if relationship == "competitor":
        return "competitor_device"
    if relationship == "previous_gen":
        return "previous_generation"
    if relationship == "subject":
        return "subject_device"
    if relationship == "unrelated":
        return "unrelated_device"
    return "unknown_relationship"


def _comparability_scores_for_relation(relation_type: str, source_type: str, text: str) -> dict[str, Any]:
    lower = text.lower()
    if relation_type == "subject_device":
        technical, biological, clinical = 3, 3, 3
        rationale = "Subject-device source; comparability is intrinsic."
    elif relation_type == "equivalent_device":
        technical, biological, clinical = 3, 3, 3
        rationale = "Formal equivalence language covers technical, biological and clinical dimensions."
    elif relation_type == "similar_device":
        technical = 2 if any(token in lower for token in ("specification", "model", "technical", "size", "dimension")) else 1
        biological = 2 if any(token in lower for token in ("material", "sterile", "biocompatibility", "contact")) else 1
        clinical = 2 if any(token in lower for token in ("intended use", "indication", "patient", "procedure", "clinical")) else 1
        rationale = "Similar-device source; comparable use is possible but equivalence is not demonstrated."
    elif relation_type == "competitor_device":
        technical = 1 if any(token in lower for token in ("specification", "model", "technical")) else 0
        biological = 1 if any(token in lower for token in ("material", "sterile", "contact")) else 0
        clinical = 2 if any(token in lower for token in ("intended use", "indication", "procedure", "clinical")) else 1
        rationale = "Competitor source; allowed for SOTA benchmark context only."
    elif relation_type == "previous_generation":
        technical, biological, clinical = 2, 2, 2
        rationale = "Previous-generation source; transferability requires documented improvement trace."
    else:
        technical, biological, clinical = 0, 0, 0
        rationale = "No reliable relationship evidence; not comparable."
    raw = technical + biological + clinical
    normalized = round((raw / 9) * 100)
    if raw >= 7:
        band = "HIGH"
    elif raw >= 4:
        band = "MEDIUM"
    elif raw >= 0:
        band = "LOW"
    else:
        band = "NOT_COMPARABLE"
    if relation_type in {"unrelated_device", "unknown_relationship"}:
        band = "NOT_COMPARABLE"
    return {"technical": technical, "biological": biological, "clinical": clinical, "raw": raw, "normalized": normalized, "band": band, "rationale": rationale}


def _allowed_use_for_relationship(relation_type: str) -> dict[str, Any]:
    if relation_type == "subject_device":
        return {
            "allowed_claim_types": ["clinical_benefit", "clinical_safety", "performance", "IFU_safety_warning", "risk_control_instruction", "PMS_or_PMCF"],
            "allowed_use": "subject-device claims according to source type and evidence strength",
            "forbidden_use": [],
            "max_conclusion_strength": "per_appraisal",
            "relation_rationale": "Subject-device evidence from the writer input package.",
            "relation_limitations": "Use remains limited by evidence level, missing-data flags and source type.",
        }
    if relation_type == "equivalent_device":
        return {
            "allowed_claim_types": ["equivalence_or_similar_device", "clinical_safety", "performance"],
            "allowed_use": "claims within validated equivalence scope only",
            "forbidden_use": ["claims_outside_equivalence_scope"],
            "max_conclusion_strength": "cautious_unless_equivalence_scope_locked",
            "relation_rationale": "Equivalent-device use requires formal technical, biological and clinical equivalence rationale.",
            "relation_limitations": "Cannot support claims outside the documented equivalence scope.",
        }
    if relation_type == "similar_device":
        return {
            "allowed_claim_types": ["SOTA_benchmark", "clinical_safety", "risk_control_instruction"],
            "allowed_use": "clinical context, SOTA benchmark and risk context only",
            "forbidden_use": ["clinical_benefit", "direct_subject_device_performance_claim", "direct_subject_device_safety_claim"],
            "max_conclusion_strength": "cautious",
            "relation_rationale": "Similar-device evidence is comparable context, not equivalent-device evidence.",
            "relation_limitations": "Must cite relationship and key differences; cannot make direct subject-device clinical benefit claims.",
        }
    if relation_type == "competitor_device":
        return {
            "allowed_claim_types": ["SOTA_benchmark"],
            "allowed_use": "SOTA benchmark only",
            "forbidden_use": ["clinical_benefit", "clinical_safety", "performance", "IFU_safety_warning", "risk_control_instruction", "PMS_or_PMCF"],
            "max_conclusion_strength": "descriptive_or_cautious",
            "relation_rationale": "Competitor evidence may define SOTA context but not subject-device claim support.",
            "relation_limitations": "Competitive relationship must be disclosed; not transferable to subject-device benefit-risk claims.",
        }
    if relation_type == "previous_generation":
        return {
            "allowed_claim_types": ["SOTA_benchmark", "clinical_safety", "risk_control_instruction"],
            "allowed_use": "clinical context and risk context only unless improvement trace is documented",
            "forbidden_use": ["direct_subject_device_performance_claim_without_improvement_trace"],
            "max_conclusion_strength": "cautious",
            "relation_rationale": "Previous-generation evidence may inform context when design continuity is documented.",
            "relation_limitations": "Cannot support direct performance claims unless improvement and transferability are documented.",
        }
    return {
        "allowed_claim_types": [],
        "allowed_use": "excluded",
        "forbidden_use": ["all_claim_types"],
        "max_conclusion_strength": "not_allowed",
        "relation_rationale": "Relationship is unrelated or unknown.",
        "relation_limitations": "Not allowed for evidence support.",
    }


def _source_text(state: dict[str, Any], doc_type: str) -> str:
    chunks = []
    for item in _candidate_sources(state, doc_type):
        chunks.append(str(item.get("text", "")))
    return "\n".join(chunks)


def _identity_source_basis_text(state: dict[str, Any], ifu_text: str) -> str:
    chunks = [ifu_text]
    for item in state.get("source_inventory") or []:
        if item.get("source_role") == "locked_delta_only" or item.get("excluded_from_device_profile"):
            continue
        doc_type = str(item.get("document_type") or "")
        source_role = str(item.get("source_role") or "")
        source_descriptor = " ".join(
            [
                str(doc_type),
                str(item.get("filename") or ""),
                str(item.get("path") or item.get("filepath") or ""),
                json.dumps(item.get("doc_proc_metadata") or {}, ensure_ascii=False, default=str)[:2000],
            ]
        ).lower()
        identity_roles = {"subject_device_ifu", "manufacturer_source", "manufacturer_equivalence"}
        include_for_identity = (
            (doc_type in IDENTITY_CONTEXT_DOC_TYPES and source_role in identity_roles)
            or item.get("primary_for_authoring")
            or (any(token.lower() in source_descriptor for token in IDENTITY_CONTEXT_NAME_TOKENS) and source_role in identity_roles)
        )
        if include_for_identity:
            chunks.append(str(item.get("filename") or ""))
            chunks.append(str(item.get("path") or ""))
            if item.get("doc_proc_metadata"):
                chunks.append(json.dumps(item.get("doc_proc_metadata"), ensure_ascii=False, default=str)[:4000])
            chunks.append(str(item.get("text") or "")[:4000])
    return "\n".join(chunk for chunk in chunks if chunk)


def _candidate_sources(state: dict[str, Any], doc_type: str) -> list[dict[str, Any]]:
    candidates = []
    for item in state.get("source_inventory") or []:
        combined = f"{item.get('document_type', '')} {item.get('filename', '')}".lower()
        if doc_type.lower() in combined:
            if doc_type.lower() == "ifu" and item.get("source_role") in {"similar_device_ifu", "similar_or_benchmark_source", "unconfirmed_ifu"}:
                continue
            if doc_type.lower() == "ifu" and item.get("excluded_from_device_profile"):
                continue
            candidates.append(item)
    candidates.sort(
        key=lambda item: (
            bool(item.get("primary_for_authoring")),
            int(item.get("relevance_score") or 0),
            int(item.get("text_length") or 0),
        ),
        reverse=True,
    )
    if doc_type.lower() == "ifu" and any(item.get("primary_for_authoring") for item in candidates):
        return [item for item in candidates if item.get("primary_for_authoring")]
    if doc_type.lower() in {"rmf", "risk"} and candidates:
        max_score = max(int(item.get("relevance_score") or 0) for item in candidates)
        if max_score > 0:
            return [item for item in candidates if int(item.get("relevance_score") or 0) == max_score]
    return candidates


def _source_id(state: dict[str, Any], doc_type: str) -> str:
    candidates = _candidate_sources(state, doc_type)
    for item in candidates:
        return str(item.get("source_id", "SRC-UNKNOWN"))
    return "SRC-UNKNOWN"


def _has_source(state: dict[str, Any], doc_type: str) -> bool:
    return bool(_source_id(state, doc_type) != "SRC-UNKNOWN")


def _first_filename_stem(state: dict[str, Any]) -> str:
    for item in state.get("source_inventory") or []:
        filename = item.get("filename")
        if filename:
            return Path(str(filename)).stem
    return ""


def _target_keywords(state: dict[str, Any]) -> list[str]:
    explicit = [str(item).strip() for item in state.get("target_keywords") or [] if str(item).strip()]
    if explicit:
        return explicit
    basis = f"{state.get('project_id', '')} {state.get('input_root', '')}".lower()
    inferred = []
    if _clinical_domain_from_text(basis) == "cardiac_pfa":
        inferred.extend(
            [
                "Pulsed Field Ablation",
                "pulsed field ablation catheter",
                "cardiac pulsed field ablation",
                "atrial fibrillation ablation",
                "electroporation ablation",
                "ablation catheter",
                "PFA",
                "脉冲电场消融",
                "心脏脉冲电场消融仪",
                "一次性使用心脏脉冲电场消融导管",
            ]
        )
    if _clinical_domain_from_text(basis) == "urology_nephroscope":
        inferred.extend(
            [
                "Single-use Electronic Ureterorenoscope",
                "Single-use Electronic Ureterorenoscope Catheter",
                "nephroscope",
                "ureterorenoscope",
                "electronic endoscope",
                "一次性使用电子输尿管肾盂内窥镜导管",
                "一次性使用电子膀胱肾盂内窥镜导管",
                "肾盂镜",
                "输尿管肾盂内窥镜",
                "膀胱肾盂内窥镜",
                "圆和",
                "Yuanhe",
            ]
        )
    if "uas" in basis or "access sheath" in basis or "导引鞘" in basis:
        inferred.extend(["Ureteral Access Sheath", "负压导引鞘", "输尿管负压导引鞘", "导引鞘", "ASFXI", "sheath"])
    if _clinical_domain_from_text(basis) == "ai_diagnostic_software":
        inferred.extend(["AI diagnostic software", "diagnostic software", "software algorithm", "artificial intelligence", "machine learning", "辅助诊断软件", "人工智能", "算法", "诊断"])
    if _clinical_domain_from_text(basis) == "software_medical_device":
        inferred.extend(["software medical device", "software as a medical device", "SaMD", "medical device software", "clinical decision support software", "医疗器械软件", "医用软件"])
    if _clinical_domain_from_text(basis) == "powered_therapeutic_equipment":
        inferred.extend(["Enteral Feeding Pump", "feeding pump", "enteral nutrition", "flow delivery", "pump alarm", "powered equipment", "肠内营养泵", "喂养泵", "泵", "报警"])
    if _clinical_domain_from_text(basis) == "plasma_surgical_equipment":
        inferred.extend(["Plasma Surgical Equipment", "Radiofrequency Plasma Surgical Equipment", "plasma generator", "ENT", "otolaryngology", "等离子手术设备", "等离子射频治疗仪", "主机", "耳鼻喉"])
    if _clinical_domain_from_text(basis) == "contrast_imaging_bubble_study_system":
        inferred.extend([
            "Bubble Study System",
            "agitated saline",
            "ultrasound contrast",
            "contrast echocardiography",
            "contrast-enhanced transcranial Doppler",
            "right-to-left shunt",
            "patent foramen ovale",
            "PFO",
            "RLS",
            "c-TTE",
            "c-TCD",
            "发泡试验",
            "超声造影",
            "右向左分流",
            "卵圆孔未闭",
        ])
    return inferred


def _clinical_domain(state: dict[str, Any]) -> str:
    profile = state.get("device_profile") or {}
    text = " ".join(
        [
            str(state.get("project_id", "")),
            str(state.get("input_root", "")),
            " ".join(str(item) for item in state.get("target_keywords") or []),
            str(profile.get("device_name", "")),
            str(profile.get("device_type", "")),
            str(profile.get("intended_purpose", "")),
            str(profile.get("mode_of_action", "")),
            str(profile.get("anatomical_site", "")),
        ]
    )
    return _clinical_domain_from_text(text)


def _clinical_domain_from_text(text: str) -> str:
    lower = str(text or "").lower()
    if _is_ligating_clip_text(text):
        return "surgical_ligating_clip"
    if _is_hemoperfusion_text(text):
        return "blood_purification_hemoperfusion"
    if _is_rf_ablation_catheter_text(text):
        return "cardiovascular_rf_ablation_catheter"
    if _is_nerve_block_needle_text(text):
        return "nerve_block_needle"
    if _is_powered_therapeutic_equipment_text(text):
        return "powered_therapeutic_equipment"
    if _is_ai_diagnostic_software_text(text):
        return "ai_diagnostic_software"
    if _is_software_medical_device_text(text):
        return "software_medical_device"
    if _is_contrast_imaging_bubble_study_text(text):
        return "contrast_imaging_bubble_study_system"
    if _is_plasma_surgical_equipment_text(text):
        return "plasma_surgical_equipment"
    if _is_plasma_surgical_electrode_text(text):
        return "plasma_surgical_electrode"
    if _is_cardiac_tissue_stabilizer_text(text):
        return "cardiac_tissue_stabilizer"
    if any(token in lower for token in ["pulsed field", "pfa", "ablation", "atrial", "cardiac", "electroporation"]) or any(
        token in str(text or "") for token in ["脉冲", "消融", "房颤", "心房", "心脏", "肺静脉", "电穿孔"]
    ):
        return "cardiac_pfa"
    if any(token in lower for token in ["ureteroscope", "ureterorenoscope", "nephroscope", "cystoscope", "endoscope"]) or any(
        token in str(text or "") for token in ["肾盂镜", "肾盂内窥镜", "输尿管肾盂内窥镜", "膀胱肾盂内窥镜", "电子内窥镜", "膀胱镜"]
    ):
        return "urology_nephroscope"
    if any(token in lower for token in ["ureteral access sheath", "ureteric access sheath", "access sheath", "uas", "suction sheath"]) or any(
        token in str(text or "") for token in ["导引鞘", "鞘管", "负压导引鞘"]
    ):
        return "urology_uas"
    return "generic"


def _source_relevance_score(filename: str, document_type: str, target_keywords: list[str]) -> int:
    haystack = f"{filename} {document_type}".lower()
    score = 0
    for keyword in target_keywords:
        key = keyword.lower()
        if key and key in haystack:
            score += 3 if len(key) >= 4 else 1
    if "ifu" in haystack or "instructions for use" in haystack or "使用说明书" in haystack or "说明书" in haystack:
        score += 2
    if "risk" in haystack or "风险管理" in haystack or "rmf" in haystack:
        score += 1
    if "性能确认" in haystack or "verification" in haystack or "validation" in haystack:
        score += 1
    if any(token in haystack for token in ("software", "algorithm", "diagnosis", "diagnostic", "samd", "ai")) or any(
        token in f"{filename} {document_type}" for token in ("软件", "算法", "诊断", "人工智能", "辅助诊断")
    ):
        score += 2
    return score


def _infer_device_name_from_sources(state: dict[str, Any]) -> str:
    for item in _candidate_sources(state, "ifu"):
        filename = str(item.get("filename", ""))
        name = _device_name_from_filename(filename)
        if name:
            return name
    for item in sorted(state.get("source_inventory") or [], key=lambda row: int(row.get("relevance_score") or 0), reverse=True):
        name = _device_name_from_filename(str(item.get("filename", "")))
        if name:
            return name
    return ""


def _is_ligating_clip_text(text: Any) -> bool:
    lower = str(text or "").lower()
    original = str(text or "")
    return any(
        token in lower
        for token in (
            "ligating clip",
            "ligating clips",
            "hemostatic clip",
            "haemostatic clip",
            "vascular clip",
            "ligation clip",
            "tubular structures or vessels",
            "ligating of tubular structures",
            "ligating of vessels",
        )
    ) or any(token in original for token in ("结扎夹", "血管夹", "止血夹", "管状结构", "血管结扎"))


def _is_cardiac_tissue_stabilizer_text(text: Any) -> bool:
    lower = str(text or "").lower()
