def _database_source_row(row: dict[str, Any]) -> dict[str, Any]:
    status = row.get("status") or "unknown"
    return {
        "row_id": f"DB-{row.get('search_id', row.get('database', 'SRC'))}",
        "search_id": row.get("search_id"),
        "database": row.get("database"),
        "purpose": row.get("objective"),
        "url": row.get("url"),
        "search_date": row.get("search_date"),
        "query": row.get("query"),
        "filters": row.get("filters"),
        "result_count": row.get("result_count"),
        "returned_count": row.get("returned_count"),
        "status": status,
        "error_type": row.get("error_type"),
        "error_message": row.get("error_message"),
        "limitation": "Subscription/API access limitation recorded; not interpreted as zero evidence." if status in {"auth_required", "source_unavailable"} else "",
    }


def _protocol_deviations_from_registry(registry: list[dict[str, Any]]) -> list[dict[str, Any]]:
    deviations = []
    for idx, row in enumerate(registry, start=1):
        status = str(row.get("status") or "").lower()
        if status in {"auth_required", "source_unavailable"}:
            deviations.append(
                {
                    "deviation_id": f"DEV-{idx:03d}",
                    "search_id": row.get("search_id"),
                    "database": row.get("database"),
                    "deviation_type": "source_access_limitation",
                    "description": f"{row.get('database')} returned {row.get('status')}; this is not a no-result search.",
                    "impact": "Evidence completeness may be limited; conclusions must remain proportionate and PMCF/full search update may be needed.",
                    "control": "Keep search metadata and request subscription/API access or manual export if the database is required for final submission.",
                }
            )
    if not deviations:
        deviations.append(
            {
                "deviation_id": "DEV-000",
                "search_id": "not applicable",
                "database": "all executed sources",
                "deviation_type": "none_recorded",
                "description": "No protocol deviation recorded in this automated run.",
                "impact": "No deviation impact identified.",
                "control": "Retain executed search logs.",
            }
        )
    return deviations


