def _public_device_term(profile: dict[str, Any], state: dict[str, Any]) -> str:
    profile_candidates = [
        profile.get("device_name"),
        profile.get("device_type"),
    ]
    for candidate in profile_candidates:
        text = str(candidate or "").strip()
        if text and text.isascii() and len(text) >= 4 and not _is_stale_ifu_placeholder_term(text):
            return text
    for keyword in state.get("target_keywords") or []:
        keyword = str(keyword).strip()
        if keyword and keyword.isascii() and len(keyword) >= 4 and not _is_stale_ifu_placeholder_term(keyword):
            return keyword
    name = str(profile.get("device_name") or "")
    if name.isascii() and len(name) >= 4 and not _is_stale_ifu_placeholder_term(name):
        return name
    if "导引鞘" in name or "鞘" in name:
        return "Ureteral Access Sheath"
    if "肾盂镜" in name or "内窥镜" in name:
        return "Single-use Ureteroscope"
    return str(profile.get("device_type") or "medical device")


