def load_ap_template_profile() -> dict[str, Any]:
    if not AP_TEMPLATE_ROOT.exists():
        return {}
    rows = []
    for path in AP_TEMPLATE_ROOT.glob("*.docx"):
        try:
            from docx import Document

            doc = Document(str(path))
            headings = []
            for paragraph in doc.paragraphs:
                style_name = getattr(getattr(paragraph, "style", None), "name", "") or ""
                text = paragraph.text.strip()
                if text and ("Heading" in style_name or re.match(r"^\d+(?:\.\d+)*\s+", text)):
                    headings.append(english_report_text(text, "AP template heading")[:180])
            rows.append(
                {
                    "filename": english_filename(path.name),
                    "template_role": _ap_template_role(path.name),
                    "paragraphs": len(doc.paragraphs),
                    "tables": len(doc.tables),
                    "heading_count": len(headings),
                    "representative_headings": headings[:15],
                }
            )
        except Exception as exc:
            rows.append({"filename": english_filename(path.name), "template_role": _ap_template_role(path.name), "status": f"unavailable: {type(exc).__name__}"})
    return {
        "root": str(AP_TEMPLATE_ROOT),
        "template_count": len(rows),
        "templates": rows,
        "cer_authoring_use": (
            "AP Clinical Evaluation Report template controls the chapter set; AP SOTA and Literature Search Protocol templates control search/report annexes; "
            "AP Vigilance Data and Benefit-Risk templates control vigilance and benefit-risk registry structure; AP CV and Declaration templates control chapters 7-9."
        ),
    }


def _structured_equivalence_rows(state: dict[str, Any]) -> list[dict[str, Any]]:
    eq_text = _source_text(state, "equivalence")
    if not eq_text:
        return []
    profile = _english_profile(state.get("device_profile") or {})
    domain = _clinical_domain(state)
    comparator = "Comparator from equivalent-device search report; exact model/manufacturer requires source confirmation."
    if domain == "urology_nephroscope":
        if "LithoVue" in eq_text or "Boston Scientific" in eq_text:
            comparator = "Boston Scientific LithoVue or another single-use ureteroscope/nephroscope benchmark identified in the equivalent-device search report"
        else:
            comparator = "Single-use or reusable ureteroscope/nephroscope comparator identified in the equivalent-device search report"
        technical = "Technical comparison must address endoscope catheter structure, insertion section, bending/deflection, optical/electronic imaging function, illumination, connector/interface, compatible image processor, working/access channel if applicable, dimensions, electrical safety, EMC, software/usability controls and mechanical integrity."
        biological = "Biological comparison must address patient-contact materials, contact duration/nature, sterile barrier, EO sterilisation or other sterilisation method, biocompatibility endpoints and any coating/lubrication or accessory-contact differences."
        clinical = "Clinical comparison must address intended purpose, target population, anatomical site, endoscopic procedure pathway, user/environment, contraindications, visualization/performance endpoints, complication profile and transferability from comparator endoscope data."
        technical_conclusion = "Technical equivalence is not demonstrated by search output alone; differences in imaging/illumination, deflection, interface compatibility, dimensions or electrical/endoscopic performance must be assessed for clinical safety/performance impact."
        biological_conclusion = "Biological equivalence is not demonstrated unless material/contact/sterilisation differences are shown not to affect patient-contact safety."
        clinical_conclusion = "Clinical equivalence remains conditional until intended-use, population, procedure pathway and endpoint transferability are confirmed for a true endoscope/nephroscope comparator."
    else:
        if "Boston Scientific" in eq_text:
            comparator = "Boston Scientific ureteral access sheath family identified in the equivalent-device search report"
        elif "Cook" in eq_text:
            comparator = "Cook ureteral access sheath family identified in the equivalent-device search report"
        technical = "Technical comparison must address sheath/dilator structure, negative-pressure drainage pathway, dimensions, markings, radiopacity, compatibility and insertion/use method."
        biological = "Biological comparison must address patient-contact materials, hydrophilic coating, EO sterilisation, contact duration and nature of urinary-tract contact."
        clinical = "Clinical comparison must address intended purpose, target population, anatomical site, user, environment, procedure pathway, contraindications and clinical endpoints."
        technical_conclusion = "Technical differences are not closed by the search report alone; any difference in suction pathway, dimensions or compatibility must be assessed for safety/performance impact before equivalence can be demonstrated."
        biological_conclusion = "Biological equivalence is not demonstrated unless material/contact/coating/sterilisation differences are shown not to affect clinical safety."
        clinical_conclusion = "Clinical equivalence remains conditional until intended-use and population/procedure match are confirmed and any negative-pressure-specific difference is justified."
    return [
        {
            "comparison_id": "EQ-TECH-001",
            "comparison_type": "technical",
            "subject_device": profile.get("device_name", ENGLISH_DEVICE_NAME),
            "comparator_device": comparator,
            "technical_characteristics": technical,
            "biological_characteristics": "Not applicable to this technical row; see biological row.",
            "clinical_characteristics": "Not applicable to this technical row; see clinical row.",
            "difference_impact_conclusion": technical_conclusion,
            "confidence": "conditional",
        },
        {
            "comparison_id": "EQ-BIO-001",
            "comparison_type": "biological",
            "subject_device": profile.get("device_name", ENGLISH_DEVICE_NAME),
            "comparator_device": comparator,
            "technical_characteristics": "Not applicable to this biological row; see technical row.",
            "biological_characteristics": biological,
            "clinical_characteristics": "Not applicable to this biological row; see clinical row.",
            "difference_impact_conclusion": biological_conclusion,
            "confidence": "conditional",
        },
        {
            "comparison_id": "EQ-CLIN-001",
            "comparison_type": "clinical",
            "subject_device": profile.get("device_name", ENGLISH_DEVICE_NAME),
            "comparator_device": comparator,
            "technical_characteristics": "Not applicable to this clinical row; see technical row.",
            "biological_characteristics": "Not applicable to this clinical row; see biological row.",
            "clinical_characteristics": clinical,
            "difference_impact_conclusion": clinical_conclusion,
            "confidence": "conditional",
        },
    ]


def _similar_device_four_step_rows(state: dict[str, Any], search_results: list[dict[str, Any]], equivalence_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    profile = _english_profile(state.get("device_profile") or {})
    device = profile.get("device_name", ENGLISH_DEVICE_NAME)
    databases = ", ".join(result.get("database", "") for result in search_results if result.get("database"))
    eudamed = next((result for result in search_results if "eudamed" in str(result.get("database", "")).lower()), {})
    return [
        {
            "row_id": "SIM-STEP-001",
            "step": "Step 1 - European market verification",
            "subject_device": device,
            "source": eudamed.get("database", "EUDAMED / market reports / competitor website"),
            "execution_record": eudamed.get("url", "EUDAMED or market source not executed"),
            "required_evidence": "EUDAMED public record, EU distributor/manufacturer website, market report or equivalent market evidence.",
            "status": "source_limited" if eudamed.get("status") == "source_unavailable" else "first_pass_recorded",
            "conclusion": "Market status must be confirmed before similar devices are used as benchmark market evidence.",
        },
        {
            "row_id": "SIM-STEP-002",
            "step": "Step 2 - Trade name and manufacturer identification",
            "subject_device": device,
            "source": databases,
            "execution_record": "FDA 510(k), AccessGUDID, EUDAMED and source package records are searched where available.",
            "required_evidence": "Confirmed trade names, manufacturer names and model identifiers for subject/similar/equivalent devices.",
            "status": "first_pass_recorded",
            "conclusion": "Trade-name confirmation is required before §4.4 device literature and §4.6 vigilance searches are finalized.",
        },
        {
            "row_id": "SIM-STEP-003",
            "step": "Step 3 - Technical parameter comparison",
            "subject_device": device,
            "source": "equivalence_matrix",
            "execution_record": "; ".join(str(row.get("comparison_id")) for row in equivalence_rows),
            "required_evidence": "Dimensions, materials, patient-contact nature/duration, energy/function, performance parameters, compatibility and sterilisation/biocompatibility evidence.",
            "status": "conditional",
            "conclusion": "Technical comparison remains conditional unless source specifications and difference-impact conclusions are complete.",
        },
        {
            "row_id": "SIM-STEP-004",
            "step": "Step 4 - Attachment package index",
            "subject_device": device,
            "source": "similar_device_attachment_index",
            "execution_record": "Attachment rows generated for 510(k), specifications, market report, IFU/manual, screenshots and clinical evidence sources.",
            "required_evidence": "10+N attachment package where applicable.",
            "status": "generated_request",
            "conclusion": "Missing attachments become human source requests and may not be replaced by unsupported narrative.",
        },
    ]


def _similar_device_attachment_rows(
    state: dict[str, Any],
    search_results: list[dict[str, Any]],
    equivalence_rows: list[dict[str, Any]],
    existing_rows: list[dict[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    profile = _english_profile(state.get("device_profile") or {})
    device = profile.get("device_name", ENGLISH_DEVICE_NAME)
    base_rows = [
        ("ATT-SIM-001", "EUDAMED / EU market verification", "EUDAMED public record, EU official/distributor page, market report or equivalent EU-market screenshot", "market_status", "§2.4 similar-device eligibility; §3.6 benchmark device context", "Do not use as EU-market or market-share evidence; record human source request."),
        ("ATT-SIM-002", "Trade-name and manufacturer evidence", "Manufacturer website, IFU/manual cover page, GUDID/510(k) record or equivalent public identity record", "identity", "§2.4 similar-device identity; §4.4/§4.6 trade-name search terms", "Do not use as device-literature or vigilance search term; request confirmed trade/manufacturer names."),
        ("ATT-SIM-003", "Technical specifications", "Specification sheet, 510(k) summary, brochure, engineering comparison table or technical file comparison", "technical", "§4.2 technical comparison and difference-impact analysis", "Do not claim technical comparability; downgrade to background SOTA context."),
        ("ATT-SIM-004", "Biological/contact evidence", "Material, patient-contact duration, sterilisation or biocompatibility comparison evidence", "biological", "§4.2 biological comparison and residual-risk support", "Do not claim biological comparability; hold equivalence conclusion as not claimed."),
        ("ATT-SIM-005", "Clinical use comparability", "Intended purpose, indication, target population, anatomical site and procedure pathway evidence", "clinical", "§2.4 clinical-condition match; §4.2 clinical comparison", "Do not use as clinical comparability evidence; mark clinical route as unconfirmed."),
        ("ATT-SIM-006", "Clinical literature / trial registry", "PubMed, Embase, Cochrane, ClinicalTrials.gov, EUCTR or other registry records tied to the similar device or class", "clinical_evidence", "§3 SOTA and §4.4 literature support, not equivalence unless confirmed", "Do not upgrade evidence weight; generate literature/full-text request."),
        ("ATT-SIM-007", "Vigilance/recall evidence", "MAUDE, recall, EUDAMED, MHRA, BfArM, Swissmedic, Medsafe or other vigilance records", "vigilance", "§4.6 vigilance and §4.7 risk/side-effect closure", "Do not infer no risk; record source limitation or execute trade-name vigilance search."),
        ("ATT-SIM-008", "Market share / gold-standard relevance", "Market research report, guideline, consensus, clinical pathway source or accepted standard-of-care source", "market_relevance", "§3.4-§3.6 SOTA positioning and benchmark relevance", "Do not call the device gold-standard or representative; keep as unweighted background."),
        ("ATT-SIM-009", "Difference impact analysis", "Technical, biological and clinical difference-impact conclusion with source references", "equivalence_analysis", "§4.2 equivalence/similar-use confidence and §4.7 conclusion limitation", "Do not state equivalence demonstrated; route to human review or downgrade."),
        ("ATT-SIM-010", "Source screenshots / raw query records", "Search URLs, dates, keywords, result counts, screenshots or exported raw records", "reproducibility", "Annex Q and search reproducibility audit trail", "Do not treat the search as reproducible; record protocol/source limitation."),
    ]
    existing_by_id = {
        str(row.get("attachment_id") or row.get("row_id") or ""): row
        for row in existing_rows or []
        if isinstance(row, dict)
    }
    rows = []
    for row_id, attachment_type, required_document, purpose, use_in_cer, if_missing in base_rows:
        existing = existing_by_id.get(row_id, {})
        source_hint = existing.get("source_hint") or existing.get("available_source_hint") or _attachment_source_hint(search_results, equivalence_rows, purpose)
        source_status = existing.get("source_status") or _attachment_source_status(source_hint)
        rows.append(
            {
                **existing,
                "attachment_id": row_id,
                "row_id": row_id,
                "subject_device": existing.get("subject_device") or device,
                "attachment_type": existing.get("attachment_type") or attachment_type,
                "required_document": existing.get("required_document") or existing.get("required_content") or required_document,
                "required_content": existing.get("required_content") or existing.get("required_document") or required_document,
                "purpose": existing.get("purpose") or purpose,
                "source_hint": source_hint,
                "available_source_hint": source_hint,
                "source_status": source_status,
                "status": existing.get("status") or ("source_recorded" if source_status == "source_hint_available" else "provided_or_requested"),
                "use_in_cer": existing.get("use_in_cer") or use_in_cer,
                "if_missing": existing.get("if_missing") or if_missing,
                "conclusion": existing.get("conclusion") or "Attachment row is mandatory for similar-device use; missing sources limit evidence use and trigger human source request.",
            }
        )
    for extra in existing_rows or []:
        extra_id = str(extra.get("attachment_id") or extra.get("row_id") or "")
        if extra_id and extra_id in existing_by_id and not any(str(row.get("attachment_id")) == extra_id for row in rows):
            rows.append(_harden_extra_similar_attachment(extra, device))
    return rows


def _similar_device_four_step_complete(rows: list[dict[str, Any]]) -> bool:
    if not rows:
        return False
    seen_steps = {str(row.get("step", "")).lower() for row in rows}
    return all(any(f"step {idx}" in step for step in seen_steps) for idx in range(1, 5))


def _similar_device_attachment_index_complete(rows: list[dict[str, Any]]) -> bool:
    if len(rows) < 10:
        return False
    return all(row.get("required_document") and row.get("use_in_cer") and row.get("if_missing") for row in rows[:10])


def _attachment_source_status(source_hint: str) -> str:
    lower = str(source_hint or "").lower()
    if not lower or "required" in lower or "not executed" in lower or "unavailable" in lower:
        return "source_request_required"
    return "source_hint_available"


def _harden_extra_similar_attachment(row: dict[str, Any], device: str) -> dict[str, Any]:
    source_hint = row.get("source_hint") or row.get("available_source_hint") or "source package / public record required"
    return {
        **row,
        "attachment_id": row.get("attachment_id") or row.get("row_id") or "ATT-SIM-EXTRA",
        "row_id": row.get("row_id") or row.get("attachment_id") or "ATT-SIM-EXTRA",
        "subject_device": row.get("subject_device") or device,
        "required_document": row.get("required_document") or row.get("required_content") or "Source document required for this additional similar-device attachment.",
        "use_in_cer": row.get("use_in_cer") or "Additional similar-device support; use only according to documented source purpose.",
        "if_missing": row.get("if_missing") or "Do not use this attachment as support; keep as source request.",
        "source_hint": source_hint,
        "source_status": row.get("source_status") or _attachment_source_status(str(source_hint)),
        "conclusion": row.get("conclusion") or "Additional attachment row hardened with mandatory G33 fields.",
    }


def _attachment_source_hint(search_results: list[dict[str, Any]], equivalence_rows: list[dict[str, Any]], purpose: str) -> str:
    if purpose in {"identity", "technical"}:
        return ", ".join(result.get("database", "") for result in search_results if any(token in str(result.get("database", "")).lower() for token in ("510", "gudid"))) or "source package required"
    if purpose == "market_status":
        return next((result.get("url", "") for result in search_results if "eudamed" in str(result.get("database", "")).lower()), "EUDAMED/market report required")
    if purpose == "equivalence_analysis":
        return ", ".join(str(row.get("comparison_id")) for row in equivalence_rows) or "equivalence report required"
    return "source package / public search record required"


def _extract_endpoint_rows_from_evidence(evidence_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    extracted = []
    sample_pattern = re.compile(r"(?:n\s*=\s*|sample(?:\s+size)?\s*(?:of|=)?\s*)(\d{2,5})", re.IGNORECASE)
    percent_pattern = re.compile(r"(\d{1,3}(?:\.\d+)?)\s*%")
    for row in evidence_rows:
        candidates = row.get("endpoint_candidates") or []
        candidate_text = " ".join(str(item.get("sentence", "")) for item in candidates if isinstance(item, dict))
        text = " ".join(str(row.get(key, "")) for key in ("title", "abstract_text", "result", "limitations", "source"))
        if candidate_text:
            text = f"{candidate_text} {text}"
        sample_match = sample_pattern.search(text)
        percent_match = percent_pattern.search(text)
        extracted.append(
            {
                "source_evidence_id": row.get("evidence_id"),
                "sample_size": sample_match.group(1) if sample_match else row.get("sample_size"),
                "timepoint": row.get("follow_up") or "not reported in bibliographic summary",
                "statistical_result": percent_match.group(0) if percent_match else row.get("result"),
                "extraction_basis": "PubMed abstract/full abstract XML and bibliographic metadata endpoint extraction attempted",
                "conclusion": "Supportive only unless full-text endpoint definition, numerator/denominator, timepoint and statistics are extracted.",
            }
        )
    return extracted


def _extract_endpoint_rows_from_sources(state: dict[str, Any]) -> list[dict[str, Any]]:
    rows = []
    endpoint_keywords = (
        "endpoint",
        "primary endpoint",
        "secondary endpoint",
        "sample size",
        "follow-up",
        "adverse event",
        "success rate",
        "clinical",
        "NCT",
        "ISO 14155",
    )
    cn_keywords = ("主要终点", "次要终点", "样本量", "随访", "不良事件", "有效性", "安全性", "临床")
    for item in sorted(state.get("source_inventory") or [], key=lambda row: int(row.get("relevance_score") or 0), reverse=True):
        text = str(item.get("text") or "")
        filename = str(item.get("filename") or "")
        haystack = f"{filename}\n{text[:40_000]}"
        if not any(keyword.lower() in haystack.lower() for keyword in endpoint_keywords) and not any(keyword in haystack for keyword in cn_keywords):
            continue
        sentence = _first_endpoint_sentence(haystack)
        if not sentence:
            continue
        rows.append(
            {
                "source_evidence_id": item.get("source_id"),
                "sample_size": _first_match(sentence, [r"(?:n\s*=\s*|sample size\s*(?:of|=)?\s*)(\d{1,5})", r"样本量[：:\s]*(\d{1,5})"]) or "not extracted",
                "timepoint": _first_match(sentence, [r"(\d+\s*(?:days?|months?|years?))", r"(\d+\s*(?:天|月|年))"]) or "not extracted",
                "statistical_result": _first_match(sentence, [r"(\d{1,3}(?:\.\d+)?\s*%)", r"(NCT\d{8})"]) or sentence[:240],
                "extraction_basis": f"source-document full text extraction from {english_filename(filename, str(item.get('source_id') or ''))}",
                "conclusion": "Manufacturer/source-document endpoint candidate extracted; human evaluator must confirm endpoint definition, numerator/denominator and statistical method.",
            }
        )
    return rows


def _first_endpoint_sentence(text: str) -> str:
    compact = re.sub(r"\s+", " ", text)
    sentences = re.split(r"(?<=[.!?。；;])\s+", compact)
    endpoint_re = re.compile(r"(endpoint|sample size|follow-up|adverse event|success|safety|efficacy|clinical|NCT|主要终点|样本量|随访|不良事件|有效性|安全性|临床)", re.IGNORECASE)
    for sentence in sentences:
        if endpoint_re.search(sentence) and any(char.isdigit() for char in sentence):
            return english_report_text(sentence[:800], "endpoint source sentence")
    return ""


def _first_match(text: str, patterns: list[str]) -> str:
    for pattern in patterns:
        match = re.search(pattern, text, flags=re.IGNORECASE)
        if match:
            return match.group(1)
    return ""


def _screen_vigilance_records(result: dict[str, Any], terms: str) -> list[dict[str, Any]]:
    rows = []
    records = result.get("records") or []
    database = _normalize_vigilance_database(result.get("database", ""))
    tokens = [token.lower() for token in re.split(r"[^A-Za-z0-9]+", terms) if len(token) >= 4]
    for idx, record in enumerate(records, start=1):
        blob = json.dumps(record, ensure_ascii=False, default=str)
        lower = blob.lower()
        matched = [token for token in tokens if token in lower]
        adverse_hint = any(word in lower for word in ("injury", "malfunction", "recall", "removal", "failure", "infection", "bleeding", "death", "serious"))
        relevance = "potentially_relevant" if matched or adverse_hint else "not_relevant_first_pass"
        rows.append(
            {
                "screening_id": f"VRS-{len(rows) + 1:03d}",
                "database": database,
                "record_index": idx,
                "relevance": relevance,
                "matched_terms": ", ".join(matched) if matched else "no direct device-term match",
                "risk_signal_hint": "adverse-event wording detected" if adverse_hint else "no first-pass adverse wording detected",
                "rationale": "First-pass relevance screening; final coding requires human review of raw record.",
            }
        )
    if not rows:
        rows.append(
            {
                "screening_id": "VRS-000",
                "database": database,
                "record_index": 0,
                "relevance": "no_records_or_source_unavailable",
                "matched_terms": "",
                "risk_signal_hint": "",
                "rationale": "No returned records were available for first-pass relevance screening; no-risk conclusion is prohibited.",
            }
        )
    return rows


def _target_stage_for_human_gap(gap: dict[str, Any]) -> str:
    gap_type = str(gap.get("type", "")).lower()
    if "section" in gap_type or "size" in gap_type:
        return "authoring-cer-writer"
    if "quality" in gap_type or "sota" in gap_type:
        return "authoring-sota-analyst"
    if "feature" in gap_type:
        return "authoring-device-profile-builder"
    if "claim" in gap_type:
        return "authoring-claim-pico-builder"
    return "authoring-cer-writer"


def _ap_template_role(filename: str) -> str:
    lower = filename.lower()
    if "clinical evaluation report" in lower:
        return "main CER chapter structure"
    if "sota" in lower:
        return "SOTA narrative and SOTA screening annex"
    if "annex 1" in lower:
        return "SOTA literature search protocol and report"
    if "annex 2" in lower:
        return "device-under-evaluation literature search protocol and report"
    if "vigilance" in lower:
        return "vigilance data update structure"
    if "benefit risk" in lower:
        return "benefit-risk ratio output structure"
    if "declaration" in lower:
        return "declaration of interest annex"
    if "cv" in lower:
        return "evaluator CV annex"
    if "pmcf" in lower:
        return "PMCF plan structure"
    if "clinical evaluation plan" in lower:
        return "CEP structure and PICO/search planning"
    return "supporting AP template"


