def _annex_mcp_and_style(state: dict[str, Any]) -> str:
    logs = state.get("mcp_call_log") or []
    style = state.get("human_style_benchmark_report") or {}
    template = state.get("template_guidance") or {}
    brief = state.get("writing_brief") or {}
    ap_profile = state.get("ap_template_profile") or style.get("ap_template_profile") or load_ap_template_profile()
    tool_results = state.get("mcp_tool_results") or {}
    guidance_rows = []
    for section, guidance in (tool_results.get("cer_kb_section_guidance") or {}).items():
        guidance_rows.append(
            {
                "Section": section,
                "Status": guidance.get("status", "not available") if isinstance(guidance, dict) else "not available",
                "Guidance": _compact_json(guidance, 1400, english_only=True),
            }
        )
    deficiency = tool_results.get("cer_kb_nb_deficiency_search") or {}
    deficiency_rows = []
    for idx, item in enumerate(deficiency.get("results") or [], start=1):
        deficiency_rows.append(
            {
                "Rank": idx,
                "Preview": item.get("text_preview", ""),
                "Metadata": _compact_json(item.get("metadata", {}), 500, english_only=True),
            }
        )
    style_rows = []
    for row in style.get("human_benchmarks") or []:
        style_rows.append(
            {
                "Template": english_filename(row.get("filename")),
                "Paragraphs": row.get("paragraphs"),
                "Tables": row.get("tables"),
                "Chars": row.get("chars"),
            }
        )
    ap_rows = []
    for row in ap_profile.get("templates") or []:
        ap_rows.append(
            {
                "AP template": row.get("filename"),
                "Role": row.get("template_role"),
                "Paragraphs": row.get("paragraphs"),
                "Tables": row.get("tables"),
                "Headings": row.get("heading_count"),
            }
        )
    return "\n".join(
        [
            "This annex proves that the report was not produced only by free text generation. It records MCP calls, template guidance, writing brief availability, and human-style benchmark scoring.",
            "",
            "## J.1 MCP Call Log",
            _md_table(
                logs,
                ["stage", "server", "tool", "status", "elapsed_ms", "summary"],
                ["Stage", "MCP server", "Tool", "Status", "Elapsed ms", "Summary"],
            ),
            "",
            "## J.2 Template and Writing-Brief Sources",
            f"Template status: {template.get('status', 'not available')}; writing brief status: {brief.get('status', 'not available')}. These artifacts are stored in authoring_workbook.json for traceability.",
            "The CER writer uses these knowledge-base outputs to align chapter order, evidence depth, section-level risks and NB deficiency prevention with historical CER examples.",
            "The raw template and writing-brief payloads are retained in authoring_workbook.json. The CER body records only English, report-safe summaries.",
            "",
            "## J.2.1 AP Template Profile",
            f"AP template package: local AP CER template directory. Loaded templates: {ap_profile.get('template_count', 0)}. Use: {ap_profile.get('cer_authoring_use', 'not available')}",
            _md_table(ap_rows, ["AP template", "Role", "Paragraphs", "Tables", "Headings"]),
            "",
            "## J.2.2 Section Guidance and NB Deficiency Search",
            _md_table(guidance_rows, ["Section", "Status", "Guidance"]),
            f"NB deficiency search status: {deficiency.get('status', 'not available')}; result count: {deficiency.get('results_count', 0)}.",
            _md_table(deficiency_rows, ["Rank", "Preview", "Metadata"]),
            "",
            "## J.3 Human CER Benchmark",
            f"Human-style benchmark decision: {style.get('status', 'not executed')}; score: {style.get('score', 'not available')}; findings: {style.get('findings', [])}.",
            _md_table(style_rows, ["Template", "Paragraphs", "Tables", "Chars"]),
        ]
    )


def _annex_device_identity_lock(state: dict[str, Any]) -> str:
    report = state.get("source_role_report") or {}
    lock = state.get("device_identity_lock") or {}
    arbitration = state.get("device_identity_arbitration") or {}
    contamination = state.get("domain_contamination_report") or {}
    inventory_rows = []
    for row in state.get("source_inventory") or []:
        inventory_rows.append(
            {
                "Source ID": row.get("source_id"),
                "Document role": row.get("source_role"),
                "Document type": row.get("document_type"),
                "Primary": row.get("primary_for_authoring"),
                "Excluded from profile": row.get("excluded_from_device_profile"),
                "Role rationale": row.get("role_reason"),
                "Document": english_filename(row.get("filename"), row.get("source_id", "")),
            }
        )
    arbitration_rows = []
    for row in state.get("device_identity_arbitration_table") or lock.get("device_identity_arbitration_table") or []:
        arbitration_rows.append(
            {
                "Rank": row.get("rank"),
                "Evidence source": row.get("evidence_source"),
                "Strength": row.get("strength"),
                "Observed domain": row.get("observed_domain"),
                "Result": row.get("arbitration_result"),
                "Source IDs": ", ".join(str(item) for item in row.get("source_ids") or []),
                "Rationale": row.get("rationale"),
            }
        )
    narrative = [
        "This annex records the identity-control logic applied before drafting. It is deliberately placed in the evidence package because device identity errors can invalidate an otherwise well-written CER. The authoring workflow therefore does not allow every IFU-like file to define the evaluated device. Each source is first classified by document type and by source role. A subject-device IFU can define the Device Profile. A similar-device IFU can support SOTA, risk identification, comparator discussion or equivalence scouting, but it cannot define the evaluated device name, intended purpose, manufacturer, target population, anatomical site or mode of action.",
        f"The locked clinical domain for this project is `{lock.get('locked_domain', report.get('locked_domain_hint', 'not available'))}`. The locked subject IFU source is `{', '.join(lock.get('subject_ifu_source_ids') or report.get('subject_ifu_source_ids') or []) or 'not available'}`. The identity statement is: {lock.get('identity_statement', 'not available')}. If lower-ranked evidence conflicts with the locked domain, the conflict is recorded as `DEVICE_IDENTITY_CONFLICT` in the arbitration table and cannot silently overwrite the selected domain.",
        "The practical consequence for CER writing is important. The SOTA chapter may mention competitor or benchmark devices only to define accepted clinical practice, alternative treatment pathways, hazards, endpoint families or non-equivalence rationale. The device-under-evaluation chapter must return to the locked subject IFU and manufacturer sources before making any statement about the evaluated device. The Claim Ledger, PICO Matrix, Risk Trace Matrix and GSPR coverage all inherit this same identity boundary.",
        "If a future source package includes several generations, accessories, image processors or equivalent-device files, the same rule still applies: the authoring team must first decide whether each file describes the subject device, a compatible accessory, a similar device, a benchmark device, an alternative therapy, or a background source. No conclusion may cross from one role to another without an explicit transferability or equivalence analysis.",
    ]
    return "\n\n".join(
        [
            *narrative,
            "## K.1 Source Role Report",
            _compact_json(report, 1800, english_only=True),
            "## K.2 Device Identity Lock",
            _compact_json(lock, 1800, english_only=True),
            "## K.3 Device Identity Arbitration",
            _compact_json(arbitration, 1800, english_only=True),
            _md_table(arbitration_rows, ["Rank", "Evidence source", "Strength", "Observed domain", "Result", "Source IDs", "Rationale"]),
            "## K.4 Domain Contamination Check",
            _compact_json(contamination, 1800, english_only=True),
            "## K.5 Source Role Table",
            _md_table(inventory_rows, ["Source ID", "Document role", "Document type", "Primary", "Excluded from profile", "Role rationale", "Document"]),
        ]
    )


def _annex_claim_reasoning_expansion(state: dict[str, Any]) -> str:
    claims = state.get("claim_ledger") or []
    picos_by_claim: dict[str, list[dict[str, Any]]] = {}
    for pico in state.get("cep_pico_matrix") or []:
        picos_by_claim.setdefault(str(pico.get("claim_id") or ""), []).append(pico)
    benchmarks = state.get("sota_benchmark_matrix") or []
    evidence = state.get("evidence_registry") or []
    risks = state.get("risk_trace_matrix") or []
    paragraphs = [
        "This annex expands the reasoning pathway behind the main CER body. Its purpose is to make the AI authoring process auditable in the same way a human evaluator would explain the route from IFU statement to clinical question, evidence search, benchmark, appraisal, risk closure and final downgraded conclusion. The main body remains concise enough to read, while this annex shows that no clinical claim was accepted only because it appeared in the IFU.",
        "For each claim, the logic is: first identify the IFU statement and its claim type; then ask what clinical uncertainty remains; then convert the uncertainty into a PICO question; then run and record the search; then appraise evidence and extract endpoints; then compare the result against the SOTA benchmark; finally decide whether the claim is supported, partially supported, not supported or remains an evidence gap. This logic is intentionally conservative because the project does not yet contain a complete manufacturer clinical investigation dataset or mature PMS/PMCF exposure evidence.",
    ]
    for claim in claims:
        claim_id = str(claim.get("claim_id") or "Claim")
        picos = picos_by_claim.get(claim_id) or []
        pico_text = " ".join(
            f"{pico.get('pico_id')}: population {pico.get('population')}; intervention {pico.get('intervention')}; comparator {pico.get('comparator')}; outcome {pico.get('outcome')}; rationale {pico.get('derivation_rationale')}."
            for pico in picos[:3]
        )
        benchmark_text = " ".join(
            f"{row.get('benchmark_id')} covers {row.get('endpoint')} with acceptance criterion {row.get('acceptance_criterion')}."
            for row in benchmarks[:4]
        )
        evidence_text = " ".join(
            f"{row.get('evidence_id')} is weighted {row.get('weight')} for endpoint {row.get('endpoint')} with limitation {row.get('limitations')}."
            for row in evidence[:5]
        )
        risk_text = " ".join(
            f"{row.get('risk_id')} records {row.get('risk_side_effect')} with IFU coverage {row.get('ifu_coverage')} and RMF coverage {row.get('rmf_coverage')}."
            for row in risks[:4]
        )
        paragraphs.append(
            f"Claim {claim_id} is classified as `{claim.get('claim_type')}` and is sourced from {claim.get('source_id') or claim.get('source')}. "
            f"The claim text is summarized as: {claim.get('claim_text') or claim.get('statement') or 'not available'}. "
            f"The verification question is: {claim.get('verification_question')}. The required evidence is: {claim.get('required_evidence')}. "
            f"PICO derivation linked to this claim: {pico_text or 'No dedicated PICO was generated; this is a rework item if the claim is clinically material.'} "
            f"SOTA/benchmark linkage: {benchmark_text or 'No benchmark is available; acceptance must remain qualitative and explicitly limited.'} "
            f"Evidence linkage: {evidence_text or 'No evidence row is available; conclusion remains an evidence gap.'} "
            f"Risk/GSPR linkage: {risk_text or 'No risk row is available; risk closure remains incomplete.'} "
            "The authoring conclusion for this claim must therefore remain partial or gap-controlled unless endpoint extraction, PMS/PMCF evidence and evaluator confirmation allow an upgrade."
        )
    rows = []
    for claim in claims:
        claim_id = str(claim.get("claim_id") or "")
        rows.append(
            {
                "Claim ID": claim_id,
                "Claim type": claim.get("claim_type"),
                "PICO count": len(picos_by_claim.get(claim_id) or []),
                "Evidence basis": ", ".join(row.get("evidence_id", "") for row in evidence[:5]) or "evidence gap",
                "Benchmark basis": ", ".join(row.get("benchmark_id", "") for row in benchmarks[:5]) or "benchmark gap",
                "Conclusion strength": "partial / evidence-gap controlled until endpoint extraction and PMS/PMCF are complete",
            }
        )
    return "\n\n".join(
        [
            *paragraphs,
            "## L.1 Claim Reasoning Control Table",
            _md_table(rows, ["Claim ID", "Claim type", "PICO count", "Evidence basis", "Benchmark basis", "Conclusion strength"]),
        ]
    )


