def _engineer_theme_authoring_location(theme_id: str) -> str:
    mapping = {
        "theme_1_summary_scope": "Chapters 1 and 2; Claim Ledger and Intended Purpose Claim Table",
        "theme_2_equivalence_logic": "Chapters 2.4, 4.1, 4.2 and Annex F",
        "theme_3_market_vigilance": "Chapters 2.5, 4.6, Annex G and Risk Trace Matrix",
        "theme_4_sota_literature": "Chapter 3, Chapter 4.4, Annex C and search registry",
        "theme_5_gspr_benefit_risk": "Chapters 4.3.2, 4.7 and Annex H",
        "theme_6_section_conclusions": "End of major sections and second-level sections",
    }
    return mapping.get(theme_id, "CER body and evidence workbook")


def _compact_json(value: Any, limit: int = 1000, english_only: bool = False) -> str:
    text = json.dumps(value, ensure_ascii=False, default=str)
    text = re.sub(r"\s+", " ", text).strip()
    if english_only and contains_cjk(text):
        text = english_report_text(text, "knowledge-base guidance")
    return _sanitize_regulatory_language(text)[:limit]


def _sanitize_regulatory_language(text: Any) -> str:
    value = str(text or "")
    # ── Regulatory language toning ──
    replacements = [
        (r"\bsafe\b", "risk-controlled"),
        (r"superiority_claim_allowed", "comparative_claim_allowed"),
        (r"superiority_allowed", "comparative_claim_allowed"),
        (r"\bsuperiority\b", "comparative better-than claim"),
        (r"\bsuperior\b", "better-than comparator"),
        (r"\bbest described\b", "described in this draft"),
        (r"\bproven\b", "treated as supported"),
        (r"\bprove\b", "demonstrate"),
        (r"\bproof\b", "stand-alone evidence"),
        (r"\bdefinitively\b", "with final evidentiary certainty"),
        (r"\bfully demonstrated\b", "fully source-supported"),
        (r"\ball risks are acceptable\b", "residual risks are conditionally acceptable when source-controlled"),
        (r"\bfavourable benefit-risk is confirmed\b", "benefit-risk remains evidence-controlled"),
        (r"\bAlways\b", "Consistently"),
        (r"\balways\b", "consistently"),
        (r"report-safe", "report-suitable"),
    ]
    for pattern, replacement in replacements:
        value = re.sub(pattern, replacement, value, flags=re.IGNORECASE)
    # ── Banned internal string cleaning ──
    _BANNED_CLEANUP = [
        (r"\bClaude\b", "[REDACTED]"),
        (r"\bDeerFlow\b", "[REDACTED]"),
        (r"\bMCP\b", "[REDACTED]"),
        (r"SKILL REFERENCE", "[REDACTED]"),
        (r"PLANNER AGENT", "[REDACTED]"),
        (r"IMPLEMENTER AGENT", "[REDACTED]"),
        (r"REVIEWER AGENT", "[REDACTED]"),
        (r"\bworkbuddy\b", "[REDACTED]"),
        (r"execution trace", "[REDACTED]"),
        (r"agent handoff", "[REDACTED]"),
        (r"delegation log", "[REDACTED]"),
        (r"subagent_invocation_log", "[REDACTED]"),
        (r"ALLOWED_USE_BLOCKED", "[REDACTED]"),
        (r"authoring run", "[REDACTED]"),
        (r"cer_authoring_v1", "[REDACTED]"),
        (r"writing-evidence-table", "[REDACTED]"),
        (r"WET / writing-evidence-table", "[REDACTED]"),
    ]
    for pattern, replacement in _BANNED_CLEANUP:
        value = re.sub(pattern, replacement, value, flags=re.IGNORECASE)
    # ── IFU placeholder cleaning ──
    _IFU_CLEANUP = [
        (r"Not extracted from IFU[^\n.]*\.?", "[Data pending IFU source confirmation]"),
        (r"IFU text not available[^\n.]*\.?", "[Data pending IFU source confirmation]"),
        (r"source text unavailable[^\n.]*\.?", "[Data pending source confirmation]"),
        (r"pending IFU confirmation[^\n.]*\.?", "[Data pending IFU source confirmation]"),
    ]
    for pattern, replacement in _IFU_CLEANUP:
        value = re.sub(pattern, replacement, value, flags=re.IGNORECASE)
    return value


def _md_table(rows: list[dict[str, Any]], keys: list[str], labels: list[str] | None = None) -> str:
    labels = [_sanitize_regulatory_language(label) for label in (labels or keys)]
    if not rows:
        rows = [{key: "Not available in this authoring run" for key in keys}]
    lines = ["| " + " | ".join(labels) + " |", "| " + " | ".join("---" for _ in labels) + " |"]
    for row in rows:
        values = [_md_cell(row.get(key, "")) for key in keys]
        lines.append("| " + " | ".join(values) + " |")
    return "\n".join(lines)


def _md_cell(value: Any) -> str:
    if isinstance(value, (dict, list)):
        value = json.dumps(value, ensure_ascii=False, default=str)
    text = re.sub(r"[\r\n|]+", " ", str(value or ""))
    text = re.sub(r"\s+", " ", text).strip()
    if contains_cjk(text):
        text = english_report_text(text, "table cell")
    return _sanitize_regulatory_language(text)[:900]
